// ÔöÇÔöÇ PROVIDER PRINCIPAL ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export function NotificationProvider({ children, profile }) {
  const location = useLocation();
  const [notifications, setNotifications] = useState([]);
  const [toasts, setToasts] = useState([]);
  const [isOpen, setIsOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const bellRef = useRef(null);

  const unreadCount = notifications.filter(n => !n.is_read).length;

  // ÔöÇÔöÇ Fetch notifications ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const fetchNotifications = useCallback(async () => {
    if (!profile?.id) return;
    const { data } = await supabase
      .from("notifications_with_actor")
      .select("*")
      .eq("user_id", profile.id)
      .order("created_at", { ascending: false })
      .limit(30);
    setNotifications(data || []);
  }, [profile?.id]);

  // ÔöÇÔöÇ Realtime subscription ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  useEffect(() => {
    if (!profile?.id) return;
    fetchNotifications();

    const channel = supabase
      .channel(`notifs-${profile.id}`)
      .on("postgres_changes", {
        event: "INSERT",
        schema: "public",
        table: "notifications",
        filter: `user_id=eq.${profile.id}`,
      }, async (payload) => {
        const newNotif = payload.new;

        // Enrichir avec actor info
        let enriched = { ...newNotif, actor_name: null, actor_avatar: null };
        if (newNotif.actor_id) {
          const { data: actor } = await supabase
            .from("profiles")
            .select("full_name, avatar_url")
            .eq("id", newNotif.actor_id)
            .single();
          enriched = { ...enriched, actor_name: actor?.full_name, actor_avatar: actor?.avatar_url };
        }

        // Ajouter ├á la liste
        setNotifications(prev => [enriched, ...prev]);

        // Afficher toast (sauf si dropdown ouvert)
        if (!isOpen) {
          setToasts(prev => [...prev.slice(-3), {
            ...enriched,
            id: `toast-${enriched.id}-${Date.now()}`,
          }]);
        }
      })
      .subscribe();

    return () => supabase.removeChannel(channel);
  }, [profile?.id, fetchNotifications]);

  // ÔöÇÔöÇ Fermer dropdown en cliquant dehors ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  useEffect(() => {
    const handler = (e) => {
      if (bellRef.current && !bellRef.current.contains(e.target)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  // ÔöÇÔöÇ Fermer dropdown sur changement de route ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  useEffect(() => {
    setIsOpen(false);
  }, [location.pathname]);

  // ÔöÇÔöÇ Actions ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleOpen = async () => {
    setIsOpen(o => !o);
    if (!isOpen && profile?.id) {
      // Marquer tout comme seen quand on ouvre
      await supabase.rpc("mark_notifications_seen", { p_user_id: profile.id });
    }
  };

  const handleRead = async (notifId) => {
    await supabase.rpc("mark_notification_read", { p_notif_id: notifId });
    setNotifications(prev =>
      prev.map(n => n.id === notifId ? { ...n, is_read: true, is_seen: true } : n)
    );
  };

  const handleMarkAllRead = async () => {
    if (!profile?.id) return;
    await supabase.rpc("mark_all_notifications_read", { p_user_id: profile.id });
    setNotifications(prev => prev.map(n => ({ ...n, is_read: true, is_seen: true })));
  };

  const removeToast = useCallback((id) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  // ÔöÇÔöÇ Toast function pour usage manuel ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const toast = useCallback((type, title, body, link) => {
    const id = `manual-${Date.now()}-${Math.random()}`;
    setToasts(prev => [...prev.slice(-3), {
      id, type, title, body, link,
      category: "general", priority: "normal",
      created_at: new Date().toISOString(),
    }]);
  }, []);

  return (
    <NotifCtx.Provider value={{
      notifications, unreadCount, isOpen,
      handleOpen, handleRead, handleMarkAllRead,
      toast, fetchNotifications, bellRef,
    }}>
      {children}

      {/* Keyframes */}
      <style>{`
        @keyframes notif-shrink {
          from { width: 100%; }
          to   { width: 0%; }
        }
      `}</style>

      {/* Toast container */}
      <div style={{
        position: "fixed",
        top: 76, right: 16,
        zIndex: 9999,
        display: "flex", flexDirection: "column", gap: 8,
        pointerEvents: "none",
        maxWidth: 340,
      }}>
        {toasts.map(t => (
          <div key={t.id} style={{ pointerEvents: "auto" }}>
            <Toast notif={t} onRemove={removeToast} />
          </div>
        ))}
      </div>
    </NotifCtx.Provider>
  );
}

// ÔöÇÔöÇ BELL EXPORT (utilis├® dans MainLayout) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export function NotificationBellConnected() {
  const ctx = useNotifications();
  if (!ctx) return null;

  return (
    <div ref={ctx.bellRef}>
      <NotificationBell
        unreadCount={ctx.unreadCount}
        notifications={ctx.notifications}
        onOpen={ctx.handleOpen}
        onMarkAllRead={ctx.handleMarkAllRead}
        onRead={ctx.handleRead}
        isOpen={ctx.isOpen}
      />
    </div>
  );
}

