// src/components/RoleGuard.jsx
// Protects routes by role. Use inside ProtectedRoute context.
// Reads profile once from Supabase and caches in module scope per session.

import { useEffect, useState } from "react";
import { Navigate } from "react-router-dom";
import { supabase } from "../lib/supabase";

// Module-level cache ÔÇö 20 s TTL so role changes take effect quickly
let _cachedProfile = null;
let _cacheUserId   = null;
let _cacheAt       = 0;
const CACHE_TTL    = 20_000; // ms

async function fetchProfile(userId, force = false) {
  const stale = Date.now() - _cacheAt > CACHE_TTL;
  if (!force && _cachedProfile && _cacheUserId === userId && !stale) {
    return _cachedProfile;
  }
  const { data, error } = await supabase
    .from("profiles")
    .select("id,role,is_banned")
    .eq("id", userId)
    .maybeSingle();
  if (error) {
    console.warn("[RoleGuard] fetchProfile error:", error.message);
    return null;
  }
  if (data?.role) data.role = data.role.toLowerCase();
  _cachedProfile = data;
  _cacheUserId   = userId;
  _cacheAt       = Date.now();
  return data;
}

// Expose a manual invalidation for use after role updates
export function invalidateRoleCache() {
  _cachedProfile = null;
  _cacheUserId   = null;
  _cacheAt       = 0;
}

// Clear cache on sign-out
supabase.auth.onAuthStateChange((event) => {
  if (event === "SIGNED_OUT") { _cachedProfile = null; _cacheUserId = null; }
});

/**
 * RoleGuard ÔÇö wraps admin/role-specific routes
 *
 * Props:
 *   allowedRoles: string[]   ÔÇö e.g. ["admin","super_admin"]
 *   redirectTo:   string     ÔÇö where to redirect if not allowed (default: "/dashboard")
 *   children:     ReactNode
 *
 * Usage in App.jsx:
 *   <Route path="/admin" element={
 *     <RoleGuard allowedRoles={["admin","super_admin"]}>
 *       <Lazy><AdminDashboard /></Lazy>
 *     </RoleGuard>
 *   } />
 */
export default function RoleGuard({ allowedRoles, redirectTo = "/dashboard", children }) {
  const [state, setState] = useState("loading"); // "loading" | "allowed" | "denied"

  useEffect(() => {
    let mounted = true;
    supabase.auth.getSession().then(async ({ data: { session } }) => {
      if (!mounted) return;
      if (!session?.user) { setState("denied"); return; }
      const profile = await fetchProfile(session.user.id);
      if (!mounted) return;
      if (!profile || profile.is_banned) { setState("denied"); return; }
      // profile.role is already lowercased by fetchProfile
      // allowedRoles are lowercase strings (from App.jsx)
      const role = profile.role?.toLowerCase() ?? "";
      const allowed = allowedRoles.some(r => r.toLowerCase() === role);
      setState(allowed ? "allowed" : "denied");
    });
    return () => { mounted = false; };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (state === "loading") return <PageLoader />;
  if (state === "denied")  return <Navigate to={redirectTo} replace />;
  return children;
}

function PageLoader() {
  return (
    <div style={{
      minHeight:      "100vh", background: "#070709",
      display:        "flex", alignItems: "center", justifyContent: "center",
      flexDirection:  "column", gap: 16,
    }}>
      <div className="loading-spinner" />
      <p style={{
        fontFamily: "'Rajdhani',sans-serif", fontSize: 12,
        letterSpacing: 3, color: "rgba(255,255,255,0.25)",
        textTransform: "uppercase", margin: 0,
      }}>V├®rification des droitsÔÇª</p>
    </div>
  );
}

import { useVerification } from "../hooks/useVerification";

/**
 * VerificationGuard
 * -----------------
 * Wraps n'importe quel bouton/action et le bloque si le compte
 * n'est pas encore approuv├®.
 *
 * Usage:
 *   <VerificationGuard profile={profile}>
 *     <button onClick={handleJoin}>Rejoindre</button>
 *   </VerificationGuard>
 *
 *   Ou avec un fallback personnalis├®:
 *   <VerificationGuard profile={profile} fallback={<span>Compte en attente</span>}>
 *     <button onClick={handleJoin}>Rejoindre</button>
 *   </VerificationGuard>
 */
export default function VerificationGuard({ profile, children, className = "", fallback = null }) {
  const { canInteract, isPending, isRejected, isBanned, requireVerified } = useVerification(profile);

  if (canInteract) return children;

  // Si fallback fourni ÔåÆ l'afficher
  if (fallback) return fallback;

  // Sinon ÔåÆ rendre les enfants d├®sactiv├®s avec overlay + tooltip
  const msg = isBanned
    ? "Compte suspendu"
    : isRejected
    ? "V├®rification refus├®e ÔÇö contactez le support"
    : "Compte en attente de validation admin";

  const color = isBanned || isRejected ? "#ef4444" : "#f59e0b";

  return (
    <div className={`relative group ${className}`} style={{ display: "inline-block" }}>
      {/* Enfants d├®sactiv├®s visuellement */}
      <div style={{ opacity: 0.45, pointerEvents: "none", userSelect: "none" }} aria-disabled="true">
        {children}
      </div>

      {/* Overlay transparent qui capture les clics */}
      <div
        style={{ position: "absolute", inset: 0, cursor: "not-allowed", zIndex: 10 }}
        onClick={e => { e.preventDefault(); e.stopPropagation(); requireVerified(() => {}); }}
      />

      {/* Tooltip au hover */}
      <div style={{
        position: "absolute",
        bottom: "calc(100% + 8px)",
        left: "50%",
        transform: "translateX(-50%)",
        background: "#0f0f1a",
        border: `1px solid ${color}55`,
        borderRadius: 8,
        padding: "7px 12px",
        whiteSpace: "nowrap",
        pointerEvents: "none",
        zIndex: 20,
        opacity: 0,
        transition: "opacity .15s",
        fontFamily: "Space Grotesk, sans-serif",
        fontSize: 11,
        color: color,
        fontWeight: 600,
      }}
        className="group-hover:opacity-100"
      >
        ­ƒöÆ {msg}
      </div>
    </div>
  );
}

