import React from "react";

export default function PlayerCard({ 
  player, 
  teamNumber, 
  seatNumber, 
  tournament, 
  role, 
  currentUserId,
  onSelect, 
  onKick,
  onChangeSeat,
  onSwapRequest,    // new: request swap with another player
  pendingSwap,      // new: { fromTeam, fromSeat, fromUserId } if someone wants to swap with me
  onSwapRespond,    // new: (accept: bool) => void
}) {
  const isCurrentUser = player?.id === currentUserId;
  const isCaptain = teamNumber === 1 && seatNumber === 1;
  
  // Someone sent ME a swap request for this seat
  const hasPendingRequest = pendingSwap && player?.id === currentUserId;

  const handleSeatClick = () => {
    if (!player) {
      // Empty seat ÔåÆ move here directly
      if (role === "participant" && tournament?.status === "open") {
        onChangeSeat?.(teamNumber, seatNumber);
      }
    } else if (!isCurrentUser) {
      // Occupied by OTHER player ÔåÆ request swap
      if (role === "participant" && tournament?.status === "open") {
        onSwapRequest?.(teamNumber, seatNumber, player);
      } else {
        onSelect?.(player);
      }
    } else {
      // My own card ÔåÆ open profile
      onSelect?.(player);
    }
  };

  const accentColor = tournament?.background_color || "#6D28D9";

  return (
    <div
      className={`relative aspect-square rounded-xl p-3 text-center transition-all duration-200 ${
        player
          ? "border cursor-pointer hover:shadow-[0_0_20px_rgba(139,92,246,0.6)]"
          : "border border-white/5 opacity-40 cursor-pointer hover:opacity-70"
      } ${isCurrentUser ? "ring-2 ring-purple-500" : ""} ${
        hasPendingRequest ? "ring-2 ring-yellow-400 animate-pulse" : ""
      }`}
      style={{
        borderColor: player ? accentColor : undefined,
        background: player
          ? `linear-gradient(135deg, ${accentColor}20, #11151C)`
          : "#11151C",
      }}
      onClick={handleSeatClick}
    >
      {/* Team / Seat badges */}
      <div className="absolute top-1 left-1 w-4 h-4 rounded-full flex items-center justify-center text-[8px] font-bold"
        style={{ backgroundColor: accentColor }}>
        {teamNumber}
      </div>
      <div className="absolute top-1 right-1 w-4 h-4 rounded-full flex items-center justify-center text-[8px] font-bold"
        style={{ backgroundColor: accentColor }}>
        {seatNumber}
      </div>

      {/* Captain crown */}
      {player && isCaptain && (
        <div className="absolute top-0 left-1/2 transform -translate-x-1/2 -translate-y-1/2 text-yellow-400 text-sm">­ƒææ</div>
      )}

      {/* Ready dot */}
      {player?.isReady && (
        <div className="absolute bottom-1 right-1 w-2 h-2 bg-green-400 rounded-full animate-pulse" />
      )}

      {/* Kick button (organizer) */}
      {role === "organizer" && player && (
        <button onClick={(e) => { e.stopPropagation(); onKick?.(player.id); }}
          className="absolute -top-1 -left-1 w-5 h-5 bg-red-500 rounded-full flex items-center justify-center text-[10px] text-white hover:bg-red-600 transition z-10">
          Ô£ò
        </button>
      )}

      {/* Swap icon overlay (not my seat, is participant) */}
      {player && !isCurrentUser && role === "participant" && tournament?.status === "open" && (
        <div className="absolute inset-0 rounded-xl bg-black/0 hover:bg-black/40 flex items-center justify-center opacity-0 hover:opacity-100 transition-all duration-200 z-5">
          <span className="text-2xl">­ƒöä</span>
        </div>
      )}

      {/* Pending swap request badge */}
      {hasPendingRequest && (
        <div className="absolute -top-2 -right-2 z-20">
          <div className="w-5 h-5 bg-yellow-400 rounded-full flex items-center justify-center text-[10px] animate-bounce">
            ­ƒöä
          </div>
        </div>
      )}

      {/* Player content */}
      {player ? (
        <>
          <div className="mb-1 mt-3">
            {player.avatar_url ? (
              <img src={player.avatar_url} alt={player.full_name}
                className="w-10 h-10 rounded-full mx-auto object-cover border-2"
                style={{ borderColor: accentColor }} />
            ) : (
              <div className="w-10 h-10 rounded-full mx-auto flex items-center justify-center text-lg font-bold"
                style={{ backgroundColor: `${accentColor}30`, color: accentColor }}>
                {player.full_name?.[0] || "?"}
              </div>
            )}
          </div>
          <p className="text-white text-xs font-medium truncate">
            {isCurrentUser ? `${player.full_name} (You)` : player.full_name}
          </p>
          <p className="text-white/40 text-[9px] truncate">{player.free_fire_id || ""}</p>
        </>
      ) : (
        <div className="h-full flex items-center justify-center">
          <p className="text-white/20 text-xs">Empty</p>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "../../lib/supabase";

export default function PlayerProfilePanel({ player, onClose, accentColor }) {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    if (!player?.user_id) return;
    supabase
      .from("player_stats")
      .select("kills, wins, tournaments_played, kd_ratio, total_points, best_position")
      .eq("user_id", player.user_id)
      .maybeSingle()
      .then(({ data }) => setStats(data));
  }, [player?.user_id]);

  if (!player) return null;

  const matches  = stats?.tournaments_played || 0;
  const wins     = stats?.wins               || 0;
  const kills    = stats?.kills              || 0;
  const winRate  = matches > 0 ? Math.round((wins / matches) * 100) : 0;
  const ac       = accentColor || "#7C3AED";

  return (
    <AnimatePresence>
      <motion.div
        initial={{ x: 300 }}
        animate={{ x: 0 }}
        exit={{ x: 300 }}
        transition={{ type:"spring", damping:25, stiffness:200 }}
        className="fixed right-0 top-0 h-full w-80 bg-[#11151F] border-l border-white/10 shadow-2xl z-50 overflow-y-auto"
        style={{ boxShadow: `-5px 0 30px ${ac}20` }}
      >
        <div className="p-6 border-b border-white/10">
          <button onClick={onClose} className="text-white/40 hover:text-white text-sm mb-4 flex items-center gap-2 transition">
            ÔåÉ Fermer
          </button>
        </div>

        <div className="p-6 flex flex-col items-center gap-4">

          {/* Avatar */}
          <div
            className="w-24 h-24 rounded-2xl flex items-center justify-center text-3xl font-bold text-white shadow-xl overflow-hidden"
            style={{ background:`linear-gradient(135deg,${ac},#4C1D95)`, boxShadow:`0 10px 25px ${ac}40` }}
          >
            {player.profiles?.avatar_url
              ? <img src={player.profiles.avatar_url} alt="" className="w-full h-full object-cover"/>
              : player.profiles?.full_name?.charAt(0) || "U"}
          </div>

          <h2 className="text-xl font-bold text-white text-center">
            {player.profiles?.full_name}
          </h2>

          <div className="bg-[#1A1F2B] rounded-lg px-4 py-2 w-full text-center">
            <p className="text-xs text-white/40">Free Fire ID</p>
            <p className="text-sm font-mono" style={{ color: ac }}>
              {player.profiles?.free_fire_id || "N/A"}
            </p>
          </div>

          {/* Stats r├®elles */}
          <div className="grid grid-cols-2 gap-3 w-full">
            <div className="bg-[#1A1F2B] p-4 rounded-lg text-center">
              <p className="text-xl font-bold text-white">{matches}</p>
              <p className="text-xs text-white/40">Matchs</p>
            </div>
            <div className="bg-[#1A1F2B] p-4 rounded-lg text-center">
              <p className="text-xl font-bold text-white">{wins}</p>
              <p className="text-xs text-white/40">Victoires</p>
            </div>
            <div className="bg-[#1A1F2B] p-4 rounded-lg text-center">
              <p className="text-xl font-bold" style={{ color:"#ef4444" }}>{kills}</p>
              <p className="text-xs text-white/40">Kills</p>
            </div>
            <div className="bg-[#1A1F2B] p-4 rounded-lg text-center">
              <p className="text-xl font-bold" style={{ color:"#00d4ff" }}>{winRate}%</p>
              <p className="text-xs text-white/40">Win Rate</p>
            </div>
          </div>

          {/* Win rate bar */}
          <div className="bg-[#1A1F2B] p-4 rounded-lg w-full">
            <p className="text-xs text-white/40 mb-2">Win Rate</p>
            <div className="flex items-center gap-2">
              <span className="text-2xl font-bold" style={{ color: ac }}>{winRate}%</span>
              <div className="flex-1 h-2 bg-white/5 rounded-full overflow-hidden">
                <div className="h-full rounded-full transition-all duration-700" style={{ width:`${winRate}%`, backgroundColor: ac }} />
              </div>
            </div>
          </div>

          <div className="flex gap-3 w-full mt-2">
            <button onClick={onClose}
              className="flex-1 px-4 py-2 border border-white/10 hover:border-white/30 rounded-lg text-sm font-medium transition">
              Fermer
            </button>
          </div>
        </div>
      </motion.div>
    </AnimatePresence>
  );
}

import React, { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

export default function RoomChat({
  messages,
  onSendMessage,
  currentUser,
  role,
  roomLocked,
  onSelectPlayer,
  accentColor,
}) {
  const [newMessage, setNewMessage] = useState("");
  const [isNearBottom, setIsNearBottom] = useState(true);
  const [typingUsers, setTypingUsers] = useState([]);
  const messagesEndRef = useRef(null);
  const containerRef = useRef(null);
  const typingTimeoutRef = useRef(null);

  useEffect(() => {
    if (isNearBottom) {
      messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages]);

  const handleScroll = () => {
    const el = containerRef.current;
    if (!el) return;
    const nearBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 100;
    setIsNearBottom(nearBottom);
  };

  const handleTyping = () => {
    if (role === "spectator") return;
    clearTimeout(typingTimeoutRef.current);
    typingTimeoutRef.current = setTimeout(() => {}, 2000);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!newMessage.trim()) return;
    onSendMessage(newMessage);
    setNewMessage("");
  };

  if (role === "spectator") {
    return (
      <div className="h-full bg-[#0E111A] flex flex-col border-t border-white/10">
        <div className="px-4 py-3 flex items-center justify-between bg-[#11151F] border-b border-white/10">
          <h3 className="text-sm font-semibold text-white tracking-wide">ROOM CHAT</h3>
          <span className="text-xs text-white/40">{messages.length} Messages</span>
        </div>
        <div className="flex-1 flex items-center justify-center">
          <p className="text-white/40 text-sm">­ƒæÇ Spectator mode - Chat disabled</p>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full bg-[#0E111A] flex flex-col border-t border-white/10">

      <div className="px-4 py-3 flex items-center justify-between bg-[#11151F] border-b border-white/10">
        <h3 className="text-sm font-semibold text-white tracking-wide">ROOM CHAT</h3>
        <span className="text-xs text-white/40">{messages.length} Messages</span>
      </div>

      <div
        ref={containerRef}
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-thin scrollbar-thumb-purple-600/30"
      >
        <AnimatePresence>
          {messages.map((msg) => {
            const isCurrentUser = msg.user_id === currentUser?.id;
            
            return (
              <motion.div
                key={msg.id}
                initial={{ opacity: 0, y: 15 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                transition={{ duration: 0.2 }}
                className={`flex items-start gap-3 group ${isCurrentUser ? 'flex-row-reverse' : ''}`}
              >
                <div
                  onClick={() => onSelectPlayer(msg)}
                  className="w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold cursor-pointer bg-gradient-to-br from-purple-600 to-indigo-600 hover:scale-110 transition flex-shrink-0"
                  style={{
                    background: accentColor ? `linear-gradient(135deg, ${accentColor}, #4C1D95)` : undefined
                  }}
                >
                  {msg.profiles?.full_name?.charAt(0) || "U"}
                </div>

                <div className={`flex-1 min-w-0 ${isCurrentUser ? 'text-right' : ''}`}>
                  <div className={`flex items-center gap-2 ${isCurrentUser ? 'justify-end' : ''}`}>
                    <span
                      onClick={() => onSelectPlayer(msg)}
                      className={`text-xs font-semibold cursor-pointer hover:underline ${
                        isCurrentUser ? 'text-purple-400 order-2' : 'text-purple-400'
                      }`}
                    >
                      {isCurrentUser ? 'You' : (msg.profiles?.full_name?.split(' ')[0] || "Player")}
                    </span>

                    <span className="text-[10px] text-white/30">
                      {new Date(msg.created_at).toLocaleTimeString([], {
                        hour: "2-digit",
                        minute: "2-digit",
                      })}
                    </span>

                    {msg.user_id === currentUser?.id && role === "organizer" && (
                      <span className="text-[8px] bg-purple-600/20 text-purple-400 px-1.5 py-0.5 rounded-full">
                        ORG
                      </span>
                    )}
                  </div>

                  <p className={`text-sm text-white/80 mt-1 leading-relaxed break-words ${
                    isCurrentUser ? 'text-purple-100' : ''
                  }`}>
                    {msg.message}
                  </p>
                </div>
              </motion.div>
            );
          })}
        </AnimatePresence>

        {typingUsers.length > 0 && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="flex items-center gap-2 text-white/40 text-xs"
          >
            <div className="flex gap-1">
              <span className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce" style={{ animationDelay: "0ms" }}></span>
              <span className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce" style={{ animationDelay: "150ms" }}></span>
              <span className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-bounce" style={{ animationDelay: "300ms" }}></span>
            </div>
            <span>{typingUsers.join(', ')} typing...</span>
          </motion.div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {!roomLocked && (
        <form
          onSubmit={handleSubmit}
          className="p-4 bg-[#11151F] border-t border-white/10"
        >
          <div className="flex gap-3">
            <input
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              onKeyDown={handleTyping}
              placeholder="Type your message..."
              className="flex-1 px-4 py-2 bg-[#0E111A] border border-white/10 rounded-lg text-white text-sm focus:outline-none focus:border-purple-500 transition"
            />
            <button
              type="submit"
              className="px-5 py-2 bg-purple-600 hover:bg-purple-700 rounded-lg text-sm font-medium transition transform hover:scale-105"
              style={{ backgroundColor: accentColor }}
            >
              Send
            </button>
          </div>
        </form>
      )}

      {roomLocked && (
        <div className="p-4 bg-[#11151F] border-t border-white/10 text-center text-white/40 text-sm">
          ­ƒöÆ Room locked - Chat disabled
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";

export default function RoomSidebar({
  tournament,
  players,
  members,
  readyCount,
  role,
  countdown,
  roomLocked,
  currentUserReady,
  userReady,
  onToggleReady,
  onStartMatch,
  onEndMatch,
  onOpenSubmit,
  onLockRoom,
}) {
  const [roomCode, setRoomCode] = useState("");
  const [roomPass, setRoomPass] = useState("");
  const [saving, setSaving] = useState(false);
  const [copied, setCopied] = useState("");
  const [toggling, setToggling] = useState(false);

  useEffect(() => {
    if (tournament?.room_code) setRoomCode(tournament.room_code);
    if (tournament?.room_password) setRoomPass(tournament.room_password);
  }, [tournament?.room_code, tournament?.room_password]);

  const isOrganizer = role === "organizer";
  const allMembers = players || members || [];
  const totalCount = allMembers.length;
  const rCount = readyCount !== undefined
    ? readyCount
    : allMembers.filter(m => m.is_ready === true).length;
  const allReady = totalCount > 0 && rCount >= totalCount;
  const isReady = currentUserReady === true || userReady === "Yes" || userReady === true;

  const tStatus = tournament?.room_status || tournament?.status || "ready";
  const phase =
    tStatus === "live"           ? "live"
    : tStatus === "results_open" ? "results"
    : tStatus === "results_closed" || tStatus === "finished" ? "done"
    : "ready";

  const copy = (val, key) => {
    navigator.clipboard.writeText(val);
    setCopied(key);
    setTimeout(() => setCopied(""), 1500);
  };

  const saveRoom = async () => {
    setSaving(true);
    try {
      const { supabase } = await import("../../lib/supabase");
      await supabase.from("tournaments")
        .update({ room_code: roomCode, room_password: roomPass })
        .eq("id", tournament.id);
    } catch (e) { console.error(e); }
    setSaving(false);
  };

  const handleReady = async () => {
    if (toggling) return;
    setToggling(true);
    try { await onToggleReady(); } catch(_e) {}
    setToggling(false);
  };

  return (
    <div style={{
      background:"linear-gradient(180deg,#0f0f1a 0%,#070710 100%)",
      border:"1px solid rgba(139,92,246,0.3)",
      borderRadius:12, padding:20,
      display:"flex", flexDirection:"column", gap:14, minWidth:220,
    }}>
      <div style={{ textAlign:"center" }}>
        <div style={{ fontSize:20, fontWeight:800, color:"#a78bfa", letterSpacing:2 }}>
          {tournament?.name || "ROOM"}
        </div>
        <div style={{ fontSize:12, color:"#6b7280", marginTop:2 }}>
          {tournament?.game_type} ┬À {tournament?.mode || tournament?.cs_format}
        </div>
      </div>

      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:8 }}>
        <Stat label="JOUEURS" value={`${totalCount}/${tournament?.max_players||"?"}`} color="#00d4ff" />
        <Stat label="PR├èTS" value={`${rCount}/${totalCount}`}
          color={allReady?"#10b981":rCount>0?"#f59e0b":"#6b7280"} />
      </div>

      <div>
        <div style={{ background:"#1a1a2e", borderRadius:4, height:6, overflow:"hidden" }}>
          <div style={{
            height:"100%",
            width: totalCount ? `${(rCount/totalCount)*100}%` : "0%",
            background: allReady
              ? "linear-gradient(90deg,#10b981,#059669)"
              : "linear-gradient(90deg,#7c3aed,#00d4ff)",
            transition:"width 0.4s ease",
          }} />
        </div>
        {allMembers.length > 0 && (
          <div style={{ marginTop:8, display:"flex", flexDirection:"column", gap:5 }}>
            {allMembers.map(m => (
              <div key={m.user_id||m.id} style={{
                display:"flex", alignItems:"center", gap:8,
                fontSize:12, color: m.is_ready?"#10b981":"#6b7280",
              }}>
                <span>{m.is_ready ? "Ô£à" : "ÔÅ│"}</span>
                <span style={{ flex:1, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                  {m.profiles?.full_name || m.full_name || "Joueur"}
                </span>
                <span style={{ fontSize:10, color: m.is_ready?"#10b981":"#4b5563", flexShrink:0 }}>
                  {m.is_ready ? "PR├èT" : "EN ATTENTE"}
                </span>
              </div>
            ))}
          </div>
        )}
        {allReady && (
          <div style={{ fontSize:11, color:"#10b981", textAlign:"center", marginTop:6, fontWeight:700 }}>
            Ô£à Tous les joueurs sont pr├¬ts !
          </div>
        )}
      </div>

      {(tournament?.room_code || (isOrganizer && phase==="ready")) && (
        <div style={{
          background:"rgba(0,212,255,0.05)", border:"1px solid rgba(0,212,255,0.2)",
          borderRadius:8, padding:12, display:"flex", flexDirection:"column", gap:8,
        }}>
          {isOrganizer && phase==="ready" ? (
            <>
              <Lbl>ID DE LA ROOM</Lbl>
              <input value={roomCode} onChange={e=>setRoomCode(e.target.value)}
                placeholder="Ex: 123456789" style={INP} />
              <Lbl>MOT DE PASSE</Lbl>
              <input value={roomPass} onChange={e=>setRoomPass(e.target.value)}
                placeholder="Ex: cipher" style={INP} />
              <button onClick={saveRoom} disabled={saving} style={SBTN}>
                {saving?"...":"­ƒÆ¥ ENREGISTRER"}
              </button>
            </>
          ) : (
            <>
              {tournament?.room_code && (
                <InfoRow label="ID ROOM" value={tournament.room_code}
                  onCopy={()=>copy(tournament.room_code,"code")} copied={copied==="code"} />
              )}
              {tournament?.room_password && (
                <InfoRow label="MOT DE PASSE" value={tournament.room_password}
                  onCopy={()=>copy(tournament.room_password,"pass")} copied={copied==="pass"} />
              )}
            </>
          )}
        </div>
      )}

      {!isOrganizer && phase==="ready" && (
        <button onClick={handleReady} disabled={toggling} style={{
          padding:"13px 0", borderRadius:8, border:"none",
          cursor: toggling?"wait":"pointer",
          fontWeight:700, fontSize:14, letterSpacing:1,
          background: isReady
            ?"linear-gradient(135deg,#10b981,#059669)"
            :"linear-gradient(135deg,#7c3aed,#4c1d95)",
          color:"#fff", opacity: toggling?0.7:1,
          boxShadow: isReady?"0 0 16px rgba(16,185,129,0.4)":"0 0 16px rgba(124,58,237,0.3)",
          transition:"all 0.2s",
        }}>
          {toggling?"...":isReady?"Ô£à PR├èT ÔÇö Annuler":"ÔÜí JE SUIS PR├èT"}
        </button>
      )}

      {isOrganizer && phase==="ready" && (
        <button onClick={onStartMatch} style={{
          padding:"14px 0", borderRadius:8, border:"none", cursor:"pointer",
          fontWeight:800, fontSize:15, letterSpacing:1.5,
          background: allReady
            ?"linear-gradient(135deg,#10b981,#059669)"
            :"linear-gradient(135deg,#7c3aed,#4c1d95)",
          color:"#fff",
          boxShadow: allReady?"0 0 24px rgba(16,185,129,0.5)":"0 0 20px rgba(124,58,237,0.4)",
          animation:"glow 2s infinite",
        }}>
          ÔûÂ LANCER LE MATCH
          {!allReady && totalCount>0 && (
            <span style={{ display:"block", fontSize:10, fontWeight:400, opacity:0.7, marginTop:2 }}>
              ({rCount}/{totalCount} pr├¬ts)
            </span>
          )}
        </button>
      )}

      {isOrganizer && phase==="live" && onEndMatch && (
        <button onClick={onEndMatch} style={{
          padding:"14px 0", borderRadius:8, border:"none", cursor:"pointer",
          fontWeight:800, fontSize:15,
          background:"linear-gradient(135deg,#ef4444,#dc2626)",
          color:"#fff", boxShadow:"0 0 20px rgba(239,68,68,0.4)",
        }}>
          ­ƒÅü TERMINER LE MATCH
        </button>
      )}

      {isOrganizer && phase==="results" && (
        <div style={{
          background:"rgba(245,158,11,0.1)", border:"1px solid rgba(245,158,11,0.3)",
          borderRadius:10, padding:"14px 16px", textAlign:"center"
        }}>
          <div style={{fontSize:18, marginBottom:6}}>ÔÅ│</div>
          <div style={{fontSize:13, fontWeight:700, color:"#f59e0b"}}>SOUMISSION OUVERTE</div>
          <div style={{fontSize:11, color:"#6b7280", marginTop:4}}>
            En attente des r├®sultats des joueurs
          </div>
          <div style={{fontSize:11, color:"#6b7280", marginTop:2}}>
            Validez-les dans ÔåÆ Admin Results
          </div>
        </div>
      )}

            {!isOrganizer && phase==="results" && onOpenSubmit && (
        <button onClick={onOpenSubmit} style={{
          padding:"14px 0", borderRadius:8, border:"none", cursor:"pointer",
          fontWeight:800, fontSize:14,
          background:"linear-gradient(135deg,#f59e0b,#d97706)",
          color:"#fff", boxShadow:"0 0 20px rgba(245,158,11,0.4)",
          animation:"glow 2s infinite",
        }}>
          ­ƒôè SOUMETTRE MON R├ëSULTAT
        </button>
      )}

      <div style={{
        textAlign:"center", fontSize:11, color:"#4b5563",
        borderTop:"1px solid rgba(255,255,255,0.05)", paddingTop:10,
      }}>
        {phase==="live"    && <span style={{color:"#ef4444"}}>­ƒö┤ MATCH EN COURS</span>}
        {phase==="ready"   && "ÔÅ│ EN ATTENTE DE LANCEMENT"}
        {phase==="results" && <span style={{color:"#f59e0b"}}>­ƒôè SOUMISSION OUVERTE</span>}
        {phase==="done"    && <span style={{color:"#10b981"}}>Ô£à TERMIN├ë</span>}
      </div>

      <style>{`@keyframes glow{0%,100%{filter:brightness(1)}50%{filter:brightness(1.2)}}`}</style>
    </div>
  );
}

const Stat = ({label,value,color}) => (
  <div style={{background:"rgba(255,255,255,0.03)",borderRadius:8,padding:"10px 8px",textAlign:"center"}}>
    <div style={{fontSize:11,color:"#6b7280",marginBottom:4}}>{label}</div>
    <div style={{fontSize:22,fontWeight:800,color}}>{value}</div>
  </div>
);
const Lbl = ({children}) => (
  <div style={{fontSize:10,color:"#6b7280",fontWeight:700,letterSpacing:1}}>{children}</div>
);
const InfoRow = ({label,value,onCopy,copied}) => (
  <div>
    <Lbl>{label}</Lbl>
    <div style={{display:"flex",alignItems:"center",gap:6,marginTop:4}}>
      <div style={{flex:1,background:"rgba(0,0,0,0.3)",borderRadius:6,padding:"6px 10px",
        fontSize:15,fontWeight:700,color:"#00d4ff",letterSpacing:2}}>{value}</div>
      <button onClick={onCopy} style={{
        background:copied?"#10b981":"rgba(0,212,255,0.1)",
        border:"1px solid rgba(0,212,255,0.3)",
        borderRadius:6,padding:"6px 10px",color:"#00d4ff",cursor:"pointer",fontSize:13,
      }}>{copied?"Ô£ô":"­ƒôï"}</button>
    </div>
  </div>
);
const INP={width:"100%",background:"rgba(0,0,0,0.4)",border:"1px solid rgba(139,92,246,0.3)",
  borderRadius:6,padding:"8px 10px",color:"#e2e8f0",fontSize:14,outline:"none",boxSizing:"border-box"};
const SBTN={padding:"8px 0",borderRadius:6,border:"none",cursor:"pointer",
  background:"linear-gradient(135deg,#7c3aed,#4c1d95)",color:"#fff",fontWeight:700,fontSize:13};

