import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "../../lib/supabase";

const CYAN="#00d4ff",GREEN="#10b981",RED="#f43f5e",AMBER="#fbbf24",INDIGO="#818cf8",VIOLET="#a78bfa";

const STATUSES = [
  { key:"registration", label:"INSCRIPTION",    icon:"­ƒôï", color:INDIGO },
  { key:"ready",        label:"PR├èT",           icon:"Ô£à", color:VIOLET },
  { key:"waiting",      label:"EN ATTENTE",     icon:"ÔÅ│", color:AMBER  },
  { key:"live",         label:"EN COURS",       icon:"­ƒö┤", color:RED    },
  { key:"results_open", label:"R├ëSULTATS",      icon:"­ƒôè", color:CYAN   },
  { key:"results_closed",label:"TERMIN├ë",       icon:"­ƒÅü", color:GREEN  },
];

function useCountdown(targetTime) {
  const [remaining, setRemaining] = useState(null);
  useEffect(() => {
    if (!targetTime) return;
    const tick = () => {
      const diff = new Date(targetTime) - new Date();
      setRemaining(Math.max(0, Math.floor(diff / 1000)));
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [targetTime]);
  return remaining;
}

function formatTime(secs) {
  if (secs === null) return "--:--";
  const m = Math.floor(secs / 60).toString().padStart(2,"0");
  const s = (secs % 60).toString().padStart(2,"0");
  return `${m}:${s}`;
}

// ÔöÇÔöÇ Admin setup panel: set room code + start time ÔöÇÔöÇ
function RoomSetupPanel({ tournament, onDone }) {
  const [code,     setCode]     = useState(tournament?.room_code || "");
  const [pass,     setPass]     = useState(tournament?.room_password || "");
  const [startDt,  setStartDt]  = useState("");
  const [duration, setDuration] = useState(tournament?.match_duration || 20);
  const [window_,  setWindow]   = useState(tournament?.result_window  || 10);
  const [saving,   setSaving]   = useState(false);
  const [error,    setError]    = useState("");

  const handleSave = async () => {
    if (!code.trim())   { setError("Room ID requis"); return; }
    if (!startDt)       { setError("Heure de d├®but requise"); return; }
    setSaving(true); setError("");
    const { data, error: e } = await supabase.rpc("setup_room", {
      p_tournament_id:  tournament.id,
      p_room_code:      code.trim(),
      p_room_password:  pass.trim() || null,
      p_start_time:     new Date(startDt).toISOString(),
      p_match_duration: duration,
      p_result_window:  window_,
    });
    setSaving(false);
    if (e || !data?.success) { setError(e?.message || data?.error); return; }
    onDone();
  };

  const inp = {
    padding:"10px 14px", borderRadius:10,
    background:"rgba(255,255,255,.04)", border:"1px solid rgba(255,255,255,.1)",
    color:"#fff", fontFamily:"Space Grotesk,sans-serif", fontSize:13,
    outline:"none", width:"100%", boxSizing:"border-box"
  };

  return (
    <motion.div initial={{opacity:0,y:10}} animate={{opacity:1,y:0}}
      style={{padding:"20px", background:"#0a1628", borderRadius:16, border:`1px solid ${AMBER}22`, marginBottom:12}}>
      <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:8,letterSpacing:3,color:AMBER+"99",marginBottom:16}}>
        ÔÜÖ´©Å CONFIGURER LA ROOM
      </p>
      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
          <div>
            <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:7,color:"rgba(255,255,255,.25)",letterSpacing:1,marginBottom:5}}>ID ROOM *</p>
            <input value={code} onChange={e=>setCode(e.target.value)} placeholder="Ex: 123456" style={inp}/>
          </div>
          <div>
            <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:7,color:"rgba(255,255,255,.25)",letterSpacing:1,marginBottom:5}}>MOT DE PASSE</p>
            <input value={pass} onChange={e=>setPass(e.target.value)} placeholder="Optionnel" style={inp}/>
          </div>
        </div>
        <div>
          <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:7,color:"rgba(255,255,255,.25)",letterSpacing:1,marginBottom:5}}>HEURE DE D├ëBUT *</p>
          <input type="datetime-local" value={startDt} onChange={e=>setStartDt(e.target.value)} style={{...inp,colorScheme:"dark"}}/>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
          <div>
            <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:7,color:"rgba(255,255,255,.25)",letterSpacing:1,marginBottom:5}}>DUR├ëE MATCH (min)</p>
            <input type="number" value={duration} onChange={e=>setDuration(+e.target.value)} min={5} max={60} style={inp}/>
          </div>
          <div>
            <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:7,color:"rgba(255,255,255,.25)",letterSpacing:1,marginBottom:5}}>FEN├èTRE R├ëSULTATS (min)</p>
            <input type="number" value={window_} onChange={e=>setWindow(+e.target.value)} min={5} max={30} style={inp}/>
          </div>
        </div>
        {error && <p style={{color:RED,fontFamily:"Space Grotesk,sans-serif",fontSize:12}}>ÔØî {error}</p>}
        <motion.button whileHover={{scale:1.02}} whileTap={{scale:.97}} onClick={handleSave} disabled={saving}
          style={{padding:"13px 0",borderRadius:12,background:`linear-gradient(135deg,${AMBER},rgba(251,191,36,.6))`,border:"none",color:"#000",fontFamily:"JetBrains Mono,monospace",fontSize:11,letterSpacing:2,fontWeight:700,cursor:"pointer"}}>
          {saving ? "ENREGISTREMENT..." : "­ƒÆ¥ CR├ëER LA ROOM"}
        </motion.button>
      </div>
    </motion.div>
  );
}

// ÔöÇÔöÇ Main RoomStatusBar ÔöÇÔöÇ
export default function RoomStatusBar({ tournament, role, onTournamentUpdate }) {
  const [showSetup, setShowSetup] = useState(false);
  const [closingReg, setClosingReg] = useState(false);

  // Fallback: derive room_status from old status if new column not yet added
  const status = tournament?.room_status || (
    tournament?.status === "live"     ? "live"     :
    tournament?.status === "finished" ? "results_open" :
    tournament?.status === "closed"   ? "ready"    :
    "registration"
  );
  const current = STATUSES.find(s=>s.key===status) || STATUSES[0];
  const currentIdx = STATUSES.findIndex(s=>s.key===status);
  const isOrg = role === "organizer";

  // Countdown targets
  const waitingCountdown = status === "waiting" ? tournament?.start_time : null;
  const liveCountdown    = status === "live"    ? tournament?.end_time   : null;
  const resultsCountdown = status === "results_open" ? tournament?.result_deadline : null;
  const countdown = useCountdown(waitingCountdown || liveCountdown || resultsCountdown);

  // Poll sync_room_status every 10s
  useEffect(() => {
    if (!tournament?.id) return;
    if (!["waiting","live","results_open"].includes(status)) return;
    const poll = async () => {
      const { data } = await supabase.rpc("sync_room_status", { p_tournament_id: tournament.id });
      if (data?.success && data.tournament?.room_status !== status) {
        onTournamentUpdate?.(data.tournament);
      }
    };
    poll();
    const id = setInterval(poll, 10000);
    return () => clearInterval(id);
  }, [tournament?.id, status, onTournamentUpdate]);

  const handleCloseRegistration = async () => {
    setClosingReg(true);
    await supabase.rpc("close_registration", { p_tournament_id: tournament.id });
    setClosingReg(false);
    onTournamentUpdate?.({ ...tournament, room_status:"ready", status:"closed" });
  };

  const countdownLabel = {
    waiting:      "D├ëBUT DANS",
    live:         "FIN DANS",
    results_open: "CL├öTURE DANS",
  }[status];

  return (
    <div style={{width:"100%",background:"#060f23",borderBottom:"1px solid rgba(255,255,255,.06)"}}>

      {/* Progress steps */}
      <div style={{display:"flex",alignItems:"center",padding:"12px 20px",gap:4,overflowX:"auto"}}>
        {STATUSES.map((s,i) => {
          const done    = i < currentIdx;
          const active  = i === currentIdx;
          return (
            <div key={s.key} style={{display:"flex",alignItems:"center",flexShrink:0}}>
              <div style={{
                display:"flex",alignItems:"center",gap:6,padding:"5px 10px",borderRadius:20,
                background: active ? `${s.color}18` : done ? "rgba(255,255,255,.03)" : "transparent",
                border: `1px solid ${active ? s.color+"55" : done ? "rgba(255,255,255,.08)" : "transparent"}`,
              }}>
                <span style={{fontSize:12}}>{done ? "Ô£ô" : s.icon}</span>
                <span style={{
                  fontFamily:"JetBrains Mono,monospace",fontSize:8,letterSpacing:1,
                  color: active ? s.color : done ? "rgba(255,255,255,.35)" : "rgba(255,255,255,.15)"
                }}>
                  {s.label}
                </span>
              </div>
              {i < STATUSES.length-1 && (
                <div style={{width:20,height:1,background:done?"rgba(255,255,255,.15)":"rgba(255,255,255,.06)",margin:"0 2px"}}/>
              )}
            </div>
          );
        })}
      </div>

      {/* Countdown strip */}
      {countdown !== null && countdownLabel && (
        <div style={{
          background: status==="live" ? `${RED}11` : status==="results_open" ? `${CYAN}0a` : `${AMBER}0a`,
          borderTop:`1px solid ${status==="live"?RED:status==="results_open"?CYAN:AMBER}22`,
          padding:"8px 20px",display:"flex",justifyContent:"space-between",alignItems:"center"
        }}>
          <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:8,letterSpacing:2,
            color:status==="live"?RED:status==="results_open"?CYAN:AMBER}}>
            {countdownLabel}
          </p>
          <p style={{fontFamily:"Bebas Neue,cursive",fontSize:22,letterSpacing:2,
            color:status==="live"?RED:status==="results_open"?CYAN:AMBER,
            textShadow:`0 0 16px currentColor`}}>
            {formatTime(countdown)}
          </p>
          {/* Live progress bar */}
          {status === "live" && tournament?.start_time && tournament?.end_time && (() => {
            const pct = Math.min(100, ((Date.now() - new Date(tournament.start_time)) / (new Date(tournament.end_time) - new Date(tournament.start_time))) * 100);
            return (
              <div style={{position:"absolute",bottom:0,left:0,right:0,height:2,background:"rgba(255,255,255,.05)"}}>
                <motion.div style={{ height:"100%", background:RED, width:`${pct}%` }}/>
              </div>
            );
          })()}
        </div>
      )}

      {/* Admin controls */}
      {isOrg && (
        <div style={{padding:"10px 20px",borderTop:"1px solid rgba(255,255,255,.04)",display:"flex",gap:8,flexWrap:"wrap"}}>
          {status === "registration" && (
            <motion.button whileHover={{scale:1.03}} whileTap={{scale:.96}}
              onClick={handleCloseRegistration} disabled={closingReg}
              style={{padding:"8px 16px",borderRadius:9,background:`rgba(129,140,248,.12)`,border:`1px solid rgba(129,140,248,.25)`,color:INDIGO,fontFamily:"JetBrains Mono,monospace",fontSize:9,letterSpacing:1.5,cursor:"pointer",fontWeight:700}}>
              ­ƒöÆ FERMER INSCRIPTIONS
            </motion.button>
          )}
          {status === "ready" && !tournament?.room_code && (
            <motion.button whileHover={{scale:1.03}} whileTap={{scale:.96}}
              onClick={() => setShowSetup(s=>!s)}
              style={{padding:"8px 16px",borderRadius:9,background:`${AMBER}18`,border:`1px solid ${AMBER}33`,color:AMBER,fontFamily:"JetBrains Mono,monospace",fontSize:9,letterSpacing:1.5,cursor:"pointer",fontWeight:700}}>
              ÔÜÖ´©Å {showSetup ? "ANNULER" : "CONFIGURER ROOM"}
            </motion.button>
          )}
          {status === "results_open" && (
            <motion.button whileHover={{scale:1.03}} whileTap={{scale:.96}}
              onClick={async()=>{
                await supabase.from("tournaments").update({room_status:"results_closed"}).eq("id",tournament.id);
                onTournamentUpdate?.({...tournament,room_status:"results_closed"});
              }}
              style={{padding:"8px 16px",borderRadius:9,background:`${RED}12`,border:`1px solid ${RED}33`,color:RED,fontFamily:"JetBrains Mono,monospace",fontSize:9,letterSpacing:1.5,cursor:"pointer",fontWeight:700}}>
              ­ƒÜ½ FERMER R├ëSULTATS
            </motion.button>
          )}
        </div>
      )}

      {/* Setup panel */}
      <AnimatePresence>
        {showSetup && isOrg && (
          <div style={{padding:"0 20px 12px"}}>
            <RoomSetupPanel tournament={tournament} onDone={() => { setShowSetup(false); window.location.reload(); }} />
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { useState, useEffect } from "react";
import { supabase } from "../../lib/supabase";

const CS_PTS = { 1: 10, 2: 6 };
const BR_PTS = { 1:12, 2:9, 3:8, 4:7, 5:6, 6:5, 7:4, 8:3, 9:2, 10:1, 11:1, 12:0 };

export default function SubmitResultPanel({ tournament, tournamentId, userId, onClose, onSubmitted }) {
  const [tData, setTData]   = useState(tournament || null);
  const [placement, setPlacement] = useState("");
  const [kills, setKills]   = useState("");
  const [screenshot, setScreenshot] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError]   = useState("");
  const [done, setDone]     = useState(false);

  // Get tournament data from tournamentId prop OR URL
  useEffect(() => {
    if (tData?.id) return;
    // Use tournamentId prop first, then URL fallback
    const tid = tournamentId || (() => {
      const segs = window.location.pathname.split("/");
      const idx  = segs.indexOf("tournaments");
      return idx !== -1 ? segs[idx + 1] : null;
    })();
    if (!tid) return;
    supabase.from("tournaments")
      .select("id,name,game_type,mode,cs_format")
      .eq("id", tid).maybeSingle()
      .then(({ data }) => { if (data) setTData(data); });
  }, [tournamentId]);

  // Check already submitted
  useEffect(() => {
    const tid = tData?.id || tournamentId;
    if (!tid || !userId) return;
    supabase.from("match_results").select("id")
      .eq("tournament_id", tid).eq("user_id", userId).maybeSingle()
      .then(({ data }) => { if (data) setDone(true); });
  }, [tData?.id, tournamentId, userId]);

  const tid  = tData?.id || tournamentId;
  const isCS = tData?.game_type === "cs"
            || ["1v1","2v2","4v4"].includes(tData?.mode)
            || ["1v1","2v2","4v4"].includes(tData?.cs_format);
  const maxP = isCS ? 2 : 12;
  const pNum = parseInt(placement) || 0;
  const kNum = parseInt(kills) || 0;
  const pPts = isCS ? (CS_PTS[pNum] || 0) : (BR_PTS[pNum] || 0);
  const total = pPts + kNum;
  const coins = total * 10;

  const handleFile = (e) => {
    const f = e.target.files[0];
    if (!f) return;
    if (f.size > 5 * 1024 * 1024) { setError("Max 5MB"); return; }
    setScreenshot(f); setPreview(URL.createObjectURL(f)); setError("");
  };

  const handleSubmit = async () => {
    setError("");
    if (!tid)                                  return setError("Tournoi introuvable ÔÇö rafra├«chissez");
    if (!pNum || pNum < 1 || pNum > maxP)      return setError(`Placement invalide (1ÔÇô${maxP})`);
    if (kills === "" || kNum < 0 || kNum > 30) return setError("Kills invalides (0ÔÇô30)");
    if (!screenshot)                           return setError("Capture d'├®cran obligatoire !");

    setLoading(true);
    try {
      const ext  = screenshot.name.split(".").pop();
      const path = `${tid}/${userId}_${Date.now()}.${ext}`;

      const { error: upErr } = await supabase.storage
        .from("screenshots").upload(path, screenshot, { upsert: true });
      if (upErr) throw new Error("Upload: " + upErr.message);

      const { data: urlData } = supabase.storage.from("screenshots").getPublicUrl(path);

      const { error: insErr } = await supabase.from("match_results").upsert({
        tournament_id:   tid,
        user_id:         userId,
        placement:       pNum,
        kills:           kNum,
        points:          total,
        estimated_coins: coins,
        screenshot_url:  urlData?.publicUrl,
        status:          "pending",
        submitted_at:    new Date().toISOString(),
      }, { onConflict: "tournament_id,user_id" });
      if (insErr) throw new Error(insErr.message);

      setDone(true);
      if (onSubmitted) onSubmitted();
    } catch (e) { setError(e.message); }
    setLoading(false);
  };

  if (done) return (
    <div style={OVL} onClick={onClose}>
      <div style={MOD} onClick={e => e.stopPropagation()}>
        <div style={{ textAlign:"center", padding:"32px 0" }}>
          <div style={{ fontSize:52 }}>Ô£à</div>
          <div style={{ fontSize:20, fontWeight:800, color:"#10b981", marginTop:12 }}>
            R├®sultat envoy├® !
          </div>
          <div style={{ color:"#6b7280", marginTop:8, fontSize:13 }}>
            En attente de v├®rification par l'organisateur
          </div>
          <button onClick={onClose}
            style={{ ...BTN, marginTop:20, background:"rgba(255,255,255,0.08)" }}>
            Fermer
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div style={OVL} onClick={onClose}>
      <div style={MOD} onClick={e => e.stopPropagation()}>

        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:20 }}>
          <span style={{ fontSize:15, fontWeight:800, color:"#a78bfa", letterSpacing:1 }}>
            ­ƒôè SOUMETTRE R├ëSULTAT
            {tData?.name && <span style={{ fontSize:11, color:"#6b7280", marginLeft:8 }}>┬À {tData.name}</span>}
          </span>
          <button onClick={onClose} style={CBTN}>Ô£ò</button>
        </div>

        <F label={`­ƒÅå CLASSEMENT (1ÔÇô${maxP})`}>
          <input type="number" min="1" max={maxP} value={placement}
            onChange={e => setPlacement(e.target.value)}
            placeholder={isCS ? "1 ou 2" : "1 ├á 12"} style={INP} />
        </F>

        <F label="­ƒö½ KILLS (0ÔÇô30)">
          <input type="number" min="0" max="30" value={kills}
            onChange={e => setKills(e.target.value)}
            placeholder="Nombre de kills" style={INP} />
        </F>

        {placement && kills !== "" && (
          <div style={{ background:"rgba(124,58,237,0.08)", border:"1px solid rgba(124,58,237,0.2)",
            borderRadius:10, padding:"12px 16px", marginBottom:14 }}>
            <div style={{ fontSize:11, color:"#6b7280", marginBottom:8 }}>Ô£ª APER├çU</div>
            <R l={`Class├® n┬░${pNum}`} v={`+${pPts} pts`}  c="#a78bfa" />
            <R l={`Kills (${kNum})`}  v={`+${kNum} pts`}  c="#00d4ff" />
            <div style={{ borderTop:"1px solid rgba(255,255,255,0.08)", marginTop:6, paddingTop:6 }}>
              <R l="TOTAL"           v={`${total} pts`} c="#f59e0b" bold />
              <R l="Pi├¿ces estim├®es" v={`+${coins} ­ƒÆ░`} c="#fbbf24" />
            </div>
          </div>
        )}

        <F label="­ƒô© CAPTURE D'├ëCRAN *OBLIGATOIRE*">
          <div onClick={() => document.getElementById("ss-inp").click()}
            style={{ border:`2px dashed ${preview?"rgba(16,185,129,0.5)":"rgba(139,92,246,0.3)"}`,
              borderRadius:10, padding:12, textAlign:"center",
              background:"rgba(0,0,0,0.2)", cursor:"pointer", minHeight:80 }}>
            {preview ? (
              <>
                <img src={preview} alt="" style={{ maxHeight:130, borderRadius:8, objectFit:"contain" }} />
                <div onClick={e=>{e.stopPropagation();setScreenshot(null);setPreview(null);}}
                  style={{ fontSize:11, color:"#ef4444", marginTop:4, cursor:"pointer" }}>
                  Ô£ò Supprimer
                </div>
              </>
            ) : (
              <div style={{ color:"#6b7280", fontSize:13, paddingTop:12 }}>
                <div style={{ fontSize:28 }}>­ƒôÀ</div>
                Cliquez pour choisir (max 5MB)
              </div>
            )}
          </div>
          <input id="ss-inp" type="file" accept="image/*" onChange={handleFile} style={{ display:"none" }} />
        </F>

        {error && (
          <div style={{ background:"rgba(239,68,68,0.1)", border:"1px solid rgba(239,68,68,0.3)",
            borderRadius:8, padding:"10px 14px", color:"#fca5a5", fontSize:13, marginBottom:12 }}>
            Ô£ò {error}
          </div>
        )}

        <button onClick={handleSubmit} disabled={loading}
          style={{ ...BTN, opacity:loading?0.7:1, cursor:loading?"wait":"pointer" }}>
          {loading ? "Envoi..." : "­ƒÜÇ SOUMETTRE LE R├ëSULTAT"}
        </button>
      </div>
    </div>
  );
}

const F = ({label,children}) => (
  <div style={{ marginBottom:14 }}>
    <div style={{ fontSize:10, color:"#6b7280", fontWeight:700, letterSpacing:1, marginBottom:6 }}>{label}</div>
    {children}
  </div>
);
const R = ({l,v,c,bold}) => (
  <div style={{ display:"flex", justifyContent:"space-between", fontSize:13,
    color:bold?"#e2e8f0":"#9ca3af", fontWeight:bold?700:400, marginBottom:3 }}>
    <span>{l}</span><span style={{color:c}}>{v}</span>
  </div>
);
const OVL = { position:"fixed", inset:0, background:"rgba(0,0,0,0.85)", zIndex:9999,
  display:"flex", alignItems:"center", justifyContent:"center", backdropFilter:"blur(6px)", padding:16 };
const MOD = { background:"linear-gradient(135deg,#0f0f1a,#1a0a2e)",
  border:"1px solid rgba(139,92,246,0.4)", borderRadius:16, padding:24,
  width:460, maxWidth:"100%", maxHeight:"90vh", overflowY:"auto" };
const INP = { width:"100%", background:"rgba(0,0,0,0.4)", border:"1px solid rgba(139,92,246,0.3)",
  borderRadius:8, padding:"10px 14px", color:"#e2e8f0", fontSize:16,
  outline:"none", boxSizing:"border-box" };
const BTN = { width:"100%", padding:"14px 0", borderRadius:10, border:"none",
  background:"linear-gradient(135deg,#7c3aed,#4c1d95)", color:"#fff", fontWeight:800, fontSize:15 };
const CBTN = { background:"rgba(255,255,255,0.05)", border:"1px solid rgba(255,255,255,0.1)",
  borderRadius:6, width:28, height:28, color:"#9ca3af", cursor:"pointer", fontSize:13 };

