// src/features/friends/FriendsPanel.jsx
// Full-featured friends system UI
// Used inside Profile or as a dedicated /friends page

import { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "../../lib/supabase";
import {
  getFriendships,
  sendFriendRequest,
  acceptFriendRequest,
  rejectFriendRequest,
  removeFriend,
  isOnline,
} from "./friendsService";
import { motion, AnimatePresence } from "framer-motion";

const C = {
  orange: "#FF5500",
  cyan:   "#00D4FF",
  green:  "#22c55e",
  red:    "#ef4444",
  amber:  "#f59e0b",
  bg:     "#070709",
  card:   "rgba(255,255,255,0.028)",
  border: "rgba(255,255,255,0.08)",
};

function timeAgo(ts) {
  const diff = (Date.now() - new Date(ts)) / 1000;
  if (diff < 60)    return "├á l'instant";
  if (diff < 3600)  return `il y a ${Math.floor(diff/60)}min`;
  if (diff < 86400) return `il y a ${Math.floor(diff/3600)}h`;
  return `il y a ${Math.floor(diff/86400)}j`;
}

/* ÔöÇÔöÇ Avatar component ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function UserAvatar({ user, size = 44 }) {
  const online   = isOnline(user?.last_seen);
  const initials = (user?.full_name || user?.username || "?")[0].toUpperCase();

  return (
    <div style={{ position: "relative", flexShrink: 0 }}>
      {user?.avatar_url ? (
        <img
          src={user.avatar_url}
          alt={initials}
          style={{ width: size, height: size, borderRadius: 12, objectFit: "cover", display: "block" }}
        />
      ) : (
        <div style={{
          width: size, height: size, borderRadius: 12,
          background: "linear-gradient(135deg,#FF5500,#FF2200)",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontFamily: "'Barlow Condensed',sans-serif",
          fontWeight: 800, fontSize: size * 0.4, color: "#fff",
        }}>{initials}</div>
      )}
      {/* Online indicator */}
      <div style={{
        position: "absolute", bottom: -2, right: -2,
        width: 11, height: 11, borderRadius: "50%",
        background: online ? C.green : "rgba(255,255,255,0.15)",
        border: `2px solid ${C.bg}`,
        boxShadow: online ? `0 0 8px ${C.green}` : "none",
      }} />
    </div>
  );
}

/* ÔöÇÔöÇ Friend card ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function FriendCard({ item, onRemove, onAccept, onReject, type }) {
  const nav = useNavigate();
  const [loading, setLoading] = useState(false);

  const wrap = async (fn) => {
    setLoading(true);
    await fn();
    setLoading(false);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, x: -20 }}
      style={{
        display:      "flex", alignItems: "center", gap: 12,
        padding:      "12px 14px",
        background:   C.card, border: `1px solid ${C.border}`,
        borderRadius: 14, transition: "border-color 0.2s",
      }}
      onMouseEnter={e => e.currentTarget.style.borderColor = "rgba(255,85,0,0.2)"}
      onMouseLeave={e => e.currentTarget.style.borderColor = C.border}
    >
      <UserAvatar user={item.user} size={44} />

      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{
          fontFamily: "'Barlow Condensed',sans-serif",
          fontWeight: 700, fontSize: 16, color: "#fff",
          whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
        }}>
          {item.user?.full_name || item.user?.username || "Joueur inconnu"}
        </div>
        <div style={{ fontSize: 11, color: "rgba(255,255,255,0.38)", fontFamily: "'Outfit',sans-serif" }}>
          {type === "friends" && (
            <span style={{ color: isOnline(item.user?.last_seen) ? C.green : "rgba(255,255,255,0.3)" }}>
              {isOnline(item.user?.last_seen) ? "ÔùÅ En ligne" : `ÔùÅ Hors ligne`}
            </span>
          )}
          {type === "sent" && "Demande envoy├®e ┬À " + timeAgo(item.created_at)}
          {type === "received" && "Demande re├ºue ┬À " + timeAgo(item.created_at)}
        </div>
      </div>

      {/* Actions */}
      <div style={{ display: "flex", gap: 6, flexShrink: 0 }}>
        {type === "friends" && (
          <>
            <ActionBtn
              label="Profil"
              icon="­ƒæñ"
              onClick={() => nav(`/profile?id=${item.user?.id}`)}
              color={C.cyan}
            />
            <ActionBtn
              label="Supprimer"
              icon="­ƒùæ´©Å"
              onClick={() => wrap(() => onRemove(item.id))}
              color={C.red}
              loading={loading}
              danger
            />
          </>
        )}
        {type === "received" && (
          <>
            <ActionBtn
              label="Accepter"
              icon="Ô£ô"
              onClick={() => wrap(() => onAccept(item.id))}
              color={C.green}
              loading={loading}
            />
            <ActionBtn
              label="Refuser"
              icon="Ô£ò"
              onClick={() => wrap(() => onReject(item.id))}
              color={C.red}
              loading={loading}
              danger
            />
          </>
        )}
        {type === "sent" && (
          <ActionBtn
            label="Annuler"
            icon="Ô£ò"
            onClick={() => wrap(() => onRemove(item.id))}
            color="rgba(255,255,255,0.3)"
            loading={loading}
          />
        )}
      </div>
    </motion.div>
  );
}

function ActionBtn({ label, icon, onClick, color, loading, danger }) {
  return (
    <button
      onClick={onClick}
      disabled={loading}
      title={label}
      style={{
        background:   danger ? `rgba(239,68,68,0.1)` : `${color}12`,
        border:       `1px solid ${color}22`,
        color,
        borderRadius: 9, padding: "7px 10px",
        fontFamily:   "'Rajdhani',sans-serif",
        fontSize:     13, fontWeight: 700, cursor: "pointer",
        transition:   "all 0.18s",
        opacity:      loading ? 0.5 : 1,
        display:      "flex", alignItems: "center", gap: 4,
        minWidth:     36, justifyContent: "center",
      }}
      onMouseEnter={e => { if (!loading) { e.currentTarget.style.background = `${color}20`; e.currentTarget.style.borderColor = `${color}44`; }}}
      onMouseLeave={e => { e.currentTarget.style.background = danger ? `rgba(239,68,68,0.1)` : `${color}12`; e.currentTarget.style.borderColor = `${color}22`; }}
    >
      {loading ? "ÔÇª" : icon}
    </button>
  );
}

/* ÔöÇÔöÇ Search + add friend ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function SearchUser({ onSent }) {
  const [query,   setQuery]   = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null); // {type, text}

  const search = useCallback(async (q) => {
    if (q.length < 2) { setResults([]); return; }
    setLoading(true);
    const { data } = await supabase
      .from("profiles")
      .select("id,username,full_name,avatar_url")
      .or(`username.ilike.%${q}%,full_name.ilike.%${q}%`)
      .limit(8);
    setResults(data || []);
    setLoading(false);
  }, []);

  useEffect(() => {
    const t = setTimeout(() => search(query), 320);
    return () => clearTimeout(t);
  }, [query, search]);

  const handleSend = async (userId) => {
    const { error, existing } = await sendFriendRequest(userId);
    if (existing) {
      setMessage({ type: "warn", text: "Demande d├®j├á envoy├®e ou vous ├¬tes d├®j├á amis." });
    } else if (error) {
      setMessage({ type: "error", text: "Erreur lors de l'envoi." });
    } else {
      setMessage({ type: "ok", text: "Demande envoy├®e !" });
      onSent?.();
    }
    setTimeout(() => setMessage(null), 3000);
  };

  return (
    <div style={{ marginBottom: 24 }}>
      <div style={{ position: "relative" }}>
        <input
          value={query}
          onChange={e => setQuery(e.target.value)}
          placeholder="Rechercher un joueur par nom ou pseudoÔÇª"
          style={{
            width:      "100%", padding: "12px 16px 12px 42px",
            background: "rgba(255,255,255,0.04)",
            border:     "1px solid rgba(255,255,255,0.1)",
            borderRadius: 12, color: "#fff",
            fontFamily: "'Outfit',sans-serif", fontSize: 14,
            outline: "none", boxSizing: "border-box",
            transition: "border-color 0.2s",
          }}
          onFocus={e => e.target.style.borderColor = "rgba(255,85,0,0.35)"}
          onBlur={e => e.target.style.borderColor = "rgba(255,255,255,0.1)"}
        />
        <span style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)", fontSize: 16 }}>
          {loading ? "ÔÅ│" : "­ƒöì"}
        </span>
      </div>

      {/* Results */}
      <AnimatePresence>
        {results.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: -8 }}
