import { Outlet, useNavigate, useLocation, NavLink, Link } from "react-router-dom";
import { useState, useEffect, useRef, useCallback } from "react";
import { supabase } from "../lib/supabase";
import { motion, AnimatePresence } from "framer-motion";
import { NotificationProvider, NotificationBellConnected, useNotify } from "../components/NotificationSystem";
import AnimatedShaderBg from "../components/ui/AnimatedShaderBg";

// ÔöÇÔöÇÔöÇ Design tokens (mirrors global.css) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const C = {
  bg:         "var(--bg)",
  bg1:        "var(--bg-1)",
  border:     "var(--ln-1)",
  borderHov:  "var(--ln-2)",
  accent:     "var(--accent)",
  accentDim:  "rgba(232,80,26,0.08)",
  accentGlow: "rgba(255,79,0,0.28)",
  danger:     "#ef4444",
  green:      "#22c55e",
  amber:      "#fbbf24",
  text:       "var(--t1)",
  textMid:    "var(--t2)",
  textLow:    "var(--t3)",
  fUi:        "var(--f-ui)",
  fDis:       "var(--f-dis)",
};

const ROLE_CFG = {
  super_admin:{ label:"SUPER ADMIN", color:"var(--accent)"  },
  admin:      { label:"ADMIN",       color:"#818cf8"        },
  founder:    { label:"FONDATEUR",   color:"var(--accent)"  },
  fondateur:  { label:"FONDATEUR",   color:"var(--accent)"  },
  designer:   { label:"DESIGNER",    color:C.green          },
  user:       { label:"MEMBRE",      color:C.textMid        },
};

const NAV_LINKS = [
  { to:"/dashboard",   label:"ACCUEIL"    },
  { to:"/tournaments", label:"TOURNOIS"   },
  { to:"/teams",       label:"├ëQUIPES"    },
  { to:"/leaderboard", label:"CLASSEMENT" },
  { to:"/store",       label:"BOUTIQUE"   },
  { to:"/news",        label:"ACTUALIT├ëS" },
];

const BOTTOM_NAV = [
  { to:"/dashboard",   icon:"­ƒÅá", label:"Accueil"  },
  { to:"/tournaments", icon:"­ƒÅå", label:"Tournois" },
  { to:"/chat",        icon:"­ƒÆ¼", label:"Chat"     },
  { to:"/store",       icon:"­ƒøì´©Å", label:"Store"    },
  { to:"/profile",     icon:"­ƒæñ", label:"Profil"   },
];

// ÔöÇÔöÇÔöÇ Logo mark ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function LogoMark({ size = 30 }) {
  return (
    <div style={{
      width: size, height: size, borderRadius: Math.round(size * 0.27),
      background: "var(--accent)", flexShrink: 0,
      display: "flex", alignItems: "center", justifyContent: "center",
    }}>
      <span style={{ fontFamily: C.fDis, fontSize: size * 0.46, fontWeight: 800, color: "#fff", letterSpacing: 0.5 }}>CP</span>
    </div>
  );
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ TOPBAR ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
function Topbar({ profile, balance, equippedItems, chatUnread, unread, urgent, onlineUsers=[], onMenuClick, onLogout }) {
  const location = useLocation();
  const navigate = useNavigate();
  const [search, setSearch] = useState("");
  const [menuOpen, setMenuOpen] = useState(false);
  const [showOnline, setShowOnline] = useState(false);
  const role = profile?.role?.toLowerCase() ?? "user";
  const isAdmin = ["admin","super_admin","founder","fondateur","designer"].includes(role);
  const initials = profile?.full_name?.split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase() || "?";

  return (
    <header style={{
      height: 64, flexShrink: 0, position: "sticky", top: 0, zIndex: 40,
      background: "rgba(10,10,13,0.92)",
      backdropFilter: "blur(20px) saturate(1.6)",
      borderBottom: "1px solid var(--ln-1)",
      display: "flex", alignItems: "center", gap: 0, padding: "0 24px",
    }}>

      {/* Mobile hamburger */}
      <button onClick={onMenuClick}
        className="cp-mobile-menu"
        style={{
          display: "none", width: 36, height: 36, borderRadius: 8,
          background: C.accentDim, border: "1px solid var(--ln-1)",
          cursor: "pointer", alignItems: "center", justifyContent: "center",
          flexShrink: 0, marginRight: 12,
        }}>
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          {[0,1,2].map(i => (
            <span key={i} style={{ display: "block", width: 16, height: 1.5, background: C.accent, borderRadius: 2 }}/>
          ))}
        </div>
      </button>

      {/* LOGO */}
      <Link to="/dashboard" style={{ textDecoration: "none", flexShrink: 0, display: "flex", alignItems: "center", gap: 10, marginRight: 40 }}>
        <LogoMark size={30} />
        <span style={{ fontFamily: C.fDis, fontSize: 18, fontWeight: 800, letterSpacing: 3, color: "var(--t1)" }} className="cp-logo-text">
          CIPHER<span style={{ color: C.accent }}>POOL</span>
        </span>
      </Link>

      {/* NAV LINKS desktop */}
      <nav className="cp-topnav" style={{ display: "flex", alignItems: "center", gap: 2, flex: 1 }}>
        {NAV_LINKS.map(l => {
          const active = l.to === "/dashboard"
            ? location.pathname === "/dashboard"
            : location.pathname.startsWith(l.to);
          return (
            <NavLink key={l.to} to={l.to} style={{
              textDecoration: "none",
              padding: "6px 12px",
              borderRadius: 6,
              fontSize: 11,
              fontWeight: 700,
              letterSpacing: "0.08em",
              fontFamily: C.fUi,
              color: active ? "var(--t1)" : "var(--t3)",
              background: active ? "rgba(255,255,255,0.05)" : "transparent",
              borderBottom: active ? `2px solid var(--accent)` : "2px solid transparent",
              transition: "all .15s",
            }}
              onMouseEnter={e => { if (!active) { e.currentTarget.style.color = "var(--t2)"; e.currentTarget.style.background = "rgba(255,255,255,0.03)"; }}}
              onMouseLeave={e => { if (!active) { e.currentTarget.style.color = "var(--t3)"; e.currentTarget.style.background = "transparent"; }}}
            >{l.label}</NavLink>
          );
        })}

        {/* Admin dropdown */}
        {isAdmin && (
          <div style={{ position: "relative" }}>
            <button
              onClick={() => setMenuOpen(o => !o)}
              style={{
                background: menuOpen ? "rgba(255,255,255,0.05)" : "transparent",
                border: "none", color: menuOpen ? "var(--t1)" : "var(--t3)",
                padding: "6px 12px", borderRadius: 6,
                fontSize: 11, fontWeight: 700, letterSpacing: "0.08em",
                fontFamily: C.fUi,
                cursor: "pointer", display: "flex", alignItems: "center", gap: 6,
                transition: "all .15s",
              }}
              onMouseEnter={e => e.currentTarget.style.color = "var(--t2)"}
              onMouseLeave={e => { if (!menuOpen) e.currentTarget.style.color = "var(--t3)"; }}
            >
              ADMIN <span style={{ fontSize: 8 }}>Ôû╝</span>
            </button>
            <AnimatePresence>
              {menuOpen && (
                <motion.div
                  initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -8 }}
                  style={{
                    position: "absolute", top: "calc(100% + 8px)", left: 0, zIndex: 99,
                    background: "var(--bg-1)", backdropFilter: "blur(20px)",
                    border: "1px solid var(--ln-1)", borderRadius: "var(--r2)",
                    padding: 6, minWidth: 200,
                    boxShadow: "0 16px 40px rgba(0,0,0,0.5)",
                  }}
                >
                  {[
                    { to:"/designer",         label:"Designer Studio",       roles:["designer","admin","super_admin"]             },
                    { to:"/admin",            label:"Administration",         roles:["admin","super_admin"]                        },
                    { to:"/admin/news",       label:"Actualit├®s Admin",       roles:["admin","founder","fondateur","super_admin"]  },
                    { to:"/admin/results",    label:"R├®sultats",              roles:["admin","founder","fondateur","super_admin"]  },
                    { to:"/admin-store",      label:"Boutique Admin",         roles:["admin","super_admin"]                        },
                    { to:"/founder",          label:"Panel Fondateur",        roles:["founder","fondateur","super_admin"]          },
                    { to:"/create-tournament",label:"Cr├®er Tournoi",          roles:["founder","fondateur","super_admin"]          },
                    { to:"/super-admin",      label:"Super Admin",            roles:["super_admin"]                                },
                  ].filter(l => l.roles.includes(role)).map(l => (
                    <NavLink key={l.to} to={l.to}
                      onClick={() => setMenuOpen(false)}
                      style={{
                        display: "block", padding: "9px 14px", borderRadius: 7,
                        textDecoration: "none", fontSize: 13,
                        color: "var(--t2)", fontFamily: C.fUi,
                        transition: "all .15s",
                      }}
                      onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,255,255,0.05)"; e.currentTarget.style.color = "var(--t1)"; }}
                      onMouseLeave={e => { e.currentTarget.style.background = "transparent"; e.currentTarget.style.color = "var(--t2)"; }}
                    >{l.label}</NavLink>
                  ))}
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )}
      </nav>

      {/* RIGHT SIDE */}
      <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>

        {/* Search */}
        <div style={{ position: "relative" }} className="cp-search">
          <span style={{ position: "absolute", left: 10, top: "50%", transform: "translateY(-50%)", fontSize: 12, opacity: .35 }}>­ƒöì</span>
          <input
            value={search} onChange={e => setSearch(e.target.value)}
            placeholder="Rechercher..."
            style={{
              width: 170, padding: "7px 12px 7px 30px", borderRadius: "var(--r1)",
              background: "rgba(255,255,255,0.04)", border: "1px solid var(--ln-1)",
              color: "var(--t1)", fontFamily: C.fUi, fontSize: 12,
              outline: "none", boxSizing: "border-box", transition: "all .2s",
            }}
            onFocus={e => { e.target.style.borderColor = "var(--accent)"; e.target.style.width = "210px"; }}
            onBlur={e => { e.target.style.borderColor = "var(--ln-1)"; e.target.style.width = "170px"; }}
          />
        </div>

        {/* Wallet */}
        <Link to="/wallet" className="cp-wallet-btn" style={{
          display: "flex", alignItems: "center", gap: 7, padding: "7px 12px",
          borderRadius: "var(--r1)", background: "var(--sf-1)",
          border: "1px solid var(--ln-1)", textDecoration: "none",
          transition: "all .2s",
        }}
          onMouseEnter={e => { e.currentTarget.style.borderColor = "var(--ln-2)"; e.currentTarget.style.background = "var(--sf-2)"; }}
          onMouseLeave={e => { e.currentTarget.style.borderColor = "var(--ln-1)"; e.currentTarget.style.background = "var(--sf-1)"; }}>
          <span style={{ fontSize: 13 }}>­ƒÆÄ</span>
          <span style={{ fontFamily: C.fUi, fontWeight: 700, fontSize: 14, color: "var(--t1)" }}>
            {balance.toLocaleString("fr-FR")}
          </span>
          <span style={{ fontFamily: "monospace", fontSize: 9, color: "var(--t3)", letterSpacing: 1 }}>pts</span>
        </Link>

        {/* Support */}
        <Link to="/support" style={{
          width: 34, height: 34, borderRadius: "var(--r1)", background: "var(--sf-1)",
          border: "1px solid var(--ln-1)", display: "flex", alignItems: "center", justifyContent: "center",
          textDecoration: "none", fontSize: 15, transition: "all .2s",
        }}
          onMouseEnter={e => { e.currentTarget.style.background = "var(--sf-2)"; e.currentTarget.style.borderColor = "var(--ln-2)"; }}
          onMouseLeave={e => { e.currentTarget.style.background = "var(--sf-1)"; e.currentTarget.style.borderColor = "var(--ln-1)"; }}>­ƒÄº</Link>

        {/* Notification Bell */}
        <NotificationBellConnected />

        {/* Chat */}
        <div style={{ position: "relative" }}>
          <Link to="/chat" style={{
            width: 34, height: 34, borderRadius: "var(--r1)", background: "var(--sf-1)",
            border: "1px solid var(--ln-1)", display: "flex", alignItems: "center", justifyContent: "center",
            textDecoration: "none", fontSize: 15, transition: "all .2s",
          }}
            onMouseEnter={e => { e.currentTarget.style.background = "var(--sf-2)"; e.currentTarget.style.borderColor = "var(--ln-2)"; }}
            onMouseLeave={e => { e.currentTarget.style.background = "var(--sf-1)"; e.currentTarget.style.borderColor = "var(--ln-1)"; }}>­ƒÆ¼</Link>
          {chatUnread > 0 && (
            <span style={{
              position: "absolute", top: -4, right: -4, minWidth: 16, height: 16, borderRadius: 6,
              background: C.accent, display: "flex", alignItems: "center", justifyContent: "center",
              fontFamily: "monospace", fontSize: 8, fontWeight: 700, color: "#fff", padding: "0 3px",
            }}>
              {chatUnread > 99 ? "99+" : chatUnread}
            </span>
          )}
        </div>

        {/* Online indicator */}
        <div style={{ position: "relative" }}>
          <button
            onClick={() => setShowOnline(o => !o)}
            style={{
