function NewsPopup({ profile }) {
  const [article, setArticle] = useState(null);

  const checkNews = useCallback(async () => {
    try {
      const { data: latest } = await supabase.from("news")
        .select("id,title,excerpt,cover_url,category,published_at")
        .order("published_at", { ascending: false })
        .limit(1).maybeSingle();
      if (!latest) return;
      const seen = JSON.parse(localStorage.getItem("cp_seen_news") || "[]");
      if (!seen.includes(latest.id)) setArticle(latest);
    } catch (error) {
      console.error("checkNews failed", error);
    }
  }, []);

  useEffect(() => {
    if (!profile?.id) return;
    checkNews();
    const ch = supabase.channel("news_popup")
      .on("postgres_changes", { event:"INSERT", schema:"public", table:"news" }, () => checkNews())
      .subscribe();
    return () => supabase.removeChannel(ch);
  }, [profile?.id, checkNews]);

  const dismiss = () => {
    if (!article) return;
    const seen = JSON.parse(localStorage.getItem("cp_seen_news") || "[]");
    if (!seen.includes(article.id)) seen.push(article.id);
    localStorage.setItem("cp_seen_news", JSON.stringify(seen));
    setArticle(null);
  };

  if (!article) return null;

  const CAT_COLORS = { general:"#818cf8", tournament:C.amber, update:"var(--accent)", player:"#10b981", team:"#a78bfa" };
  const catColor = CAT_COLORS[article.category] || "#818cf8";

  return (
    <AnimatePresence>
      <motion.div key="news-overlay"
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        style={{
          position: "fixed", inset: 0, zIndex: 999, background: "rgba(0,0,0,0.8)", backdropFilter: "blur(12px)",
          display: "flex", alignItems: "center", justifyContent: "center", padding: 20,
        }}>
        <motion.div
          initial={{ scale: 0.88, opacity: 0, y: 24 }} animate={{ scale: 1, opacity: 1, y: 0 }} exit={{ scale: 0.88, opacity: 0 }}
          transition={{ type: "spring", stiffness: 280, damping: 26 }}
          style={{
            background: "var(--bg-1)", border: "1px solid var(--ln-2)",
            borderRadius: "var(--r3)", width: "100%", maxWidth: 520, overflow: "hidden",
            boxShadow: "0 30px 80px rgba(0,0,0,0.6)",
          }}>
          {article.cover_url && (
            <div style={{ position: "relative", height: 180, overflow: "hidden" }}>
              <img src={article.cover_url} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }}/>
              <div style={{ position: "absolute", inset: 0, background: "linear-gradient(to bottom, transparent 50%, var(--bg-1))" }}/>
            </div>
          )}
          <div style={{ padding: article.cover_url ? "0 24px" : "24px 24px 0" }}>
            <div style={{
              display: "inline-flex", alignItems: "center", gap: 6,
              background: `${catColor}20`, border: `1px solid ${catColor}50`,
              borderRadius: 20, padding: "4px 12px", marginBottom: 12,
            }}>
              <span style={{ width: 6, height: 6, borderRadius: "50%", background: catColor, display: "block" }}/>
              <span style={{ fontFamily: "monospace", fontSize: 9, letterSpacing: 2, color: catColor, fontWeight: 700, textTransform: "uppercase" }}>­ƒôó NOUVELLE ANNONCE</span>
            </div>
            <h2 style={{ fontFamily: C.fDis, fontSize: 26, letterSpacing: 2, color: "var(--t1)", margin: "0 0 10px", lineHeight: 1.2 }}>{article.title}</h2>
            {article.excerpt && (
              <p style={{ fontFamily: C.fUi, fontSize: 14, color: "var(--t2)", lineHeight: 1.6, margin: "0 0 24px" }}>{article.excerpt}</p>
            )}
          </div>
          <div style={{ padding: "0 24px 24px" }}>
            <button onClick={dismiss} style={{
              width: "100%", padding: 14, background: "var(--accent)",
              border: "none", borderRadius: "var(--r2)",
              fontFamily: C.fDis, fontSize: 18, letterSpacing: 3, color: "#fff", cursor: "pointer",
              transition: "all .2s",
            }}
              onMouseEnter={e => e.currentTarget.style.opacity = "0.85"}
              onMouseLeave={e => e.currentTarget.style.opacity = "1"}>
              Ô£ô J'AI LU ÔÇö OK
