        <p style={{ fontFamily: C.fUi, fontSize: 12, color: "var(--t3)", margin: "2px 0 0" }}>
          Votre compte est en attente de validation. Certaines actions sont temporairement d├®sactiv├®es.
        </p>
      </div>
      <div style={{ display: "flex", gap: 8, flexShrink: 0 }}>
        <button onClick={() => navigate("/profile")}
          style={{
            padding: "7px 16px", borderRadius: "var(--r1)",
            background: "rgba(251,191,36,0.12)", border: "1px solid rgba(251,191,36,0.4)",
            color: C.amber, fontFamily: C.fUi, fontWeight: 700, fontSize: 12, cursor: "pointer", transition: "all .2s",
          }}
          onMouseEnter={e => e.currentTarget.style.background = "rgba(251,191,36,0.22)"}
          onMouseLeave={e => e.currentTarget.style.background = "rgba(251,191,36,0.12)"}>
          ­ƒôÄ Mon profil
        </button>
        <button onClick={() => setDismissed(true)}
          style={{
            width: 28, height: 28, borderRadius: 6,
            background: "rgba(255,255,255,0.05)", border: "1px solid var(--ln-1)",
