}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ NOTIFY INJECTOR ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
function NotifyInjector({ profile, setProfile, balance, setBalance, equippedItems, refreshProfile }) {
  const notify = useNotify();
  return <Outlet context={{ profile, setProfile, balance, setBalance, equippedItems, refreshProfile, notify }}/>;
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ MAIN LAYOUT ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
export default function MainLayout() {
  const navigate  = useNavigate();
  const location  = useLocation();
  const [profile,       setProfile]       = useState(null);
  const [loading,       setLoading]       = useState(true);
  const [balance,       setBalance]       = useState(0);
  const [equippedItems, setEquippedItems] = useState({});
  const [unread,        setUnread]        = useState(0);
  const [urgent,        setUrgent]        = useState(0);
  const [chatUnread,    setChatUnread]    = useState(0);
  const [mobileOpen,    setMobileOpen]    = useState(false);
  const [onlineUsers,   setOnlineUsers]   = useState([]);
  const pRef = useRef(null);

  useEffect(() => { loadProfile(); }, []);

  useEffect(() => {
    if (!profile) return;
    pRef.current = profile;
    fetchBalance(); fetchEquipped(); fetchUnread(); fetchUrgent(); fetchChatUnread();

    const ch = supabase.channel("ml_v5")
      .on("postgres_changes",{event:"*",schema:"public",table:"wallets",filter:`user_id=eq.${profile.id}`},p=>{if(p.new?.balance!==undefined)setBalance(p.new.balance);})
      .on("postgres_changes",{event:"*",schema:"public",table:"user_items",filter:`user_id=eq.${profile.id}`},()=>fetchEquipped())
      .on("postgres_changes",{event:"UPDATE",schema:"public",table:"profiles",filter:`id=eq.${profile.id}`},p=>{if(p.new)setProfile(p.new);})
      .on("postgres_changes",{event:"INSERT",schema:"public",table:"admin_messages"},fetchUnread)
      .on("postgres_changes",{event:"INSERT",schema:"public",table:"chat_messages"},()=>{if(location.pathname!=="/chat")fetchChatUnread();})
      .subscribe();

    const presenceCh = supabase.channel("global-presence", {
      config: { presence: { key: profile.id } }
    });
    presenceCh
      .on("presence", { event: "sync" }, () => {
        const state = presenceCh.presenceState();
        const users = Object.values(state).map(arr=>arr[0]).filter(Boolean);
        setOnlineUsers(users);
      })
      .subscribe(async (status) => {
        if (status === "SUBSCRIBED") {
          await presenceCh.track({
            user_id:    profile.id,
            full_name:  profile.full_name,
            avatar_url: profile.avatar_url || null,
            role:       profile.role || "user",
            online_at:  new Date().toISOString(),
          });
        }
      });

    return () => {
      supabase.removeChannel(ch);
      supabase.removeChannel(presenceCh);
    };
  }, [profile?.id]);

  useEffect(() => {
    if (location.pathname === "/chat") {
      localStorage.setItem("chat_last_seen", new Date().toISOString());
      setChatUnread(0);
    }
    setMobileOpen(false);
  }, [location.pathname]);

  const fetchBalance    = async () => { try { const{data}=await supabase.from("wallets").select("balance").eq("user_id",pRef.current?.id).maybeSingle(); setBalance(data?.balance??0); } catch(_) {} };
  const fetchEquipped   = async () => { try { const{data}=await supabase.from("user_items").select("item_id,equipped,store_items(id,name,type,rarity,image_url)").eq("user_id",pRef.current?.id).eq("equipped",true); if(data){const m={};data.forEach(u=>{if(u.store_items)m[u.store_items.type]=u.store_items;});setEquippedItems(m);} } catch(_) {} };
  const fetchUnread     = async () => { try { const p=pRef.current; if(!p)return; const{count}=await supabase.from("admin_messages").select("*",{count:"exact",head:true}).or(`user_id.eq.${p.id},is_global.eq.true`).eq("read",false); setUnread(count||0); } catch(_) {} };
  const fetchUrgent     = async () => { try { const{count}=await supabase.from("support_tickets").select("*",{count:"exact",head:true}).in("priority",["urgent","critique"]).eq("status","open"); setUrgent(count||0); } catch(_) {} };
  const fetchChatUnread = async () => { try { const p=pRef.current; if(!p)return; const last=localStorage.getItem("chat_last_seen")||"2020-01-01"; const{count}=await supabase.from("chat_messages").select("*",{count:"exact",head:true}).gt("created_at",last).neq("sender_id",p.id); setChatUnread(count||0); } catch(_) {} };
  const refreshProfile  = async () => { const p=pRef.current; if(!p?.id)return; const{data}=await supabase.from("profiles").select("*").eq("id",p.id).maybeSingle(); if(data)setProfile(data); await fetchBalance(); await fetchEquipped(); };

  const loadProfile = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) { navigate("/"); return; }

    const { data, error } = await supabase
      .from("profiles")
      .select("*")
      .eq("id", user.id)
      .maybeSingle();

    if (error || !data) {
      await supabase.auth.signOut();
      navigate("/");
      return;
    }

    setProfile(data);
    setLoading(false);
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    navigate("/");
  };

  if (loading) return (
    <div style={{ minHeight: "100vh", background: "var(--bg)", display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ textAlign: "center" }}>
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
          style={{
            width: 40, height: 40, border: "2px solid var(--ln-1)", borderTopColor: "var(--accent)",
            borderRadius: "50%", margin: "0 auto 20px",
          }}
        />
        <p style={{ fontFamily: "monospace", fontSize: 10, letterSpacing: 5, color: "var(--accent)" }}>CHARGEMENT</p>
      </div>
    </div>
  );

  return (
    <NotificationProvider profile={profile}>
      <div style={{ minHeight: "100vh", background: "var(--bg)", color: "var(--t1)", display: "flex", flexDirection: "column", position: "relative" }}>

        {/* Global animated shader background ÔÇö fixed behind everything */}
        <div style={{ position: "fixed", inset: 0, zIndex: 0, pointerEvents: "none" }}>
          <AnimatedShaderBg opacity={0.28} />
        </div>

        <div style={{ position: "relative", zIndex: 41 }}>
          <Topbar
            profile={profile} balance={balance} equippedItems={equippedItems}
            chatUnread={chatUnread} unread={unread} urgent={urgent}
            onlineUsers={onlineUsers}
            onMenuClick={() => setMobileOpen(o => !o)}
            onLogout={handleLogout}
          />
        </div>

        <AnimatePresence>
          {mobileOpen && (
            <>
              <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                onClick={() => setMobileOpen(false)}
                style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", backdropFilter: "blur(8px)", zIndex: 48 }}/>
              <motion.div initial={{ x: -280 }} animate={{ x: 0 }} exit={{ x: -280 }}
                transition={{ type: "spring", stiffness: 320, damping: 32 }}
                style={{
                  position: "fixed", top: 0, left: 0, zIndex: 49, width: 280, height: "100vh", overflowY: "auto",
                  background: "var(--bg-1)", backdropFilter: "blur(28px)",
                  borderRight: "1px solid var(--ln-1)",
                }}>
                <MobileDrawer profile={profile} onClose={() => setMobileOpen(false)} onLogout={handleLogout}/>
              </motion.div>
            </>
          )}
        </AnimatePresence>

        <KYCBanner profile={profile} />
        <NewsPopup profile={profile} />

        <main style={{
          flex: 1, overflowY: "auto", minWidth: 0, position: "relative", zIndex: 1, width: "100%",
          paddingBottom: "var(--bottom-nav-h,0px)",
        }}>
          <BackButton/>
          <NotifyInjector profile={profile} setProfile={setProfile} balance={balance}
            setBalance={setBalance} equippedItems={equippedItems} refreshProfile={refreshProfile}/>
        </main>

        <div className="cp-bottom-nav">
          <BottomNav chatUnread={chatUnread}/>
        </div>

        <style>{`
          *,*::before,*::after{box-sizing:border-box;}
          html{-webkit-text-size-adjust:100%;}
          body{margin:0;overflow-x:hidden;}
          img{max-width:100%;height:auto;}
          button{-webkit-tap-highlight-color:transparent;touch-action:manipulation;}
          ::-webkit-scrollbar{width:4px;}
          ::-webkit-scrollbar-track{background:transparent;}
          ::-webkit-scrollbar-thumb{background:rgba(232,80,26,0.25);border-radius:4px;}
          .cp-bottom-nav{display:none;}
          main > *{max-width:100%;}
          @media(max-width:767px){ main{padding-left:0;padding-right:0;} }
          @media(max-width:1023px){
            .cp-bottom-nav{display:block;}
            :root{--bottom-nav-h:64px;}
          }
          @media(min-width:1024px){
            :root{--bottom-nav-h:0px;}
          }
        `}</style>
      </div>
    </NotificationProvider>
  );
}

// Sidebar.jsx ÔÇö CipherPool ┬À Role-based navigation v3
// Premium dark sidebar ┬À lucide icons ┬À design-system classes
import { NavLink, Link, useNavigate } from "react-router-dom";
import { supabase } from "../lib/supabase";
import { motion } from "framer-motion";
import {
  LayoutDashboard, Trophy, BarChart2, Users, Newspaper,
  MessageSquare, ShoppingBag, Swords, Medal, Gift,
  Wallet, User, LifeBuoy, LogOut,
  Shield, Plus, ClipboardList, TrendingUp,
  Palette, Package, Crown, Coins,
  Settings, TicketCheck, Star,
} from "lucide-react";
import "../components/admin/admin.css";

/* ÔöÇÔöÇ Role dot ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
const ROLE_META = {
  super_admin: { label: "Super Admin", cls: "adm-sidebar-role-badge--super_admin" },
  admin:       { label: "Admin",       cls: "adm-sidebar-role-badge--admin"       },
  founder:     { label: "Founder",     cls: "adm-sidebar-role-badge--founder"     },
  fondateur:   { label: "Fondateur",   cls: "adm-sidebar-role-badge--founder"     },
  designer:    { label: "Designer",    cls: "adm-sidebar-role-badge--designer"    },
  user:        { label: "Player",      cls: "adm-sidebar-role-badge--user"        },
};

/* ÔöÇÔöÇ Nav link helper ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function SideLink({ to, icon: Icon, label, badge, accentKey }) {
  const activeMap = {
    violet: "adm-nav-link--active",
    orange: "adm-nav-link--active-orange",
    gold:   "adm-nav-link--active-gold",
  };

  return (
    <NavLink
      to={to}
      end={to === "/dashboard"}
      className={({ isActive }) =>
        `adm-nav-link${isActive ? " " + (activeMap[accentKey] || "adm-nav-link--active") : ""}`
      }
    >
      {Icon && (
        <span className="adm-nav-link-icon">
          <Icon size={15} />
        </span>
      )}
      {label}
      {badge > 0 && (
        <span className={`adm-nav-badge${badge > 5 ? " adm-nav-badge--danger" : ""}`}>
          {badge > 99 ? "99+" : badge}
        </span>
      )}
    </NavLink>
  );
}

function NavSection({ label }) {
  return (
    <div className="adm-nav-section">
      <p className="adm-nav-label">{label}</p>
    </div>
  );
}

/* ÔöÇÔöÇ Main Sidebar ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
export default function Sidebar({ profile }) {
  const navigate = useNavigate();
  const role      = (profile?.role || "user").toLowerCase();
  const meta      = ROLE_META[role] || ROLE_META.user;

  const isSuperAdmin = role === "super_admin";
  const isAdmin      = role === "admin" || isSuperAdmin;
  const isFounder    = role === "founder" || role === "fondateur" || isSuperAdmin;
  const isDesigner   = role === "designer" || isAdmin;

  const handleLogout = async () => {
    await supabase.auth.signOut();
    navigate("/");
  };

  return (
    <aside className="adm-sidebar">
      {/* Logo */}
      <Link to="/" className="adm-sidebar-logo" style={{ textDecoration: "none" }}>
        <div className="adm-sidebar-logo-mark">CP</div>
        <div>
          <div className="adm-sidebar-logo-text">
            CIPHER<span style={{ color: "var(--accent)" }}>POOL</span>
          </div>
          <div className={`adm-sidebar-role-badge ${meta.cls}`}>
            {meta.label}
          </div>
        </div>
      </Link>

      {/* Navigation */}
      <nav className="adm-sidebar-nav">

        {/* ÔöÇÔöÇ Main ÔöÇÔöÇ */}
        <NavSection label="Main" />
        <SideLink to="/dashboard"     icon={LayoutDashboard} label="Dashboard"     />
        <SideLink to="/tournaments"   icon={Trophy}          label="Tournaments"   />
        <SideLink to="/leaderboard"   icon={BarChart2}       label="Leaderboard"   />
        <SideLink to="/teams"         icon={Users}           label="Teams"         />
        <SideLink to="/news"          icon={Newspaper}       label="News"          />
        <SideLink to="/chat"          icon={MessageSquare}   label="Global Chat"   />
        <SideLink to="/store"         icon={ShoppingBag}     label="Store"         />
        <SideLink to="/stats"         icon={Swords}          label="My Stats"      />
        <SideLink to="/achievements"  icon={Medal}           label="Achievements"  />
        <SideLink to="/daily-rewards" icon={Gift}            label="Daily Rewards" />
        <SideLink to="/wallet"        icon={Wallet}          label="Wallet"        />
        <SideLink to="/profile"       icon={User}            label="My Profile"    />
        <SideLink to="/support"       icon={LifeBuoy}        label="Support"       />

        {/* ÔöÇÔöÇ Founder ÔöÇÔöÇ */}
        {isFounder && (
          <>
            <NavSection label="Founder" />
            <SideLink to="/founder"           icon={Crown}         label="Founder Panel"      accentKey="gold" />
            <SideLink to="/create-tournament" icon={Plus}          label="Create Tournament"  accentKey="gold" />
            <SideLink to="/founder/requests"  icon={ClipboardList} label="Requests"           accentKey="gold" />
            <SideLink to="/founder/results"   icon={TrendingUp}    label="Results"            accentKey="gold" />
          </>
        )}

        {/* ÔöÇÔöÇ Designer only (not admin) ÔöÇÔöÇ */}
        {isDesigner && !isAdmin && (
          <>
            <NavSection label="Studio" />
            <SideLink to="/designer" icon={Palette}     label="Designer Studio" accentKey="violet" />
            <SideLink to="/store"    icon={ShoppingBag} label="Store"           accentKey="violet" />
          </>
        )}

        {/* ÔöÇÔöÇ Admin ÔöÇÔöÇ */}
        {isAdmin && (
          <>
            <NavSection label="Administration" />
            <SideLink to="/admin"         icon={Shield}       label="Control Center"  accentKey="orange" />
            <SideLink to="/admin/support" icon={TicketCheck}  label="Support Tickets" accentKey="orange" />
            <SideLink to="/admin/results" icon={TrendingUp}   label="Results"         accentKey="orange" />
            <SideLink to="/admin/news"    icon={Newspaper}    label="News Manager"    accentKey="orange" />
            <SideLink to="/admin-store"   icon={Package}      label="Store Admin"     accentKey="orange" />
          </>
        )}

        {/* ÔöÇÔöÇ Super Admin ÔöÇÔöÇ */}
        {isSuperAdmin && (
          <>
            <NavSection label="Super Admin" />
            <SideLink to="/super-admin"       icon={Crown}   label="Command Center"  accentKey="orange" />
            <SideLink to="/super-admin/grant" icon={Coins}   label="Coin Management" accentKey="orange" />
            <SideLink to="/designer"          icon={Palette} label="Designer Studio" accentKey="orange" />
          </>
        )}

      </nav>

      {/* User / Logout */}
      <div className="adm-sidebar-footer">
        {profile && (
          <div style={{
            display: "flex", alignItems: "center", gap: 10,
            padding: "8px 12px", marginBottom: 6,
          }}>
            <div style={{
              width: 28, height: 28, borderRadius: 8,
              background: "var(--accent-2)", border: "1px solid var(--accent-3)",
              display: "flex", alignItems: "center", justifyContent: "center",
              fontFamily: "var(--f-dis)", fontSize: 11, fontWeight: 700, color: "var(--accent)",
              flexShrink: 0, textTransform: "uppercase",
            }}>
              {(profile.full_name || "?").charAt(0)}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <p style={{ fontFamily: "var(--f-ui)", fontSize: 12, fontWeight: 600, color: "var(--t1)", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", margin: 0 }}>
                {profile.full_name || "Unknown"}
              </p>
              <p style={{ fontFamily: "var(--f-ui)", fontSize: 10, color: "var(--t4)", margin: 0 }}>
                {profile.email || ""}
              </p>
            </div>
          </div>
        )}
        <button className="adm-sidebar-logout" onClick={handleLogout}>
          <LogOut size={14} />
          Sign Out
        </button>
      </div>
    </aside>
  );
}

