/* ÔöÇÔöÇ Stat card ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function StatCard({ icon: Icon, iconCls, cardCls, label, value, sub, delay = 0 }) {
  return (
    <motion.div
      className={`adm-stat-card adm-stat-card--${cardCls}`}
      initial={{ opacity: 0, y: 16 }}
