/* ÔöÇÔöÇ Page ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
export default function AdminDashboard() {
  const navigate = useNavigate();
  const [profile, setProfile] = useState(null);
  const [stats,   setStats]   = useState({
    totalUsers: 0, pendingUsers: 0,
    totalTickets: 0, urgentTickets: 0,
    totalTournaments: 0, openTournaments: 0,
    totalReports: 0,
  });
  const [recentTickets, setRecentTickets]   = useState([]);
  const [recentUsers,   setRecentUsers]     = useState([]);
  const [recentReports, setRecentReports]   = useState([]);
  const [loading,       setLoading]         = useState(true);
  const [msg,           setMsg]             = useState(null);

  const { isSuperAdmin } = usePermissions(profile);

  /* ÔöÇÔöÇ auth + data ÔöÇÔöÇ */
  useEffect(() => {
    (async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { navigate("/login"); return; }

      const { data, error } = await supabase
        .from("profiles").select("*").eq("id", user.id).maybeSingle();

      const role = data?.role?.toLowerCase() ?? "";
      if (error || !data || (role !== "admin" && role !== "super_admin")) {
        navigate("/dashboard");
        return;
      }

      if (data.role) data.role = role; // normalize in-place
      setProfile(data);
      await Promise.all([fetchStats(), fetchRecentData()]);
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const fetchStats = async () => {
    const [
      { count: totalUsers },
      { count: pendingUsers },
      { count: totalTickets },
      { count: urgentTickets },
      { count: totalTournaments },
      { count: openTournaments },
      { count: totalReports },
    ] = await Promise.all([
      supabase.from("profiles").select("*", { count: "exact", head: true }),
      supabase.from("profiles").select("*", { count: "exact", head: true }).eq("verification_status", "pending"),
      supabase.from("support_tickets").select("*", { count: "exact", head: true }),
      supabase.from("support_tickets").select("*", { count: "exact", head: true }).in("priority", ["urgent", "critique"]).eq("status", "open"),
      supabase.from("tournaments").select("*", { count: "exact", head: true }),
      supabase.from("tournaments").select("*", { count: "exact", head: true }).eq("status", "open"),
      supabase.from("reports").select("*", { count: "exact", head: true }).eq("status", "pending"),
    ]);

    setStats({
      totalUsers:       totalUsers       || 0,
      pendingUsers:     pendingUsers     || 0,
      totalTickets:     totalTickets     || 0,
      urgentTickets:    urgentTickets    || 0,
      totalTournaments: totalTournaments || 0,
      openTournaments:  openTournaments  || 0,
      totalReports:     totalReports     || 0,
    });
  };

  const fetchRecentData = async () => {
    const [
      { data: tickets },
      { data: users },
      { data: reports },
    ] = await Promise.all([
      supabase.from("support_tickets")
        .select("*, user:profiles!support_tickets_user_id_fkey(full_name)")
        .order("created_at", { ascending: false }).limit(5),
      supabase.from("profiles")
        .select("id, full_name, verification_status, created_at, role")
        .order("created_at", { ascending: false }).limit(6),
      supabase.from("reports")
        .select("*, reporter:profiles!reports_reporter_id_fkey(full_name), reported:profiles!reports_reported_id_fkey(full_name)")
        .eq("status", "pending").order("created_at", { ascending: false }).limit(5),
    ]);

    setRecentTickets(tickets || []);
    setRecentUsers(users || []);
    setRecentReports(reports || []);
    setLoading(false);
  };

  const verifyUser = async (userId) => {
    try {
      const { error } = await supabase.rpc("verify_user", {
        target_user: userId,
        verifier_id: profile.id,
      });
      if (error) throw error;
      await supabase.from("admin_logs").insert([{
        user_id: profile.id,
        action: "verify_user",
        details: { target_user: userId },
      }]);
      setMsg({ type: "success", text: "User verified successfully." });
      fetchRecentData();
      fetchStats();
    } catch (err) {
      setMsg({ type: "error", text: "Verification failed: " + err.message });
    }
    setTimeout(() => setMsg(null), 3500);
  };

  /* ÔöÇÔöÇ loading ÔöÇÔöÇ */
  if (loading) {
    return (
      <div className="adm-page">
        <div className="adm-loading">
          <div className="adm-spinner" />
        </div>
      </div>
    );
  }

  const pendingVerifUsers = recentUsers.filter(u => u.verification_status === "pending");

  return (
    <div className="adm-page">
      <div className="adm-content">

        {/* ÔöÇÔöÇ Page header ÔöÇÔöÇ */}
        <div className="adm-page-head">
          <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", gap: 12 }}>
            <div>
              <h1 className="adm-page-title">
                {isSuperAdmin ? "Super Admin" : "Admin"} Control Center
              </h1>
              <p className="adm-page-sub">
                Welcome back, {profile?.full_name} ÔÇö platform overview &amp; quick actions
              </p>
            </div>
            {isSuperAdmin && (
              <Link to="/super-admin" className="adm-btn adm-btn--primary">
                <Crown size={13} />
                Command Center
              </Link>
            )}
          </div>
        </div>

        {/* ÔöÇÔöÇ Alert ÔöÇÔöÇ */}
        {msg && (
          <div className={`adm-alert adm-alert--${msg.type}`}>
            {msg.type === "success" ? <CheckCircle2 size={14} /> : <XCircle size={14} />}
            {msg.text}
          </div>
        )}

        {/* ÔöÇÔöÇ Stats ÔöÇÔöÇ */}
        <div className="adm-section">
          <div className="adm-stat-grid">
            <StatCard icon={Users}       iconCls="violet" cardCls="violet" label="Total Players"       value={stats.totalUsers}       delay={0.00} />
            <StatCard icon={ClipboardCheck} iconCls="gold" cardCls="gold"  label="Pending Verification" value={stats.pendingUsers}     delay={0.05} sub={stats.pendingUsers > 0 ? "Needs review" : "All clear"} />
            <StatCard icon={TicketCheck} iconCls="cyan"   cardCls="cyan"   label="Support Tickets"      value={stats.totalTickets}     delay={0.10} />
            <StatCard icon={AlertTriangle} iconCls="orange" cardCls="orange" label="Urgent Tickets"     value={stats.urgentTickets}    delay={0.15} sub={stats.urgentTickets > 0 ? "Requires action" : "None"} />
            <StatCard icon={Trophy}      iconCls="green"  cardCls="green"  label="Tournaments"          value={stats.totalTournaments} delay={0.20} />
            <StatCard icon={Circle}      iconCls="green"  cardCls="green"  label="Open Tournaments"     value={stats.openTournaments}  delay={0.25} />
            <StatCard icon={ShieldAlert} iconCls="red"    cardCls="red"    label="Pending Reports"      value={stats.totalReports}     delay={0.30} sub={stats.totalReports > 0 ? "Awaiting review" : "None"} />
          </div>
        </div>

        {/* ÔöÇÔöÇ Quick Actions ÔöÇÔöÇ */}
        <div className="adm-section">
          <div className="adm-section-head">
            <p className="adm-section-title adm-section-title--orange">Quick Actions</p>
          </div>
          <div className="adm-quick-grid">
            <QuickCard to="/admin/support" icon={TicketCheck}    iconCls="orange" cardCls="orange" label="Support Tickets"  sub={`${stats.urgentTickets} urgent open`} />
            <QuickCard to="/admin/news"    icon={ExternalLink}   iconCls="violet" cardCls=""       label="News Manager"    sub="Publish &amp; manage articles" />
            <QuickCard to="/tournaments"   icon={Trophy}         iconCls="green"  cardCls=""       label="Tournaments"     sub={`${stats.openTournaments} open now`} />
            {isSuperAdmin && (
              <>
                <QuickCard to="/super-admin/grant" icon={Coins}  iconCls="gold"   cardCls="gold"  label="Coin Management" sub="Grant coins to players" />
                <QuickCard to="/super-admin"       icon={Crown}  iconCls="orange" cardCls="orange" label="Command Center"  sub="Full platform control" />
              </>
            )}
          </div>
        </div>

        {/* ÔöÇÔöÇ Two column ÔöÇÔöÇ */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 28 }}>

          {/* Pending verifications */}
          <div className="adm-card">
            <div className="adm-card-head">
              <p className="adm-section-title adm-section-title--gold">Pending Verifications</p>
              {pendingVerifUsers.length > 0 && (
                <span className="adm-badge adm-badge--gold">
                  {pendingVerifUsers.length}
                </span>
              )}
            </div>
            <div className="adm-card-body">
              {pendingVerifUsers.length === 0 ? (
                <div className="adm-empty">
                  <div className="adm-empty-icon"><CheckCircle2 size={20} /></div>
                  <p className="adm-empty-title">All clear</p>
                  <p className="adm-empty-sub">No pending verifications</p>
                </div>
              ) : (
                pendingVerifUsers.map(user => (
                  <div key={user.id} className="adm-row-item">
                    <div className="adm-row-avatar">
                      {(user.full_name || "?").charAt(0)}
                    </div>
                    <div className="adm-row-main">
                      <p className="adm-row-name">{user.full_name}</p>
                      <p className="adm-row-sub">Joined {fmtDate(user.created_at)}</p>
                    </div>
                    <div className="adm-row-actions">
                      <button
                        className="adm-btn adm-btn--success adm-btn--sm"
                        onClick={() => verifyUser(user.id)}
                      >
                        <CheckCircle2 size={11} />
                        Verify
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* Recent reports */}
          <div className="adm-card">
            <div className="adm-card-head">
              <p className="adm-section-title adm-section-title--red">Pending Reports</p>
              {recentReports.length > 0 && (
                <span className="adm-badge adm-badge--red">{recentReports.length}</span>
              )}
            </div>
            <div className="adm-card-body">
              {recentReports.length === 0 ? (
                <div className="adm-empty">
                  <div className="adm-empty-icon"><ShieldAlert size={20} /></div>
                  <p className="adm-empty-title">No pending reports</p>
                  <p className="adm-empty-sub">Community is clean</p>
                </div>
              ) : (
                recentReports.map(r => (
                  <div key={r.id} className="adm-row-item">
                    <div className="adm-row-avatar" style={{ background: "rgba(229,64,64,0.10)", border: "1px solid rgba(229,64,64,0.20)", color: "var(--s-red)" }}>
                      <ShieldAlert size={13} />
                    </div>
                    <div className="adm-row-main">
                      <p className="adm-row-name">
                        {r.reporter?.full_name} ÔåÆ {r.reported?.full_name}
                      </p>
                      <p className="adm-row-sub">{r.reason}</p>
                    </div>
                    <span className="adm-badge adm-badge--red">Pending</span>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>

        {/* ÔöÇÔöÇ Recent tickets ÔöÇÔöÇ */}
        <div className="adm-section">
          <div className="adm-section-head">
            <p className="adm-section-title">Recent Tickets</p>
            <Link to="/admin/support" className="adm-btn adm-btn--ghost adm-btn--sm">
              View all <ChevronRight size={12} />
            </Link>
          </div>
          <div className="adm-table-wrap">
            <table className="adm-table">
              <thead>
                <tr>
                  <th>Subject</th>
                  <th>Player</th>
                  <th>Priority</th>
                  <th>Status</th>
                  <th>Date</th>
                </tr>
              </thead>
              <tbody>
                {recentTickets.length === 0 ? (
                  <tr>
                    <td colSpan={5}>
                      <div className="adm-empty">
                        <p className="adm-empty-title">No recent tickets</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  recentTickets.map(t => {
                    const pMeta = PRIORITY_META[t.priority] || PRIORITY_META.normal;
                    const statusColor = t.status === "open" ? "adm-badge--red" :
                                        t.status === "answered" ? "adm-badge--green" :
                                        t.status === "pending" ? "adm-badge--gold" : "adm-badge--subtle";
                    return (
                      <tr key={t.id}>
                        <td>
                          <Link to="/admin/support" className="adm-table-name" style={{ textDecoration: "none" }}>
                            {t.subject}
                          </Link>
                        </td>
                        <td>{t.user?.full_name || "ÔÇö"}</td>
                        <td>
                          <span className={`adm-badge ${pMeta.cls}`}>
                            <span className="adm-badge-dot" />
                            {pMeta.label}
                          </span>
                        </td>
                        <td>
                          <span className={`adm-badge ${statusColor}`}>
                            {t.status}
                          </span>
                        </td>
                        <td style={{ color: "var(--t4)" }}>{fmtDate(t.created_at)}</td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>

        {/* ÔöÇÔöÇ Recent users ÔöÇÔöÇ */}
        <div className="adm-section">
          <div className="adm-section-head">
            <p className="adm-section-title">Recent Registrations</p>
          </div>
          <div className="adm-table-wrap">
            <table className="adm-table">
              <thead>
                <tr>
                  <th>Player</th>
                  <th>Role</th>
                  <th>Verification</th>
                  <th>Joined</th>
                </tr>
              </thead>
              <tbody>
                {recentUsers.map(u => {
                  const vMeta = VERIF_META[u.verification_status] || VERIF_META.pending;
                  return (
                    <tr key={u.id}>
                      <td>
                        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                          <div className="adm-row-avatar" style={{ width: 26, height: 26, fontSize: 10, flexShrink: 0 }}>
                            {(u.full_name || "?").charAt(0)}
                          </div>
                          <span className="adm-table-name">{u.full_name}</span>
                        </div>
                      </td>
                      <td>
                        <span className={`adm-badge ${
                          u.role === "admin" || u.role === "super_admin" ? "adm-badge--orange" :
                          u.role === "founder" ? "adm-badge--gold" :
                          u.role === "designer" ? "adm-badge--cyan" : "adm-badge--subtle"
                        }`}>
                          {u.role || "user"}
                        </span>
                      </td>
                      <td>
                        <span className={`adm-badge ${vMeta.cls}`}>
                          <span className="adm-badge-dot" />
                          {vMeta.label}
                        </span>
                      </td>
                      <td style={{ color: "var(--t4)" }}>{fmtDate(u.created_at)}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useOutletContext, useNavigate } from "react-router-dom";
import { supabase } from "../lib/supabase";
import { motion, AnimatePresence } from "framer-motion";

export default function AdminGrant() {
  const { profile } = useOutletContext();
  const navigate = useNavigate();
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState("");
  const [amount, setAmount] = useState("");
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [message, setMessage] = useState({ type: "", text: "" });
  const [recentGrants, setRecentGrants] = useState([]);
  const [currentBalance, setCurrentBalance] = useState(0);

  const isSuperAdmin = profile?.role === "super_admin";

  useEffect(() => {
    if (!isSuperAdmin) {
      navigate("/dashboard");
    }
  }, [isSuperAdmin, navigate]);

  useEffect(() => {
    if (isSuperAdmin) {
      fetchApprovedUsers();
      fetchRecentGrants();
    }
  }, [isSuperAdmin]);

  const fetchApprovedUsers = async () => {
    try {
      const { data: profiles, error: profilesError } = await supabase
        .from("profiles")
        .select(`
          id, 
          full_name, 
          free_fire_id
        `)
        .eq("verification_status", "approved")
        .order("full_name", { ascending: true });

      if (profilesError) throw profilesError;

      const usersWithBalance = await Promise.all(
        (profiles || []).map(async (user) => {
          const { data: wallet } = await supabase
            .from("wallets")
            .select("balance")
            .eq("user_id", user.id)
            .maybeSingle();
          
          return {
            ...user,
            coins: wallet?.balance || 0
          };
        })
      );

      setUsers(usersWithBalance || []);
    } catch (err) {
      console.error("Error fetching users:", err);
      setMessage({ type: "error", text: "Erreur lors du chargement des utilisateurs" });
    }
  };

  const fetchRecentGrants = async () => {
    try {
      const { data, error } = await supabase
        .from("wallet_transactions")
        .select(`
          id,
          amount,
          created_at,
          profiles!wallet_transactions_user_id_fkey (
            full_name
          )
        `)
        .eq("type", "admin_grant")
        .order("created_at", { ascending: false })
        .limit(10);

      if (error) throw error;
      setRecentGrants(data || []);
    } catch (err) {
      console.error("Error fetching recent grants:", err);
    }
  };

  const fetchUserBalance = async (userId) => {
    if (!userId || userId === "") {
      setCurrentBalance(0);
      return;
    }

    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(userId)) {
      setCurrentBalance(0);
      return;
    }

    try {
      const { data, error } = await supabase
        .from("wallets")
        .select("balance")
        .eq("user_id", userId)
        .maybeSingle();

      if (error) throw error;
      setCurrentBalance(data?.balance || 0);
    } catch (err) {
      console.error("Error fetching balance:", err);
      setCurrentBalance(0);
    }
  };

  const handleUserSelect = (userId) => {
    if (!userId || userId === "") {
      setSelectedUser("");
      setCurrentBalance(0);
      return;
    }

    setSelectedUser(userId);
    fetchUserBalance(userId);
  };

  const handleGrantCoins = async () => {
    if (!selectedUser) {
      setMessage({ type: "error", text: "Veuillez s├®lectionner un utilisateur" });
      return;
    }

    const amountNum = parseInt(amount);
    if (isNaN(amountNum) || amountNum <= 0) {
      setMessage({ type: "error", text: "Veuillez entrer un montant valide" });
      return;
    }

    if (amountNum > 10000) {
      setMessage({ type: "error", text: "Le montant maximum est de 10 000 pi├¿ces" });
      return;
    }

    setLoading(true);
    setMessage({ type: "", text: "" });

    try {
      const { data, error } = await supabase
        .rpc("grant_coins", {
          target_user: selectedUser,
          amount: amountNum
        });

      if (error) throw error;

      if (data && data.success) {
        setMessage({ 
          type: "success", 
          text: `Ô£à ${amountNum} pi├¿ces ont ├®t├® accord├®es avec succ├¿s` 
        });
        setAmount("");
        setSelectedUser("");
        setSearchTerm("");
        fetchApprovedUsers();
        fetchRecentGrants();
      } else {
        setMessage({ type: "error", text: data?.message || "Erreur lors de l'op├®ration" });
      }
    } catch (err) {
      console.error("Error granting coins:", err);
      setMessage({ 
        type: "error", 
        text: err.message || "├ëchec de l'op├®ration" 
      });
    } finally {
      setLoading(false);
    }
  };

  const filteredUsers = users.filter(user =>
    user.full_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.free_fire_id?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const selectedUserData = users.find(u => u.id === selectedUser);

  if (!isSuperAdmin) {
    return null;
  }

  return (
    <div className="min-h-screen bg-[#030014] text-white cyber-grid p-4 md:p-8">
      <div className="max-w-7xl mx-auto">

      <style>{`
        @media (max-width: 768px) {
          .max-w-7xl { padding-left: 12px !important; padding-right: 12px !important; }
          .p-8 { padding: 16px !important; }
          .p-6 { padding: 14px !important; }
          .gap-8 { gap: 16px !important; }
          .gap-6 { gap: 12px !important; }
          .grid-cols-7, .lg\:grid-cols-7 { grid-template-columns: repeat(4,1fr) !important; }
          .md\:grid-cols-3 { grid-template-columns: 1fr !important; }
          .md\:grid-cols-2 { grid-template-columns: 1fr !important; }
          .md\:grid-cols-4 { grid-template-columns: 1fr 1fr !important; }
          .lg\:grid-cols-8 { grid-template-columns: repeat(4,1fr) !important; }
          .text-3xl { font-size: 20px !important; }
          .text-4xl { font-size: 24px !important; }
          .mb-8 { margin-bottom: 16px !important; }
          .overflow-x-auto { overflow-x: auto !important; -webkit-overflow-scrolling: touch; }
          table { font-size: 12px !important; }
          th, td { padding: 6px 8px !important; }
        }
        @media (max-width: 480px) {
          .grid-cols-7, .lg\:grid-cols-7, .lg\:grid-cols-8 { grid-template-columns: repeat(2,1fr) !important; }
          .md\:grid-cols-4 { grid-template-columns: 1fr 1fr !important; }
          .flex-row { flex-direction: column !important; }
        }
      `}</style>

        
        <div className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-3xl font-bold bg-gradient-to-r from-[#7c3aed] to-[#06b6d4] bg-clip-text text-transparent">
              ­ƒææ GESTION DES COINS
            </h1>
            <p className="text-white/40 mt-2">
              Accorder des pi├¿ces aux utilisateurs approuv├®s
            </p>
          </div>
          <div className="flex gap-3">
            <button
              onClick={() => navigate("/super-admin")}
              className="px-4 py-2 bg-[#11152b] border border-[rgba(124,58,237,0.2)] rounded-lg text-sm text-white/60 hover:text-white transition"
            >
              ÔåÉ RETOUR
            </button>
            <button
              onClick={() => navigate("/admin")}
              className="px-4 py-2 bg-[#7c3aed] text-white rounded-lg text-sm hover:bg-[#6d28d9] transition"
            >
              PANEL ADMIN
            </button>
          </div>
        </div>

        <div className="grid lg:grid-cols-2 gap-8">
          
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-[#0a0a1a] border border-[rgba(124,58,237,0.2)] rounded-2xl p-8"
          >
            <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
              <span className="w-1 h-6 bg-[#7c3aed] rounded-full"></span>
              ­ƒÆ░ ACCORDER DES PI├êCES
            </h2>

            <div className="mb-6">
              <label className="block text-sm text-white/40 mb-2">
                RECHERCHER UN UTILISATEUR
              </label>
              <input
                type="text"
                placeholder="Nom ou Free Fire ID..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full px-4 py-3 bg-[#11152b] border border-[rgba(124,58,237,0.2)] rounded-xl text-white focus:border-[#7c3aed] transition mb-3"
              />

              <select
                value={selectedUser}
                onChange={(e) => handleUserSelect(e.target.value)}
                className="w-full px-4 py-3 bg-[#11152b] border border-[rgba(124,58,237,0.2)] rounded-xl text-white focus:border-[#7c3aed] transition"
                size="5"
              >
                <option value="">-- S├ëLECTIONNER UN UTILISATEUR --</option>
                {filteredUsers.map(user => (
                  <option key={user.id} value={user.id} className="py-2">
                    {user.full_name} - {user.coins} pi├¿ces
                    {user.free_fire_id && ` (FF: ${user.free_fire_id})`}
                  </option>
                ))}
              </select>

              {filteredUsers.length === 0 && searchTerm && (
                <p className="mt-2 text-sm text-white/40">
                  Aucun utilisateur trouv├® pour "{searchTerm}"
                </p>
              )}
            </div>

            {selectedUserData && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: "auto" }}
                className="mb-6 p-4 bg-gradient-to-r from-[#7c3aed]/10 to-[#06b6d4]/10 border border-[rgba(124,58,237,0.3)] rounded-xl"
              >
                <p className="text-sm text-[#7c3aed] mb-1">UTILISATEUR S├ëLECTIONN├ë</p>
                <p className="font-medium text-white text-lg">{selectedUserData.full_name}</p>
                {selectedUserData.free_fire_id && (
                  <p className="text-sm text-white/60">FF: {selectedUserData.free_fire_id}</p>
                )}
                <div className="flex justify-between items-center mt-3 pt-3 border-t border-[rgba(124,58,237,0.2)]">
                  <span className="text-white/40">SOLDE ACTUEL</span>
                  <span className="text-xl font-bold text-[#7c3aed]">{currentBalance} pi├¿ces</span>
                </div>
              </motion.div>
            )}

            <div className="mb-6">
              <label className="block text-sm text-white/40 mb-2">
                MONTANT (MAX 10 000)
              </label>
              <input
                type="number"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
                placeholder="Entrer le montant"
                min="1"
                max="10000"
                className="w-full px-4 py-3 bg-[#11152b] border border-[rgba(124,58,237,0.2)] rounded-xl text-white focus:border-[#7c3aed] transition"
              />
            </div>

            <AnimatePresence>
              {message.text && (
                <motion.div
                  initial={{ opacity: 0, y: -10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0 }}
                  className={`mb-6 p-4 rounded-xl ${
                    message.type === "success" 
                      ? "bg-green-500/10 border border-green-500/30 text-green-400"
                      : "bg-red-500/10 border border-red-500/30 text-red-400"
                  }`}
                >
                  {message.text}
                </motion.div>
              )}
            </AnimatePresence>

            <button
              onClick={handleGrantCoins}
              disabled={loading || !selectedUser || !amount}
              className="w-full px-6 py-4 bg-gradient-to-r from-[#7c3aed] to-[#06b6d4] rounded-xl font-bold text-white hover:opacity-90 transition disabled:opacity-50"
            >
              {loading ? "OP├ëRATION EN COURS..." : "ACCORDER DES PI├êCES"}
            </button>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="bg-[#0a0a1a] border border-[rgba(124,58,237,0.2)] rounded-2xl p-8"
          >
            <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
              <span className="w-1 h-6 bg-[#7c3aed] rounded-full"></span>
              ­ƒôï HISTORIQUE R├ëCENT
            </h2>

            {recentGrants.length === 0 ? (
              <div className="text-center py-12">
                <div className="text-6xl mb-4 opacity-30">­ƒô¡</div>
                <p className="text-white/40">AUCUNE OP├ëRATION POUR LE MOMENT</p>
              </div>
            ) : (
              <div className="space-y-4">
                {recentGrants.map(grant => (
                  <div
                    key={grant.id}
                    className="bg-[#11152b] border border-[rgba(124,58,237,0.2)] rounded-xl p-4 hover:scale-[1.02] transition-all duration-300"
                  >
                    <div className="flex justify-between items-center">
                      <div>
                        <p className="font-medium text-white">
