            style={{ padding:"12px 20px", borderRadius:10, background: msg.startsWith("Ô£à") ? "rgba(16,185,129,.15)" : "rgba(244,63,94,.15)",
              border:`1px solid ${msg.startsWith("Ô£à") ? GREEN : RED}44`, marginBottom:24,
