                </div>

                {/* Content */}
                <div>
                  <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:2, color:"rgba(255,255,255,.3)", marginBottom:6 }}>CONTENU COMPLET</p>
