import { useState, useEffect } from "react";
import { useOutletContext, useNavigate } from "react-router-dom";
import { supabase } from "../lib/supabase";
import { motion, AnimatePresence } from "framer-motion";

// ÔöÇÔöÇ RARITY CONFIG ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const RC = {
  common:    { color: "#9ca3af", label: "COMMUN" },
  rare:      { color: "#3b82f6", label: "RARE" },
  epic:      { color: "#a855f7", label: "├ëPIQUE" },
  legendary: { color: "#f59e0b", label: "L├ëGEND." },
};

const TYPE_ICON = {
  avatar: "­ƒÄ¡", banner: "­ƒû╝´©Å", badge: "­ƒÅà",
  name_color: "Ô£¿", frame: "­ƒÆá", emote: "­ƒÿÄ",
};

// ÔöÇÔöÇ COIN BADGE ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function CoinBadge({ amount }) {
  const pos = amount > 0;
  return (
    <span style={{
      padding: "3px 10px", borderRadius: 99, fontSize: 12, fontWeight: 700,
      fontFamily: "Orbitron, sans-serif",
      background: pos ? "rgba(16,185,129,0.12)" : "rgba(239,68,68,0.12)",
      color: pos ? "#10b981" : "#ef4444",
      border: `1px solid ${pos ? "rgba(16,185,129,0.25)" : "rgba(239,68,68,0.25)"}`,
    }}>
      {pos ? "+" : ""}{amount.toLocaleString()} ­ƒÆ░
    </span>
  );
}

// ÔöÇÔöÇ MAIN ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export default function AdminStorePanel() {
  const { profile } = useOutletContext();
  const navigate    = useNavigate();

  const [tab, setTab]             = useState("grant");
  const [users, setUsers]         = useState([]);
  const [storeItems, setStoreItems] = useState([]);
  const [searchUser, setSearchUser] = useState("");
  const [selectedUser, setSelectedUser] = useState(null);
  const [userInventory, setUserInventory] = useState([]);
  const [selectedItem, setSelectedItem] = useState(null);
  const [coinAmount, setCoinAmount]     = useState(0);
  const [coinReason, setCoinReason]     = useState("");
  const [loading, setLoading]     = useState(false);
  const [notification, setNotification] = useState(null);
  const [pendingItems,  setPendingItems]  = useState([]);
  const [allStoreItems, setAllStoreItems] = useState([]);
  const [searchItem,    setSearchItem]    = useState("");
  const [itemFilter,    setItemFilter]    = useState("all");
  const [logs, setLogs]           = useState([]);

  useEffect(() => {
    if (!["admin","super_admin","designer"].includes(profile?.role)) navigate("/dashboard");
    fetchUsers();
    fetchStoreItems();
    fetchPendingItems();
    fetchAllStoreItems();
  }, []);

  const fetchPendingItems = async () => {
    const { data } = await supabase.from("store_items")
      .select("*, creator:profiles!store_items_created_by_fkey(full_name)")
      .eq("approved", false).order("created_at", { ascending:false });
    setPendingItems(data ?? []);
  };

  const fetchAllStoreItems = async () => {
    const { data } = await supabase.from("store_items")
      .select("*").order("sort_order", { ascending:true });
    setAllStoreItems(data ?? []);
  };

  const approveItem = async (itemId) => {
    await supabase.from("store_items").update({ approved:true, active:true }).eq("id", itemId);
    fetchPendingItems(); fetchAllStoreItems(); fetchStoreItems();
    notify("Ô£à Item approuv├® !");
  };

  const rejectItem = async (itemId) => {
    await supabase.from("store_items").update({ approved:false, active:false }).eq("id", itemId);
    fetchPendingItems();
    notify("ÔØî Item rejet├®", "error");
  };

  const toggleFeatured = async (itemId, current) => {
    await supabase.from("store_items").update({ featured: !current }).eq("id", itemId);
    fetchAllStoreItems();
    notify(current ? "Item retir├® des featured" : "Ô¡É Item mis en featured !");
  };

  const toggleVisible = async (itemId, current) => {
    await supabase.from("store_items").update({ active: !current }).eq("id", itemId);
    fetchAllStoreItems();
    notify(current ? "Item masqu├®" : "Item visible en boutique");
  };

  const updatePrice = async (itemId, price) => {
    await supabase.from("store_items").update({ price }).eq("id", itemId);
    fetchAllStoreItems();
    notify("­ƒÆ░ Prix mis ├á jour");
  };

  useEffect(() => {
    if (selectedUser) fetchUserInventory(selectedUser.id);
  }, [selectedUser]);

  const fetchUsers = async () => {
    const { data } = await supabase
      .from("profiles")
      .select("id, full_name, email, role, avatar_url, level, equipped_badge, equipped_name_color")
      .order("full_name");
    setUsers(data || []);
  };

  const fetchStoreItems = async () => {
    const { data } = await supabase
      .from("store_items")
      .select("*")
      .order("rarity", { ascending: false });
    setStoreItems(data || []);
  };

  const fetchUserInventory = async (uid) => {
    const { data } = await supabase
      .from("user_items")
      .select("*, item:store_items(*)")
      .eq("user_id", uid);
    setUserInventory(data || []);
  };

  const fetchWallet = async (uid) => {
    const { data } = await supabase.from("wallets").select("balance").eq("user_id", uid).maybeSingle();
    return data?.balance || 0;
  };

  const notify = (msg, type = "success") => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 3500);
  };

  const addLog = (action, target, detail) => {
    setLogs(prev => [{
      id: Date.now(), action, target, detail,
      time: new Date().toLocaleTimeString("fr-FR"),
    }, ...prev.slice(0, 49)]);
  };

  // ÔöÇÔöÇ GRANT ITEM ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleGrant = async () => {
    if (!selectedUser || !selectedItem) {
      notify("S├®lectionne un joueur et un item", "error"); return;
    }
    setLoading(true);
    const { data, error } = await supabase.rpc("admin_grant_item", {
      p_target_user_id: selectedUser.id,
      p_item_id:        selectedItem.id,
      p_reason:         "Don Admin",
    });
    setLoading(false);

    if (error || !data?.success) {
      notify(data?.error || error?.message || "Erreur", "error"); return;
    }

    notify(`Ô£à ${selectedItem.name} accord├® ├á ${selectedUser.full_name}`);
    addLog("GRANT ITEM", selectedUser.full_name, `${selectedItem.name} (${selectedItem.rarity})`);
    fetchUserInventory(selectedUser.id);
    setSelectedItem(null);
  };

  // ÔöÇÔöÇ REMOVE ITEM ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleRemove = async (inv) => {
    if (!confirm(`Retirer "${inv.item?.name}" ├á ${selectedUser.full_name} ?`)) return;
    setLoading(true);
    const { data, error } = await supabase.rpc("admin_remove_item", {
      p_target_user_id: selectedUser.id,
      p_item_id:        inv.item_id,
    });
    setLoading(false);

    if (error || !data?.success) {
      notify(data?.error || "Erreur", "error"); return;
    }

    notify(`­ƒùæ´©Å ${inv.item?.name} retir├® de ${selectedUser.full_name}`);
    addLog("REMOVE ITEM", selectedUser.full_name, inv.item?.name);
    fetchUserInventory(selectedUser.id);
  };

  // ÔöÇÔöÇ ADJUST COINS ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const handleCoins = async () => {
    if (!selectedUser) { notify("S├®lectionne un joueur", "error"); return; }
    if (!coinAmount || coinAmount === 0) { notify("Montant invalide", "error"); return; }
    if (!coinReason.trim()) { notify("Raison obligatoire", "error"); return; }
    setLoading(true);

    const { data, error } = await supabase.rpc("admin_adjust_coins", {
      p_target_user_id: selectedUser.id,
      p_amount:         parseInt(coinAmount),
      p_reason:         coinReason,
    });
    setLoading(false);

    if (error || !data?.success) {
      notify(data?.error || "Erreur", "error"); return;
    }

    const sign = coinAmount > 0 ? "+" : "";
    notify(`­ƒÆ░ ${sign}${coinAmount} coins ÔåÆ ${selectedUser.full_name} (nouveau solde: ${data.new_balance})`);
    addLog(coinAmount > 0 ? "ADD COINS" : "REMOVE COINS", selectedUser.full_name, `${sign}${coinAmount} ÔÇö ${coinReason}`);
    setCoinAmount(0);
    setCoinReason("");

    // Refresh wallet display
    const newBal = await fetchWallet(selectedUser.id);
    setSelectedUser(prev => ({ ...prev, _balance: newBal }));
  };

  // ÔöÇÔöÇ FILTERED USERS ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  const filteredUsers = users.filter(u =>
    !searchUser ||
    u.full_name?.toLowerCase().includes(searchUser.toLowerCase()) ||
    u.email?.toLowerCase().includes(searchUser.toLowerCase())
  );

  const ownedIds = new Set(userInventory.map(u => u.item_id));

  // ÔöÇÔöÇ RENDER ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@700;900&family=Rajdhani:wght@500;600;700&display=swap');
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-thumb { background: rgba(124,58,237,0.3); border-radius: 99px; }
        .fi { font-family: 'Rajdhani', sans-serif; }
        .field-label {
          font-size: 11px; font-weight: 700; letter-spacing: 1.5px;
          color: rgba(255,255,255,0.4); margin-bottom: 6px; display: block;
        }
        .field-input {
          width: 100%; padding: 10px 14px; box-sizing: border-box;
          background: rgba(255,255,255,0.04);
          border: 1px solid rgba(255,255,255,0.1);
          border-radius: 8px; color: #fff; font-size: 14px;
          font-family: 'Rajdhani', sans-serif; outline: none;
          transition: border-color 0.2s;
        }
        .field-input:focus { border-color: rgba(124,58,237,0.6); }
        .field-input option { background: #0d0e1f; }
      `}</style>

      {/* Notification */}
      <AnimatePresence>
        {notification && (
          <motion.div
            initial={{ opacity: 0, y: -30, x: "-50%" }}
            animate={{ opacity: 1, y: 0, x: "-50%" }}
            exit={{ opacity: 0, y: -30, x: "-50%" }}
            style={{
              position: "fixed", top: 20, left: "50%", zIndex: 9999,
              padding: "12px 24px", borderRadius: 10,
              background: notification.type === "error" ? "#1a0505" : "#050d1a",
              border: `1px solid ${notification.type === "error" ? "#ef4444" : "#10b981"}`,
              color: notification.type === "error" ? "#ef4444" : "#10b981",
              fontSize: 14, fontWeight: 600,
              boxShadow: "0 8px 30px rgba(0,0,0,0.5)",
              fontFamily: "Rajdhani, sans-serif",
            }}
          >
            {notification.msg}
          </motion.div>
        )}
      </AnimatePresence>

      <div style={{ minHeight: "100vh", background: "#030014", color: "#fff", fontFamily: "Rajdhani, sans-serif" }}>

        {/* HEADER */}
        <div style={{
          padding: "28px 32px 24px",
          background: "linear-gradient(180deg, rgba(239,68,68,0.08), transparent)",
          borderBottom: "1px solid rgba(239,68,68,0.12)",
        }}>
          <div style={{ maxWidth: 1300, margin: "0 auto", display: "flex", alignItems: "center", gap: 14 }}>
            <div style={{
              width: 46, height: 46, borderRadius: 12,
              background: "linear-gradient(135deg, #dc2626, #7c3aed)",
              display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22,
              boxShadow: "0 8px 25px rgba(220,38,38,0.35)",
            }}>
              ­ƒææ
            </div>
            <div>
              <h1 style={{ fontFamily: "Orbitron", fontSize: 20, fontWeight: 900, color: "#fff", margin: 0, letterSpacing: 2 }}>
                ADMIN <span style={{ color: "#ef4444" }}>STORE</span> PANEL
              </h1>
              <p style={{ color: "rgba(255,255,255,0.3)", fontSize: 11, letterSpacing: 2, margin: 0 }}>
                GESTION ITEMS & COINS JOUEURS
              </p>
            </div>
            <div style={{ marginLeft: "auto", display: "flex", gap: 12 }}>
              <div style={{
                padding: "8px 16px", borderRadius: 10, fontSize: 12, fontWeight: 700, letterSpacing: 1,
                background: "rgba(239,68,68,0.1)", border: "1px solid rgba(239,68,68,0.25)",
                color: "#ef4444",
              }}>
                {users.length} JOUEURS
              </div>
              <div style={{
                padding: "8px 16px", borderRadius: 10, fontSize: 12, fontWeight: 700, letterSpacing: 1,
                background: "rgba(124,58,237,0.1)", border: "1px solid rgba(124,58,237,0.25)",
                color: "#a855f7",
              }}>
                {storeItems.length} ITEMS
              </div>
            </div>
          </div>
        </div>

        {/* TABS */}
        <div style={{
          position: "sticky", top: 0, zIndex: 10,
          background: "rgba(3,0,20,0.97)", backdropFilter: "blur(20px)",
          borderBottom: "1px solid rgba(255,255,255,0.06)", padding: "0 32px",
        }}>
          <div style={{ maxWidth: 1300, margin: "0 auto", display: "flex" }}>
            {[
              { key: "grant",    icon: "­ƒÄü", label: "DONNER" },
              { key: "coins",    icon: "­ƒÆ░", label: "COINS" },
              { key: "items",    icon: "­ƒôª", label: "ITEMS" },
              { key: "approve",  icon: "ÔÅ│", label: "APPROBATIONS" },
              { key: "logs",     icon: "­ƒôï", label: "LOGS" },
            ].map(t => (
              <button key={t.key} onClick={() => setTab(t.key)}
                style={{
                  padding: "14px 20px", background: "transparent", border: "none",
                  borderBottom: `2px solid ${tab === t.key ? "#ef4444" : "transparent"}`,
                  color: tab === t.key ? "#fff" : "rgba(255,255,255,0.3)",
                  fontSize: 11, fontWeight: 700, letterSpacing: 1.5, cursor: "pointer",
                  fontFamily: "Rajdhani, sans-serif", display: "flex", alignItems: "center", gap: 7,
                  transition: "all 0.2s",
                }}
              >
                <span>{t.icon}</span><span>{t.label}</span>
              </button>
            ))}
          </div>
        </div>

        <div style={{ maxWidth: 1300, margin: "0 auto", padding: "28px 32px" }}>

          {/* USER SELECTOR (shared between tabs) */}
          <div style={{
            padding: "20px", borderRadius: 14, marginBottom: 24,
            background: "#08031a", border: "1px solid rgba(255,255,255,0.07)",
          }}>
            <label className="field-label">S├ëLECTIONNER UN JOUEUR</label>
            <div style={{ display: "grid", gridTemplateColumns:"repeat(auto-fit,minmax(240px,1fr))", gap: 16 }}>
              <div>
                <input
                  className="field-input"
                  placeholder="­ƒöì Rechercher par nom ou email..."
                  autoComplete="off"
                  value={searchUser}
                  onChange={e => setSearchUser(e.target.value)}
                />
              </div>
              <select className="field-input"
                value={selectedUser?.id || ""}
                onChange={e => {
                  const u = users.find(x => x.id === e.target.value);
                  setSelectedUser(u || null);
                }}
              >
                <option value="">-- Choisir un joueur --</option>
                {filteredUsers.map(u => (
                  <option key={u.id} value={u.id}>
                    {u.full_name} ({u.role}) {u.email ? `ÔÇö ${u.email}` : ""}
                  </option>
                ))}
              </select>
            </div>

            {/* Selected user card */}
            {selectedUser && (
              <motion.div
                initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}
                style={{
                  marginTop: 16, padding: "14px 18px", borderRadius: 10,
                  background: "rgba(124,58,237,0.08)", border: "1px solid rgba(124,58,237,0.2)",
                  display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 12,
                }}
              >
                <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                  <div style={{
                    width: 40, height: 40, borderRadius: 10,
                    background: "linear-gradient(135deg, #7c3aed, #06b6d4)",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontSize: 18, fontWeight: 700,
                  }}>
                    {selectedUser.full_name?.[0]?.toUpperCase()}
                  </div>
                  <div>
                    <div style={{ fontWeight: 700, fontSize: 16 }}>{selectedUser.full_name}</div>
                    <div style={{ fontSize: 11, color: "rgba(255,255,255,0.4)" }}>{selectedUser.email}</div>
                  </div>
                  <span style={{
                    padding: "3px 10px", borderRadius: 99, fontSize: 10, fontWeight: 700, letterSpacing: 1,
                    background: selectedUser.role === "super_admin" ? "rgba(245,158,11,0.15)" : "rgba(124,58,237,0.15)",
                    color: selectedUser.role === "super_admin" ? "#f59e0b" : "#a855f7",
                    border: `1px solid ${selectedUser.role === "super_admin" ? "rgba(245,158,11,0.3)" : "rgba(124,58,237,0.3)"}`,
                  }}>
                    {selectedUser.role?.toUpperCase()}
                  </span>
                </div>

                <div style={{ display: "flex", gap: 16 }}>
                  <div style={{ textAlign: "center" }}>
                    <div style={{ fontSize: 10, color: "rgba(255,255,255,0.35)", letterSpacing: 1 }}>INVENTAIRE</div>
                    <div style={{ fontSize: 18, fontWeight: 700, color: "#a855f7", fontFamily: "Orbitron" }}>
                      {userInventory.length}
                    </div>
                  </div>
                </div>
              </motion.div>
            )}
          </div>

          {/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ TAB: GRANT ITEM ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */}
          {tab === "grant" && (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 360px", gap: 24 }}>

              {/* Items grid */}
              <div>
                <div style={{ marginBottom: 16, fontSize: 13, color: "rgba(255,255,255,0.4)", letterSpacing: 1 }}>
                  S├ëLECTIONNE L'ITEM ├Ç DONNER
                </div>

                {["legendary","epic","rare","common"].map(r => {
                  const section = storeItems.filter(i => i.rarity === r);
                  if (!section.length) return null;
                  const rc = RC[r];
                  return (
                    <div key={r} style={{ marginBottom: 28 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
                        <div style={{ height: 1, flex: 1, background: `linear-gradient(90deg, ${rc.color}40, transparent)` }} />
                        <span style={{ fontSize: 10, fontWeight: 700, letterSpacing: 2, color: rc.color }}>
                          {rc.label}
                        </span>
                        <div style={{ height: 1, flex: 1, background: `linear-gradient(90deg, transparent, ${rc.color}40)` }} />
                      </div>
                      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(180px, 1fr))", gap: 10 }}>
                        {section.map(item => {
                          const owned = ownedIds.has(item.id);
                          const selected = selectedItem?.id === item.id;
                          return (
                            <div
                              key={item.id}
                              onClick={() => !owned && setSelectedItem(item)}
                              style={{
                                padding: "12px", borderRadius: 10, cursor: owned ? "not-allowed" : "pointer",
                                border: `1px solid ${selected ? rc.color : owned ? "rgba(16,185,129,0.3)" : "rgba(255,255,255,0.07)"}`,
                                background: selected ? `${rc.color}15` : owned ? "rgba(16,185,129,0.05)" : "rgba(255,255,255,0.02)",
                                opacity: owned ? 0.6 : 1,
                                transition: "all 0.2s",
                                display: "flex", alignItems: "center", gap: 10,
                              }}
                            >
                              <span style={{ fontSize: 22 }}>{TYPE_ICON[item.type] || "­ƒÄ«"}</span>
                              <div style={{ flex: 1, minWidth: 0 }}>
                                <div style={{ fontSize: 12, fontWeight: 700, color: selected ? rc.color : "#fff",
                                  whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                                  {item.name}
                                </div>
                                <div style={{ fontSize: 10, color: "rgba(255,255,255,0.35)" }}>
                                  {owned ? "Ô£à d├®j├á poss├®d├®" : `­ƒÆ░ ${item.price}`}
                                </div>
                              </div>
                              {selected && <span style={{ fontSize: 16 }}>Ô£ô</span>}
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>

              {/* Right: action panel */}
              <div style={{ position: "sticky", top: 80 }}>
                <div style={{
                  padding: "20px", borderRadius: 14,
                  background: "#08031a", border: "1px solid rgba(255,255,255,0.07)",
                }}>
                  <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, color: "rgba(255,255,255,0.4)", marginBottom: 16 }}>
                    R├ëSUM├ë DE L'ACTION
                  </div>

                  <div style={{ display: "flex", flexDirection: "column", gap: 10, marginBottom: 20 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 12px", borderRadius: 8, background: "rgba(255,255,255,0.03)" }}>
                      <span style={{ fontSize: 12, color: "rgba(255,255,255,0.4)" }}>JOUEUR</span>
                      <span style={{ fontSize: 12, fontWeight: 700, color: selectedUser ? "#fff" : "rgba(255,255,255,0.2)" }}>
                        {selectedUser?.full_name || "ÔÇö"}
                      </span>
                    </div>
                    <div style={{ display: "flex", justifyContent: "space-between", padding: "10px 12px", borderRadius: 8, background: "rgba(255,255,255,0.03)" }}>
                      <span style={{ fontSize: 12, color: "rgba(255,255,255,0.4)" }}>ITEM</span>
