                  <p style={{fontSize:36,marginBottom:12,opacity:.3}}>­ƒÅƒ´©Å</p>
                  <p style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:18,fontWeight:800,color:"rgba(255,255,255,0.2)",letterSpacing:2,marginBottom:16}}>AR├êNE EN VEILLE</p>
                  <p style={{fontFamily:"'Share Tech Mono',monospace",fontSize:10,color:"rgba(255,255,255,0.2)",letterSpacing:1,marginBottom:24}}>Aucun tournoi actif pour le moment</p>
                  <button className="db-btn" onClick={() => nav("/tournaments")}>PARCOURIR ÔåÆ</button>
                </motion.div>
              ) : (
                <div style={{display:"flex",flexDirection:"column",gap:8}}>
                  {tournaments.map((t,i) => <TrnCard key={t.id} t={t} index={i}/>)}
                </div>
              )}
            </div>

            {/* Announcements */}
            {messages.length > 0 && (
              <motion.div initial={{opacity:0,y:20}} animate={{opacity:1,y:0}} transition={{delay:.5}}>
                <div className="db-lbl">Annonces</div>
                <div style={{display:"flex",flexDirection:"column",gap:10}}>
                  {messages.map(m => (
                    <div key={m.id} style={{padding:"14px 16px",background:"rgba(220,38,38,0.04)",border:"1px solid rgba(220,38,38,0.15)",borderLeft:"3px solid #dc2626"}}>
                      <p style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:14,fontWeight:800,marginBottom:4}}>{m.title??"ANNONCE"}</p>
                      <p style={{fontSize:13,color:"rgba(255,255,255,0.5)",lineHeight:1.5}}>{m.content??m.message??"ÔÇö"}</p>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </div>

          {/* RIGHT */}
          <div style={{display:"flex",flexDirection:"column",gap:24}}>

            {/* Rank block */}
            <motion.div initial={{opacity:0,y:20}} animate={{opacity:1,y:0}} transition={{delay:.35}} style={{background:"rgba(255,255,255,0.02)",border:"1px solid rgba(255,255,255,0.06)",padding:"24px 20px"}}>
              <div className="db-lbl">Mon Classement</div>
              <div style={{display:"flex",alignItems:"baseline",gap:10,marginBottom:20}}>
                <span style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:64,fontWeight:900,lineHeight:1,color:stats.rank?"#fff":"rgba(255,255,255,0.08)"}}>
                  {stats.rank?`#${stats.rank}`:"ÔÇö"}
                </span>
                <span style={{fontFamily:"'Share Tech Mono',monospace",fontSize:10,letterSpacing:2,color:stats.rank?"#dc2626":"rgba(255,255,255,0.2)"}}>GLOBAL</span>
              </div>
              <div style={{marginBottom:24}}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
                  <span style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,letterSpacing:2,color:"rgba(255,255,255,0.3)"}}>WIN RATE</span>
                  <span style={{fontFamily:"'Barlow Condensed',monospace",fontSize:14,fontWeight:800,color:"#22c55e"}}>{stats.winRate}%</span>
                </div>
                <div style={{height:3,background:"rgba(255,255,255,0.06)",overflow:"hidden"}}>
                  <motion.div initial={{width:0}} animate={{width:`${stats.winRate}%`}} transition={{delay:.8,duration:1,ease:"easeOut"}} style={{height:"100%",background:"linear-gradient(90deg,#22c55e,#16a34a)"}}/>
                </div>
                <div style={{display:"flex",justifyContent:"space-between",marginTop:4}}>
                  <span style={{fontFamily:"'Share Tech Mono',monospace",fontSize:8,color:"rgba(255,255,255,0.15)"}}>0%</span>
                  <span style={{fontFamily:"'Share Tech Mono',monospace",fontSize:8,color:"rgba(255,255,255,0.15)"}}>100%</span>
                </div>
              </div>
              {(() => {
                const ROLE_PANELS = {
                  super_admin: { label:"­ƒææ SUPER ADMIN", color:"#00e5ff", path:"/super-admin" },
                  admin:       { label:"­ƒøí´©Å PANEL ADMIN", color:"#818cf8", path:"/admin" },
                  founder:     { label:"ÔÜí PANEL FONDATEUR", color:"#a855f7", path:"/founder" },
                  fondateur:   { label:"ÔÜí PANEL FONDATEUR", color:"#a855f7", path:"/founder" },
                  designer:    { label:"­ƒÄ¿ PANEL DESIGNER", color:"#22c55e", path:"/designer" },
                  user:        { label:"JOUEUR", color:"rgba(255,255,255,0.35)", path:null },
                };
                const r = ROLE_PANELS[profile?.role] ?? ROLE_PANELS.user;
                if (!r.path) return (
                  <div style={{display:"inline-flex",alignItems:"center",gap:8,background:`${r.color}10`,border:`1px solid ${r.color}30`,padding:"6px 14px",fontFamily:"'Barlow Condensed',sans-serif",fontSize:12,fontWeight:800,letterSpacing:2,color:r.color}}>
                    {r.label}
                  </div>
                );
                return (
                  <button
                    onClick={() => nav(r.path)}
                    style={{
                      display:"inline-flex",alignItems:"center",gap:8,
                      background:`${r.color}15`,
                      border:`1px solid ${r.color}60`,
                      padding:"8px 16px",
                      fontFamily:"'Barlow Condensed',sans-serif",
                      fontSize:13,fontWeight:800,letterSpacing:2,
                      color:r.color,cursor:"pointer",
                      transition:"all .2s",
                      boxShadow:`0 0 12px ${r.color}20`,
                    }}
                    onMouseEnter={e=>{e.currentTarget.style.background=`${r.color}25`;e.currentTarget.style.boxShadow=`0 0 20px ${r.color}40`;}}
                    onMouseLeave={e=>{e.currentTarget.style.background=`${r.color}15`;e.currentTarget.style.boxShadow=`0 0 12px ${r.color}20`;}}
                  >
                    {r.label}
                  </button>
                );
              })()}
            </motion.div>

            {/* Quick links */}
            <div>
              <div className="db-lbl">Navigation Rapide</div>
              <div style={{display:"flex",flexDirection:"column",gap:6}}>
                {QUICK_LINKS.map((l,i) => (
                  <motion.div key={l.label} className="ql" initial={{opacity:0,x:16}} animate={{opacity:1,x:0}} transition={{delay:i*.06,duration:.3}} onClick={() => nav(l.path)}>
                    <div style={{display:"flex",alignItems:"center",gap:12}}>
                      <span style={{fontSize:18}}>{l.icon}</span>
                      <div>
                        <p style={{fontFamily:"'Barlow Condensed',sans-serif",fontSize:14,fontWeight:800,letterSpacing:.5}}>{l.label}</p>
                        <p style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,color:"rgba(255,255,255,0.3)",letterSpacing:1}}>{l.sub}</p>
                      </div>
                    </div>
                    <span style={{color:"rgba(220,38,38,0.5)",fontSize:16}}>ÔÇ║</span>
                  </motion.div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// src/pages/ClanTest.jsx ÔÇö CipherPool Clan Test Application
import { useState, useEffect } from "react";
import { useNavigate, useOutletContext, useSearchParams } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "../lib/supabase";

const C = {
  bg:      "#08090d",
  card:    "#0f1117",
  border:  "#1a1d28",
  primary: "#7c3aed",
  cyan:    "#00d4ff",
  green:   "#10b981",
  red:     "#ef4444",
  amber:   "#f59e0b",
  text:    "rgba(255,255,255,0.92)",
  muted:   "rgba(255,255,255,0.4)",
  low:     "rgba(255,255,255,0.15)",
};

const ROLES = [
  { key:"rusher",  label:"Rusher",   icon:"ÔÜö´©Å",  desc:"Attaque frontale" },
  { key:"sniper",  label:"Sniper",   icon:"­ƒÄ»",  desc:"Longue port├®e" },
  { key:"support", label:"Support",  icon:"­ƒøí´©Å",  desc:"Soin & couverture" },
  { key:"igl",     label:"IGL",      icon:"­ƒºá",  desc:"Strat├¿ge / leader" },
];

const SKILLS = [
  { key:"pocher",        label:"Pocher",        icon:"­ƒÆè" },
  { key:"reviver",       label:"Reviver",       icon:"ÔØñ´©Å" },
  { key:"cover",         label:"Cover",         icon:"­ƒøí´©Å" },
  { key:"aim",           label:"Aim pr├®cis",    icon:"­ƒÄ»" },
  { key:"communication", label:"Communication", icon:"­ƒÄÖ´©Å" },
  { key:"gloo_wall",     label:"Gloo Wall",     icon:"­ƒº▒" },
];

const EXP = [
  { key:"ranked",   label:"Ranked",     icon:"­ƒöÑ" },
  { key:"cs",       label:"Clash Squad", icon:"ÔÜí" },
  { key:"tournois", label:"Tournois",   icon:"­ƒÅå" },
];

export default function ClanTest() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { profile } = useOutletContext();
  const teamId   = searchParams.get("team");
  const teamName = searchParams.get("name") || "CipherPool";

  const [team, setTeam]       = useState(null);
  const [step, setStep]       = useState(1); // 1=form, 2=success
  const [saving, setSaving]   = useState(false);
  const [existing, setExisting] = useState(null); // already applied?

  const [form, setForm] = useState({
    pseudo:        profile?.full_name || "",
    ff_id:         profile?.free_fire_id || "",
    role:          "",
    skills:        [],
    experience:    [],
    hours_per_day: "",
    has_mic:       null,
    schedule_ok:   null,
    message:       "",
  });

  useEffect(() => {
    if (teamId) loadTeam();
    checkExisting();
  }, [teamId, profile?.id]);

  const loadTeam = async () => {
    const { data } = await supabase.from("teams").select("*").eq("id", teamId).maybeSingle();
    if (data) setTeam(data);
  };

  const checkExisting = async () => {
    if (!profile?.id) return;
    const q = supabase.from("clan_applications").select("id,status,created_at")
      .eq("user_id", profile.id).order("created_at", { ascending: false }).limit(1);
    if (teamId) q.eq("team_id", teamId);
    const { data } = await q.maybeSingle();
    if (data) setExisting(data);
  };

  const toggleSkill = (key) => {
    setForm(f => ({
      ...f,
      skills: f.skills.includes(key) ? f.skills.filter(s => s !== key) : [...f.skills, key]
    }));
  };

  const toggleExp = (key) => {
    setForm(f => ({
      ...f,
      experience: f.experience.includes(key) ? f.experience.filter(e => e !== key) : [...f.experience, key]
    }));
  };

  const handleSubmit = async () => {
    if (!form.pseudo || !form.ff_id || !form.role) return;
    setSaving(true);
    try {
      const payload = {
        user_id:       profile.id,
        team_id:       teamId || null,
        pseudo:        form.pseudo.trim(),
        ff_id:         form.ff_id.trim(),
        role:          form.role,
        skills:        form.skills,
        experience:    form.experience,
        hours_per_day: form.hours_per_day ? parseInt(form.hours_per_day) : null,
        has_mic:       form.has_mic,
        schedule_ok:   form.schedule_ok,
        message:       form.message.trim() || null,
        status:        "pending",
      };
      const { error } = await supabase.from("clan_applications").insert([payload]);
      if (error) throw error;

      // Notification admin_messages ÔåÆ founder
      try {
        await supabase.from("admin_messages").insert([{
          user_id: profile.id,
          content: `­ƒÄ« Nouvelle candidature clan de ${form.pseudo} (${form.role}) ÔÇö ${teamName}`,
          type:    "clan_test",
          is_global: false,
          read: false,
        }]);
      } catch (_) {}

      setStep(2);
    } catch (err) {
      alert("Erreur: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const canSubmit = form.pseudo && form.ff_id && form.role;

  // Already applied
  if (existing) {
    const statusColor = existing.status === "accepted" ? C.green : existing.status === "rejected" ? C.red : C.amber;
    const statusLabel = existing.status === "accepted" ? "Ô£à Accept├®" : existing.status === "rejected" ? "ÔØî Refus├®" : "ÔÅ│ En attente";
    return (
      <div style={{ minHeight:"100vh", background:C.bg, display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
        <motion.div initial={{opacity:0,scale:.9}} animate={{opacity:1,scale:1}}
          style={{ maxWidth:440, width:"100%", background:C.card, border:`1px solid ${C.border}`,
            borderRadius:20, padding:40, textAlign:"center" }}>
          <div style={{ fontSize:56, marginBottom:16 }}>­ƒôï</div>
          <h2 style={{ fontFamily:"'Bebas Neue',cursive", fontSize:28, letterSpacing:2, color:"#fff", margin:"0 0 8px" }}>
            CANDIDATURE EXISTANTE
          </h2>
          <p style={{ color:C.muted, fontSize:13, marginBottom:24 }}>Tu as d├®j├á postul├® pour ce clan.</p>
          <div style={{ background:`${statusColor}18`, border:`1px solid ${statusColor}40`, borderRadius:12,
            padding:"14px 20px", marginBottom:24 }}>
            <span style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:16, fontWeight:700, color:statusColor }}>
              {statusLabel}
            </span>
            <div style={{ color:C.muted, fontSize:11, marginTop:4 }}>
              {new Date(existing.created_at).toLocaleDateString("fr-FR")}
            </div>
          </div>
          <button onClick={() => navigate(-1)}
            style={{ padding:"11px 28px", borderRadius:10, background:C.primary, border:"none",
              color:"#fff", fontFamily:"'Space Grotesk',sans-serif", fontWeight:700, cursor:"pointer" }}>
            ÔåÉ Retour
          </button>
        </motion.div>
      </div>
    );
  }

  // Success screen
  if (step === 2) {
    return (
      <div style={{ minHeight:"100vh", background:C.bg, display:"flex", alignItems:"center", justifyContent:"center", padding:20 }}>
        <motion.div initial={{opacity:0,scale:.85,y:20}} animate={{opacity:1,scale:1,y:0}}
          transition={{type:"spring",stiffness:260,damping:22}}
          style={{ maxWidth:440, width:"100%", background:C.card, border:`1px solid ${C.green}30`,
            borderRadius:20, padding:40, textAlign:"center",
            boxShadow:`0 0 40px ${C.green}15` }}>
          <motion.div animate={{scale:[1,1.2,1]}} transition={{duration:.6,delay:.2}}
            style={{ fontSize:64, marginBottom:16 }}>­ƒÄ«</motion.div>
          <h2 style={{ fontFamily:"'Bebas Neue',cursive", fontSize:32, letterSpacing:2, color:C.green, margin:"0 0 8px" }}>
            CANDIDATURE ENVOY├ëE !
          </h2>
          <p style={{ color:C.muted, fontSize:14, lineHeight:1.6, marginBottom:28 }}>
            Ta demande de test clan a ├®t├® soumise. Le fondateur va la r├®viser et te contacter pour fixer un rendez-vous.
          </p>
          <div style={{ background:`${C.primary}12`, border:`1px solid ${C.primary}25`, borderRadius:12,
            padding:"14px 20px", marginBottom:28, textAlign:"left" }}>
            <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:11, color:C.primary, letterSpacing:2, marginBottom:8 }}>R├ëSUM├ë</div>
            <div style={{ color:"rgba(255,255,255,.7)", fontSize:13 }}>
              <div>­ƒÄ« Pseudo: <strong style={{color:"#fff"}}>{form.pseudo}</strong></div>
              <div>­ƒåö FF ID: <strong style={{color:"#fff"}}>{form.ff_id}</strong></div>
              <div>ÔÜö´©Å R├┤le: <strong style={{color:"#fff"}}>{ROLES.find(r=>r.key===form.role)?.label}</strong></div>
            </div>
          </div>
          <button onClick={() => navigate("/teams")}
            style={{ padding:"13px 32px", borderRadius:10, background:`linear-gradient(135deg,${C.primary},${C.cyan}80)`,
              border:"none", color:"#fff", fontFamily:"'Space Grotesk',sans-serif", fontWeight:700, cursor:"pointer",
              fontSize:14, letterSpacing:.5 }}>
            Voir les ├®quipes ÔåÆ
          </button>
        </motion.div>
      </div>
    );
  }

  return (
    <div style={{ minHeight:"100vh", background:C.bg, padding:"24px 16px 80px" }}>
      <div style={{ maxWidth:600, margin:"0 auto" }}>

        {/* Header */}
        <motion.div initial={{opacity:0,y:-16}} animate={{opacity:1,y:0}} style={{ marginBottom:28 }}>
          <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:16 }}>
            {team?.logo_url && (
              <img src={team.logo_url} style={{ width:40, height:40, borderRadius:10, objectFit:"cover" }} />
            )}
            <div>
              <div style={{ fontFamily:"'Bebas Neue',cursive", fontSize:26, letterSpacing:2, color:"#fff", lineHeight:1 }}>
                TEST CLAN ÔÇö {team?.name?.toUpperCase() || teamName.toUpperCase()}
              </div>
              <div style={{ fontFamily:"'JetBrains Mono',monospace", fontSize:10, color:C.primary, letterSpacing:2 }}>
                CANDIDATURE OFFICIELLE
              </div>
            </div>
          </div>
          <div style={{ height:1, background:`linear-gradient(90deg,${C.primary}60,transparent)` }}/>
        </motion.div>

        {/* Form */}
        <div style={{ display:"flex", flexDirection:"column", gap:18 }}>

          {/* Infos de base */}
          <Section title="INFORMATIONS DE BASE" icon="­ƒÄ«">
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
              <Field label="Pseudo Free Fire *">
                <input value={form.pseudo} onChange={e=>setForm(f=>({...f,pseudo:e.target.value}))}
                  placeholder="Ton pseudo FF..."
                  style={inputStyle} />
              </Field>
              <Field label="FF ID *">
                <input value={form.ff_id} onChange={e=>setForm(f=>({...f,ff_id:e.target.value}))}
                  placeholder="123456789"
                  style={inputStyle} />
              </Field>
            </div>
          </Section>

          {/* R├┤le */}
          <Section title="TON R├öLE" icon="ÔÜö´©Å">
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
              {ROLES.map(r => (
                <RoleCard key={r.key} role={r}
                  selected={form.role === r.key}
                  onClick={() => setForm(f => ({...f, role: r.key}))} />
              ))}
            </div>
          </Section>

          {/* Skills */}
          <Section title="TES SKILLS" icon="­ƒÆ¬">
            <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
              {SKILLS.map(s => (
                <ToggleChip key={s.key} item={s}
                  active={form.skills.includes(s.key)}
                  onClick={() => toggleSkill(s.key)} />
              ))}
            </div>
          </Section>

          {/* Exp├®rience */}
          <Section title="EXP├ëRIENCE" icon="­ƒÅå">
            <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
              {EXP.map(e => (
                <ToggleChip key={e.key} item={e}
                  active={form.experience.includes(e.key)}
                  onClick={() => toggleExp(e.key)} />
              ))}
            </div>
          </Section>

          {/* Questions */}
          <Section title="QUELQUES QUESTIONS" icon="ÔØô">
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>

              <Field label="Heures de jeu par jour">
                <select value={form.hours_per_day}
                  onChange={e => setForm(f=>({...f,hours_per_day:e.target.value}))}
                  style={{...inputStyle, appearance:"none"}}>
                  <option value="">S├®lectionner...</option>
                  {["1","2","3","4","5","6+"].map(h => (
                    <option key={h} value={h}>{h} heure{h==="1"?"":"s"}</option>
                  ))}
                </select>
              </Field>

              <div>
                <div style={labelStyle}>Tu as un micro ? *</div>
                <div style={{ display:"flex", gap:8 }}>
                  {[{v:true,l:"Ô£à Oui"},{v:false,l:"ÔØî Non"}].map(({v,l}) => (
                    <button key={String(v)} onClick={() => setForm(f=>({...f,has_mic:v}))}
                      style={{
                        flex:1, padding:"10px", borderRadius:9, cursor:"pointer",
                        fontFamily:"'Space Grotesk',sans-serif", fontSize:13, fontWeight:600,
                        background: form.has_mic === v ? `${C.primary}25` : "rgba(255,255,255,0.03)",
                        border: `1px solid ${form.has_mic === v ? C.primary : C.border}`,
                        color: form.has_mic === v ? "#fff" : C.muted,
                        transition:"all .15s",
                      }}>
                      {l}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <div style={labelStyle}>Disponible pour un schedule fixe ?</div>
                <div style={{ display:"flex", gap:8 }}>
                  {[{v:true,l:"Ô£à Oui"},{v:false,l:"ÔØî Non"}].map(({v,l}) => (
                    <button key={String(v)} onClick={() => setForm(f=>({...f,schedule_ok:v}))}
                      style={{
                        flex:1, padding:"10px", borderRadius:9, cursor:"pointer",
                        fontFamily:"'Space Grotesk',sans-serif", fontSize:13, fontWeight:600,
                        background: form.schedule_ok === v ? `${C.green}20` : "rgba(255,255,255,0.03)",
                        border: `1px solid ${form.schedule_ok === v ? C.green : C.border}`,
                        color: form.schedule_ok === v ? "#fff" : C.muted,
                        transition:"all .15s",
                      }}>
                      {l}
                    </button>
                  ))}
                </div>
              </div>

              <Field label="Message pour le fondateur (optionnel)">
                <textarea value={form.message}
                  onChange={e => setForm(f=>({...f,message:e.target.value}))}
                  placeholder="Pourquoi veux-tu rejoindre ce clan ? Qu'est-ce qui te distingue ?"
                  rows={3}
                  style={{...inputStyle, resize:"vertical", minHeight:80}} />
              </Field>
            </div>
          </Section>

          {/* Submit */}
          <motion.button
            whileHover={canSubmit ? {scale:1.02} : {}}
            whileTap={canSubmit ? {scale:0.98} : {}}
            onClick={handleSubmit}
            disabled={!canSubmit || saving}
            style={{
              width:"100%", padding:"16px", borderRadius:12, cursor: canSubmit ? "pointer" : "not-allowed",
              background: canSubmit
                ? `linear-gradient(135deg,${C.primary},${C.cyan}80)`
                : "rgba(255,255,255,0.05)",
              border:"none", color: canSubmit ? "#fff" : C.low,
              fontFamily:"'Bebas Neue',cursive", fontSize:20, letterSpacing:3,
              boxShadow: canSubmit ? `0 8px 28px ${C.primary}40` : "none",
              transition:"all .2s",
            }}>
            {saving ? "ÔÅ│ ENVOI..." : "­ƒÄ« ENVOYER MA CANDIDATURE"}
          </motion.button>

          {!canSubmit && (
            <p style={{ textAlign:"center", color:C.muted, fontSize:11, fontFamily:"'JetBrains Mono',monospace", letterSpacing:1 }}>
              * Pseudo + FF ID + R├┤le requis
            </p>
          )}
        </div>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Space+Grotesk:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap');
        select option { background: #0f1117; color: #fff; }
        textarea { font-size: 16px !important; }
        input { font-size: 16px !important; }
      `}</style>
    </div>
  );
}

