        )}
      </AnimatePresence>

      {/* HEADER */}
      <div style={{marginBottom:28}}>
        <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:10,letterSpacing:3,color:cx(.5),marginBottom:6}}>­ƒÄü R├ëCOMPENSES</p>
