// ÔöÇÔöÇÔöÇ MAIN DESIGNER PANEL ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export default function DesignerPanel() {
  const { profile }  = useOutletContext();
  const navigate     = useNavigate();
  const fileRef      = useRef(null);

  const [tab, setTab]             = useState("create");
  const [form, setForm]           = useState(EMPTY_FORM);
  const [imageFile, setImageFile] = useState(null);
  const [imageUrl, setImageUrl]   = useState("");
  const [uploading, setUploading] = useState(false);
  const [saving, setSaving]       = useState(false);
  const [items, setItems]         = useState([]);
  const [loadingItems, setLoadingItems] = useState(false);
  const [notification, setNotification] = useState(null);
  const [editItem, setEditItem]   = useState(null);

  // Access check
  useEffect(() => {
    const role = profile?.role?.toLowerCase?.() || "";
    if (!["designer","admin","super_admin"].includes(role)) {
      navigate("/dashboard");
    }
  }, [profile]);

  useEffect(() => {
    if (tab === "manage") fetchItems();
  }, [tab]);

  const fetchItems = async () => {
    setLoadingItems(true);
    const { data } = await supabase
      .from("store_items")
      .select("*")
      .order("created_at", { ascending: false });
    setItems(data || []);
    setLoadingItems(false);
  };

  const notify = (msg, type = "success") => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 3500);
  };

  const handleImageSelect = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setImageFile(file);
    setImageUrl(URL.createObjectURL(file));
  };

  const uploadImage = async () => {
    if (!imageFile) return null;
    const ext  = imageFile.name.split(".").pop();
    const path = `items/${Date.now()}_${Math.random().toString(36).slice(2)}.${ext}`;
    const { error } = await supabase.storage
      .from("store-items")
      .upload(path, imageFile, { upsert: true });
    if (error) throw new Error("Upload image: " + error.message);
    const { data } = supabase.storage.from("store-items").getPublicUrl(path);
    return data.publicUrl;
  };

  const handleSave = async () => {
    if (!form.name.trim()) { notify("Nom obligatoire", "error"); return; }
    if (form.source === "store" && form.price < 0) { notify("Prix invalide", "error"); return; }
    setSaving(true);

    try {
      let url = imageUrl;

      // Upload image if new file selected
      if (imageFile) {
        setUploading(true);
        url = await uploadImage();
        setUploading(false);
      }

      const payload = {
        ...form,
        image_url:   url || null,
        price:       form.source !== "store" ? 0 : parseInt(form.price) || 0,
        created_by:  profile.id,
        featured:    form.featured || false,
        visible_in_store: form.visible_in_store !== false,
        show_in_profile:  form.show_in_profile !== false,
        show_in_chat:     form.show_in_chat !== false,
        show_in_leaderboard: form.show_in_leaderboard !== false,
        show_in_team:     form.show_in_team !== false,
        // super_admin, admin & designer: auto-approve
        approved:    ["super_admin","admin","designer"].includes(profile.role?.toLowerCase?.()),
        approved_by: ["super_admin","admin","designer"].includes(profile.role?.toLowerCase?.()) ? profile.id : null,
        limited_until: form.limited && form.limited_until ? form.limited_until : null,
      };

      if (editItem) {
        const { error } = await supabase
          .from("store_items")
          .update(payload)
          .eq("id", editItem.id);
        if (error) throw error;
        notify("Ô£à Item mis ├á jour !");
        setEditItem(null);
      } else {
        const { error } = await supabase
          .from("store_items")
          .insert([payload]);
        if (error) throw error;
        notify(
          ["super_admin","admin","designer"].includes(profile.role?.toLowerCase?.())
            ? "Ô£à Item cr├®├® et publi├® !"
            : "Ô£à Item cr├®├® ÔÇö en attente d'approbation"
        );
      }

      setForm(EMPTY_FORM);
      setImageFile(null);
      setImageUrl("");
      if (fileRef.current) fileRef.current.value = "";

    } catch (err) {
      notify(err.message || "Erreur", "error");
    }
    setSaving(false);
  };

  const toggleActive = async (item) => {
    await supabase.from("store_items")
      .update({ active: !item.active })
