                        </div>
                      </div>
                    ) : (
                      <div>
                        <div style={{ fontSize: 36, marginBottom: 8 }}>­ƒôü</div>
                        <p style={{ color: "rgba(255,255,255,0.5)", fontSize: 13 }}>Cliquer pour choisir une image</p>
