import { Trophy, Crosshair, Coins, Users, Calendar, Flame, Medal } from "lucide-react";

/* ÔöÇÔöÇ helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
const fmt   = n => n >= 1_000_000 ? (n/1_000_000).toFixed(1)+"M" : n >= 1_000 ? (n/1_000).toFixed(1)+"K" : String(n ?? 0);
const ease  = [0.32, 0, 0.15, 1];

const MEDAL_CFG = {
  1: { bg: "rgba(232,160,32,0.12)", border: "rgba(232,160,32,0.35)", glow: "rgba(232,160,32,0.20)", text: "#E8A020", label: "Champion", icon: "­ƒÑç" },
  2: { bg: "rgba(192,192,210,0.10)", border: "rgba(192,192,210,0.28)", glow: "rgba(192,192,210,0.14)", text: "#C0C0D2", label: "2├¿me place", icon: "­ƒÑê" },
  3: { bg: "rgba(180,100,50,0.10)", border: "rgba(180,100,50,0.28)", glow: "rgba(180,100,50,0.14)", text: "#C87840", label: "3├¿me place", icon: "­ƒÑë" },
};

const PERIODS = [
  { key: "weekly",  label: "Cette semaine", icon: <Flame size={13} /> },
  { key: "monthly", label: "Ce mois",       icon: <Calendar size={13} /> },
  { key: "alltime", label: "Tout le temps", icon: <Trophy size={13} /> },
];

/* ÔöÇÔöÇ data hook ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function useLeaderboard(period) {
  const [players, setPlayers] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetch = useCallback(async () => {
    setLoading(true);
    try {
      let statsData;

      if (period === "alltime") {
        const { data } = await supabase
          .from("player_stats")
          .select("user_id, total_points, kills, tournaments_played, wins, best_position")
          .gt("tournaments_played", 0)
          .order("total_points", { ascending: false });
        statsData = data;
      } else {
        const days  = period === "weekly" ? 7 : 30;
        const since = new Date(Date.now() - days * 86_400_000).toISOString();
        const { data: results } = await supabase
          .from("match_results")
          .select("user_id, kills, points, estimated_coins, placement")
          .eq("status", "verified")
          .gte("submitted_at", since);

        if (!results?.length) { setPlayers([]); setLoading(false); return; }

        const agg = {};
        results.forEach(r => {
          if (!agg[r.user_id]) agg[r.user_id] = { user_id: r.user_id, total_points: 0, kills: 0, tournaments_played: 0, wins: 0, best_position: null };
          agg[r.user_id].total_points      += (r.points || 0);
          agg[r.user_id].kills             += (r.kills  || 0);
          agg[r.user_id].tournaments_played += 1;
          if (r.placement === 1) agg[r.user_id].wins += 1;
          if (!agg[r.user_id].best_position || r.placement < agg[r.user_id].best_position)
            agg[r.user_id].best_position = r.placement;
        });
        statsData = Object.values(agg).sort((a, b) => b.total_points - a.total_points);
      }

      if (!statsData?.length) { setPlayers([]); setLoading(false); return; }

      const ids = statsData.map(s => s.user_id);
      const [{ data: profiles }, { data: wallets }] = await Promise.all([
        supabase.from("profiles").select("id, full_name, free_fire_id, avatar_url").in("id", ids),
        supabase.from("wallets").select("user_id, balance").in("user_id", ids),
      ]);

      const pm = Object.fromEntries((profiles || []).map(p => [p.id, p]));
      const wm = Object.fromEntries((wallets  || []).map(w => [w.user_id, w.balance || 0]));
      const sm = Object.fromEntries(statsData.map(s => [s.user_id, s]));

      const result = ids
        .filter(id => pm[id])
        .map(id => ({
          id,
          name:    pm[id]?.full_name    || "Joueur",
          ffId:    pm[id]?.free_fire_id || "ÔÇö",
          avatar:  pm[id]?.avatar_url,
          coins:   wm[id] || 0,
          points:  sm[id]?.total_points || 0,
          kills:   sm[id]?.kills || 0,
          matches: sm[id]?.tournaments_played || 0,
          wins:    sm[id]?.wins || 0,
          winRate: sm[id]?.tournaments_played > 0
            ? Math.round((sm[id].wins / sm[id].tournaments_played) * 100)
            : 0,
        }))
        .sort((a, b) => b.points !== a.points ? b.points - a.points : b.kills - a.kills)
        .map((p, i) => ({ ...p, rank: i + 1 }));

      setPlayers(result);
    } catch (e) {
      console.error("leaderboard error:", e);
    }
    setLoading(false);
  }, [period]);

  useEffect(() => {
    fetch();
    const ch = supabase
      .channel("lb-rt")
      .on("postgres_changes", { event: "UPDATE", schema: "public", table: "player_stats" }, fetch)
      .subscribe();
    return () => supabase.removeChannel(ch);
  }, [period, fetch]);

  return { players, loading };
}

