import { useState, useRef } from "react";
import { useNavigate, Link } from "react-router-dom";
import { supabase } from "../lib/supabase";
import { motion } from "framer-motion";
import { Mail, Lock, Eye, EyeOff, AlertCircle } from "lucide-react";
import "./auth/auth.css";

const MAX_ATTEMPTS = 5;
const LOCKOUT_MS   = 30_000;

function validate(email, password) {
  const e = {};
  if (!email.trim())                     e.email    = "Email requis";
  else if (!/\S+@\S+\.\S+/.test(email)) e.email    = "Email invalide";
  if (!password)                         e.password = "Mot de passe requis";
  else if (password.length < 6)         e.password = "Minimum 6 caract├¿res";
  return e;
}

export default function Login() {
  const navigate = useNavigate();
  const [email,       setEmail]    = useState("");
  const [password,    setPass]     = useState("");
  const [showPass,    setShowPass] = useState(false);
  const [loading,     setLoading]  = useState(false);
  const [errors,      setErrors]   = useState({});
  const [globalErr,   setGlobal]   = useState("");
  const [lockSecs,    setLockSecs] = useState(0);

  const attempts    = useRef(0);
  const lockedUntil = useRef(0);

  const startCountdown = () => {
    const tick = () => {
      const rem = Math.ceil((lockedUntil.current - Date.now()) / 1000);
      if (rem > 0) { setLockSecs(rem); setTimeout(tick, 1000); }
      else         { setLockSecs(0);   setGlobal(""); }
    };
    tick();
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (lockSecs > 0) return;

    const errs = validate(email, password);
    setErrors(errs);
    if (Object.keys(errs).length) return;

    setLoading(true);
    setGlobal("");

    try {
      const { error } = await supabase.auth.signInWithPassword({ email: email.trim(), password });
      if (error) throw error;
      attempts.current = 0;
      navigate("/dashboard");
    } catch {
      attempts.current++;
      if (attempts.current >= MAX_ATTEMPTS) {
        lockedUntil.current = Date.now() + LOCKOUT_MS;
        startCountdown();
        setGlobal(`Trop de tentatives. R├®essayez dans ${LOCKOUT_MS / 1000}s.`);
      } else {
        setGlobal("Email ou mot de passe incorrect.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-video-root">
      {/* ÔöÇÔöÇ Video background ÔöÇÔöÇ */}
      <div className="auth-video-bg" aria-hidden="true">
        <div className="auth-video-overlay" />
