                placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                value={password}
                onChange={e => setPass(e.target.value)}
                autoComplete="current-password"
              />
              <button
                type="button"
                className="ui-input-action"
                onClick={() => setShowPass(v => !v)}
                aria-label={showPass ? "Hide password" : "Show password"}
              >
                {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
            {errors.password && <p className="ui-field-error">{errors.password}</p>}
            <div style={{ textAlign: "right", marginTop: 7 }}>
              <Link to="/reset-password" className="auth-link" style={{ fontSize: 12 }}>
                Forgot password?
              </Link>
            </div>
          </div>

          {/* Submit */}
          <button
            type="submit"
            className="ui-btn ui-btn--primary ui-btn--lg ui-btn-full"
            disabled={loading || lockSecs > 0}
          >
            {loading && <span className="ui-btn-spinner" />}
            {loading ? "Signing inÔÇª" : lockSecs > 0 ? `Locked (${lockSecs}s)` : "Enter the Arena ÔåÆ"}
          </button>
        </form>

        <div className="auth-divider">
          <span className="auth-divider-line" />
          <span className="auth-divider-text">or</span>
          <span className="auth-divider-line" />
        </div>

        <p className="auth-form-footer">
          No account yet?{" "}
          <Link to="/register">Join for free ÔåÆ</Link>
        </p>
      </motion.div>

      {/* Footer */}
      <p className="auth-video-footer">┬® 2026 CipherPool ÔÇö All rights reserved</p>
    </div>
  );
}

