    } catch {
      setArticles(DUMMY);
    } finally {
      setLoading(false);
    }
  };

  const openArticle = (a) => {
    setSelected(a);
    // Incr├®menter vues sans bloquer
    supabase.from("news").update({ views: (a.views || 0) + 1 }).eq("id", a.id).catch(() => {});
  };

  const featured  = articles.find(a => a.featured) || articles[0];
  const filtered  = articles.filter(a => {
    const matchCat    = filter === "all" || a.category === filter;
    const matchSearch = !search || a.title.toLowerCase().includes(search.toLowerCase()) || a.excerpt?.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch && a.id !== featured?.id;
  });

  if (loading) return (
    <div style={{ minHeight:"80vh", display:"flex", alignItems:"center", justifyContent:"center" }}>
      <motion.div animate={{ rotate:360 }} transition={{ duration:1, repeat:Infinity, ease:"linear" }}
        style={{ width:36, height:36, border:`2px solid ${cx(.12)}`, borderTopColor:CYAN, borderRadius:"50%" }}/>
