    <div className="news-page">
      {/* HEADER */}
      <div style={{ marginBottom:28 }}>
        <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:10, letterSpacing:3, color:cx(.5), marginBottom:6 }}>­ƒô░ ACTUALIT├ëS</p>
        <h1 style={{ fontFamily:"Bebas Neue,cursive", fontSize:46, letterSpacing:3, margin:0, color:"#fff" }}>
          CIPHER<span style={{ color:CYAN }}>NEWS</span>
        </h1>
      </div>

      {/* FEATURED */}
      {featured && (
        <motion.div initial={{ opacity:0, y:20 }} animate={{ opacity:1, y:0 }} whileHover={{ y:-3 }}
          onClick={() => openArticle(featured)}
          style={{ cursor:"pointer", marginBottom:28, position:"relative", overflow:"hidden", borderRadius:18, background:`linear-gradient(135deg,${CARD},rgba(0,212,255,.06))`, border:`1px solid ${cx(.18)}`, boxShadow:`0 0 40px ${cx(.08)},0 24px 60px rgba(0,0,0,.5)`, padding:"clamp(18px,4vw,36px)" }}>
          <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:`linear-gradient(90deg,${CYAN},${INDIGO},${VIOLET})` }}/>
          <div style={{ position:"absolute", top:16, right:20 }}>
            <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:"#000", background:`linear-gradient(135deg,${CYAN},${INDIGO})`, padding:"4px 12px", borderRadius:99, fontWeight:700, letterSpacing:1 }}>Ôÿà ├Ç LA UNE</span>
          </div>
          <div style={{ maxWidth:680 }}>
            {CAT[featured.category] && (
              <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:CAT[featured.category].color, background:CAT[featured.category].bg, padding:"3px 10px", borderRadius:6, letterSpacing:1, marginBottom:14, display:"inline-block" }}>
                {CAT[featured.category].label}
              </span>
            )}
            <h2 style={{ fontFamily:"Bebas Neue,cursive", fontSize:34, letterSpacing:2, color:"#fff", lineHeight:1.15, margin:"10px 0 12px" }} className="news-title">
              {featured.title}
            </h2>
            <p style={{ fontSize:14, color:"rgba(255,255,255,.45)", lineHeight:1.7, marginBottom:20 }}>{featured.excerpt}</p>
            <div style={{ display:"flex", gap:16, alignItems:"center" }}>
              <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:"rgba(255,255,255,.25)" }}>­ƒòÉ {timeAgo(featured.published_at)}</span>
              <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:"rgba(255,255,255,.25)" }}>­ƒæü {featured.views || 0}</span>
              {featured.tags?.slice(0,3).map(t => (
                <span key={t} style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:cx(.5), background:cx(.06), border:`1px solid ${cx(.1)}`, padding:"2px 8px", borderRadius:5 }}>#{t}</span>
              ))}
            </div>
          </div>
        </motion.div>
      )}

      {/* FILTERS */}
      <div style={{ display:"flex", gap:10, marginBottom:22, flexWrap:"wrap", alignItems:"center" }}>
        <div style={{ display:"flex", gap:4, background:cx(.04), borderRadius:10, padding:4 }}>
          {[["all","TOUS"],["tournament","TOURNOIS"],["update","UPDATES"],["player","JOUEURS"],["team","├ëQUIPES"],["general","G├ëN├ëRAL"]].map(([k,l]) => (
            <button key={k} onClick={() => setFilter(k)}
              style={{ padding:"7px 14px", borderRadius:7, border:"none", cursor:"pointer", fontFamily:"JetBrains Mono,monospace", fontSize:8, letterSpacing:1.5, background:filter===k?`linear-gradient(135deg,${CYAN},${INDIGO})`:"transparent", color:filter===k?"#000":"rgba(255,255,255,.4)", fontWeight:filter===k?700:400, transition:"all .2s" }}>
              {l}
            </button>
          ))}
        </div>
        <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Rechercher..."
          style={{ flex:1, minWidth:"min(180px,100%)", padding:"10px 16px", borderRadius:10, background:cx(.05), border:`1px solid ${cx(.1)}`, color:"#fff", fontFamily:"Space Grotesk,sans-serif", fontSize:13, outline:"none" }}/>
      </div>

      {/* GRID */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(min(300px,100%),1fr))", gap:14 }}>
        {filtered.map((a, i) => {
          const cat = CAT[a.category] || CAT.general;
          return (
            <motion.div key={a.id} initial={{ opacity:0, y:16 }} animate={{ opacity:1, y:0 }} transition={{ delay:i*.05 }}
              whileHover={{ y:-4, transition:{ duration:.15 } }} onClick={() => openArticle(a)}
              className="news-card"
              style={{ cursor:"pointer", position:"relative", overflow:"hidden", background:CARD, border:`1px solid ${cx(.09)}`, borderRadius:14, padding:"22px 22px", boxShadow:"0 4px 20px rgba(0,0,0,.4)", transition:"border-color .22s" }}>
              <div style={{ position:"absolute", top:0, left:0, right:0, height:2, background:`linear-gradient(90deg,transparent,${cat.color},transparent)`, opacity:.6 }}/>
              <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:cat.color, background:cat.bg, padding:"3px 10px", borderRadius:6, letterSpacing:1, marginBottom:12, display:"inline-block" }}>
                {cat.label}
              </span>
              <h3 style={{ fontSize:16, fontWeight:700, color:"#fff", lineHeight:1.35, margin:"10px 0 10px", transition:"color .2s" }} className="news-title">
                {a.title}
              </h3>
              <p style={{ fontSize:12, color:"rgba(255,255,255,.35)", lineHeight:1.6, marginBottom:14 }}>
                {a.excerpt?.slice(0,100)}{a.excerpt?.length > 100 ? "..." : ""}
              </p>
              <div style={{ display:"flex", gap:12, alignItems:"center" }}>
                <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:"rgba(255,255,255,.2)" }}>­ƒòÉ {timeAgo(a.published_at)}</span>
                <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:"rgba(255,255,255,.2)" }}>­ƒæü {a.views || 0}</span>
                <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:cat.color, marginLeft:"auto" }}>LIRE ÔåÆ</span>
              </div>
            </motion.div>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div style={{ textAlign:"center", padding:"60px 0" }}>
          <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:10, letterSpacing:4, color:"rgba(255,255,255,.2)" }}>AUCUN ARTICLE TROUV├ë</p>
        </div>
      )}
    </div>

    {/* ARTICLE MODAL */}
    <AnimatePresence>
      {selected && (
        <motion.div initial={{ opacity:0 }} animate={{ opacity:1 }} exit={{ opacity:0 }}
          style={{ position:"fixed", inset:0, background:"rgba(2,8,23,.92)", backdropFilter:"blur(16px)", zIndex:50, overflowY:"auto", padding:"40px 20px" }}
          onClick={() => setSelected(null)}>
          <motion.div initial={{ y:40, opacity:0 }} animate={{ y:0, opacity:1 }} exit={{ y:40, opacity:0 }}
            onClick={e => e.stopPropagation()}
            style={{ maxWidth:700, margin:"0 auto", background:CARD, border:`1px solid ${cx(.14)}`, borderRadius:20, boxShadow:`0 0 60px ${cx(.1)},0 32px 80px rgba(0,0,0,.7)`, overflow:"hidden" }}>
            <div style={{ height:3, background:`linear-gradient(90deg,${CYAN},${INDIGO},${VIOLET})` }}/>
            <div style={{ padding:"clamp(14px,4vw,28px) clamp(14px,4vw,32px)" }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:16 }}>
                {CAT[selected.category] && (
                  <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:CAT[selected.category].color, background:CAT[selected.category].bg, padding:"4px 12px", borderRadius:6, letterSpacing:1 }}>
                    {CAT[selected.category].label}
                  </span>
                )}
                <button onClick={() => setSelected(null)}
                  style={{ background:"none", border:`1px solid ${cx(.12)}`, color:"rgba(255,255,255,.4)", borderRadius:8, padding:"6px 14px", cursor:"pointer", fontFamily:"JetBrains Mono,monospace", fontSize:9 }}>
                  Ô£ò FERMER
                </button>
              </div>
              <h2 style={{ fontFamily:"Bebas Neue,cursive", fontSize:30, letterSpacing:2, color:"#fff", lineHeight:1.2, marginBottom:12 }}>
                {selected.title}
              </h2>
              <div style={{ display:"flex", gap:14, marginBottom:24, flexWrap:"wrap" }}>
                <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:"rgba(255,255,255,.25)" }}>­ƒòÉ {timeAgo(selected.published_at)}</span>
                <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:"rgba(255,255,255,.25)" }}>­ƒæü {selected.views || 0} vues</span>
                {selected.tags?.map(t => (
                  <span key={t} style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:cx(.5), background:cx(.06), border:`1px solid ${cx(.1)}`, padding:"2px 8px", borderRadius:5 }}>#{t}</span>
                ))}
              </div>
              <div style={{ height:1, background:cx(.06), marginBottom:24 }}/>
              <p style={{ fontSize:14, color:"rgba(255,255,255,.6)", lineHeight:1.9 }}>
                {selected.content || selected.excerpt}
              </p>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  </>);
}

import { useState, useEffect } from "react";
import { useOutletContext } from "react-router-dom";
import { motion } from "framer-motion";
import { supabase } from "../lib/supabase";

const CYAN="#00d4ff",INDIGO="#818cf8",VIOLET="#a78bfa",GREEN="#10b981",RED="#f43f5e",AMBER="#fbbf24",BG="#020817",CARD="#0a1628";
const cx=a=>`rgba(0,212,255,${a})`,gx=a=>`rgba(16,185,129,${a})`,rx=a=>`rgba(244,63,94,${a})`,ax=a=>`rgba(251,191,36,${a})`;

function StatCard({label,value,sub,color,icon,delay=0}){
  return(
    <motion.div initial={{opacity:0,y:16}} animate={{opacity:1,y:0}} transition={{delay,type:"spring",stiffness:180}}
      whileHover={{y:-4,transition:{duration:.15}}}
      style={{position:"relative",overflow:"hidden",background:CARD,border:`1px solid ${color}20`,borderRadius:14,padding:"22px 20px",
        boxShadow:`0 0 20px ${color}10,0 4px 20px rgba(0,0,0,.4)`,transition:"all .22s"}}>
      <div style={{position:"absolute",top:0,left:0,right:0,height:2,background:`linear-gradient(90deg,transparent,${color},transparent)`,opacity:.6}}/>
      <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:8,letterSpacing:2.5,color:"rgba(255,255,255,.22)",marginBottom:10}}>{icon} {label}</p>
      <p style={{fontFamily:"Bebas Neue,cursive",fontSize:40,color:color,lineHeight:1,marginBottom:4,textShadow:`0 0 20px ${color}50`}}>{value}</p>
      {sub&&<p style={{fontFamily:"JetBrains Mono,monospace",fontSize:9,color:"rgba(255,255,255,.25)"}}>{sub}</p>}
    </motion.div>
  );
}

function Bar({value,max,color}){
  const pct=max>0?Math.min(100,(value/max)*100):0;
  return(
    <div style={{height:6,background:"rgba(255,255,255,.05)",borderRadius:99,overflow:"hidden"}}>
      <motion.div initial={{width:0}} animate={{width:`${pct}%`}} transition={{duration:1.2,ease:[.22,1,.36,1]}}
        style={{height:"100%",background:color,borderRadius:99,boxShadow:`0 0 8px ${color}80`}}/>
    </div>
  );
}

const POSITIONS={"1er":"­ƒÑç","2├¿me":"­ƒÑê","3├¿me":"­ƒÑë"};

export default function PlayerStats(){
  const{profile}=useOutletContext();
  const[stats,setStats]=useState(null);
  const[history,setHistory]=useState([]);
  const[loading,setLoading]=useState(true);
  const[tab,setTab]=useState("stats");

  useEffect(()=>{fetchData();},[profile?.id]);

  const fetchData=async()=>{
    if(!profile?.id){setLoading(false);return;}
    setLoading(true);
    try{
      // Fetch stats + real match history from match_results
      const[{data:sData},{data:matchData}]=await Promise.all([
        supabase.from("player_stats").select("*").eq("user_id",profile.id).maybeSingle(),
        supabase.from("match_results")
          .select("id, tournament_id, placement, kills, points, estimated_coins, status, submitted_at")
          .eq("user_id", profile.id)
          .eq("status", "verified")
          .order("submitted_at", {ascending:false})
          .limit(20)
      ]);

      // Enrich match history with tournament names
      let enrichedHistory = [];
      if (matchData?.length) {
        const tIds = [...new Set(matchData.map(m => m.tournament_id))];
        const { data: tours } = await supabase.from("tournaments")
          .select("id, name, game_type").in("id", tIds);
        const tMap = Object.fromEntries((tours||[]).map(t=>[t.id,t]));
        enrichedHistory = matchData.map(m => ({
          ...m,
          tournament: tMap[m.tournament_id] || { name: "Tournoi", game_type: "BR" },
          position: m.placement,
          prize_won: m.estimated_coins || 0,
        }));
      }

      setStats(sData||{kills:0,wins:0,tournaments_played:0,total_points:0});
      setHistory(enrichedHistory);
    }catch(e){console.error(e);}
    finally{setLoading(false);}
  };

  const s=stats||{};
  const wr=s.tournaments_played>0?Math.round(((s.wins||0)/s.tournaments_played)*100):0;
  const kd = s.kd_ratio ? parseFloat(s.kd_ratio).toFixed(2) : s.tournaments_played > 0 ? (s.kills/s.tournaments_played).toFixed(2) : '0.00';

  const displayHistory = history;

  if(loading)return(
    <div style={{minHeight:"80vh",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <motion.div animate={{rotate:360}} transition={{duration:1,repeat:Infinity,ease:"linear"}}
        style={{width:36,height:36,border:`2px solid ${cx(.12)}`,borderTopColor:CYAN,borderRadius:"50%"}}/>
    </div>
  );

  return(<>
    <style>{`
      @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Space+Grotesk:wght@400;500;600;700;800&family=JetBrains+Mono:wght@400;500;600&display=swap');
      .ps{font-family:Space Grotesk,sans-serif;color:rgba(255,255,255,.88);min-height:100vh;background:${BG};padding:32px}
      ::-webkit-scrollbar{width:4px}::-webkit-scrollbar-thumb{background:${cx(.22)};border-radius:99px}
    `}</style>

    <div className="ps">
      {/* HEADER */}
      <div style={{marginBottom:28}}>
        <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:10,letterSpacing:3,color:cx(.5),marginBottom:6}}>­ƒôè STATISTIQUES JOUEUR</p>
        <div style={{display:"flex",alignItems:"flex-end",gap:18,flexWrap:"wrap"}}>
          {profile?.avatar_url
            ?<img src={profile.avatar_url} style={{width:64,height:64,borderRadius:14,border:`2px solid ${cx(.3)}`,objectFit:"cover"}}/>
            :<div style={{width:64,height:64,borderRadius:14,border:`2px solid ${cx(.3)}`,background:cx(.1),display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"Bebas Neue,cursive",fontSize:28,color:CYAN}}>
              {(profile?.username||"?")[0].toUpperCase()}
            </div>}
          <div>
            <h1 style={{fontFamily:"Bebas Neue,cursive",fontSize:40,letterSpacing:3,margin:0,color:"#fff",lineHeight:1}}>
              {profile?.username||"JOUEUR"} <span style={{color:CYAN,fontSize:24}}>#{s.rank||"-"}</span>
            </h1>
            <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:10,color:"rgba(255,255,255,.3)",marginTop:4}}>
              {s.tournaments_played||0} TOURNOIS ┬À SAISON 1
            </p>
          </div>
        </div>
      </div>

      {/* TABS */}
      <div style={{display:"flex",gap:4,background:cx(.04),borderRadius:10,padding:4,marginBottom:24,width:"fit-content"}}>
        {[["stats","STATISTIQUES"],["history","HISTORIQUE"]].map(([k,l])=>(
          <button key={k} onClick={()=>setTab(k)}
            style={{padding:"9px 22px",borderRadius:7,border:"none",cursor:"pointer",fontFamily:"JetBrains Mono,monospace",fontSize:10,letterSpacing:1.5,
              background:tab===k?`linear-gradient(135deg,${CYAN},${INDIGO})`:"transparent",
              color:tab===k?"#000":"rgba(255,255,255,.4)",fontWeight:tab===k?700:400,transition:"all .2s"}}>
            {l}
          </button>
        ))}
      </div>

      {/* STATS TAB */}
      {tab==="stats"&&(<>
        {/* KPI GRID */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:12,marginBottom:24}}>
          <StatCard label="KILLS TOTAL" value={s.kills||0} color={RED} icon="­ƒÄ»" delay={0}/>
          <StatCard label="VICTOIRES" value={s.wins||0} color={AMBER} icon="­ƒÅå" delay={.05}/>
          <StatCard label="TOP 3" value={s.top3_finishes||0} color={GREEN} icon="­ƒÑë" delay={.1}/>
          <StatCard label="K/D RATIO" value={kd} color={CYAN} icon="ÔÜö´©Å" delay={.15}/>
          <StatCard label="WIN RATE" value={`${wr}%`} color={INDIGO} icon="­ƒôê" delay={.2}/>
          <StatCard label="MVP" value={s.mvp_count||0} color={VIOLET} icon="Ô¡É" delay={.25}/>
          <StatCard label="GAINS TOTAUX" value={`${s.total_earnings||0}`} sub="COINS" color={AMBER} icon="­ƒÆÄ" delay={.3}/>
          <StatCard label="MEILLEURE POS." value={s.best_position?`#${s.best_position}`:"-"} color={GREEN} icon="­ƒÅà" delay={.35}/>
        </div>

        {/* PERFORMANCE BARS */}
        <motion.div initial={{opacity:0,y:14}} animate={{opacity:1,y:0}} transition={{delay:.4}}
          style={{background:CARD,border:`1px solid ${cx(.09)}`,borderRadius:14,padding:"24px 24px",marginBottom:16}}>
          <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:9,letterSpacing:2.5,color:"rgba(255,255,255,.22)",marginBottom:20}}>PERFORMANCE GLOBALE</p>
          <div style={{display:"flex",flexDirection:"column",gap:16}}>
            {[
              ["Win Rate",wr,100,AMBER,"­ƒÅå"],
              ["Kills par match",Math.min(100,((s.kills||0)/Math.max(1,s.tournaments_played||1))*10),100,RED,"­ƒÄ»"],
              ["Top 3 Rate",s.tournaments_played>0?Math.round(((s.top3_finishes||0)/s.tournaments_played)*100):0,100,GREEN,"­ƒÑë"],
              ["MVP Rate",s.tournaments_played>0?Math.round(((s.mvp_count||0)/s.tournaments_played)*100):0,100,VIOLET,"Ô¡É"],
            ].map(([l,v,m,c,ico])=>(
              <div key={l}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}>
                  <span style={{fontFamily:"Space Grotesk,sans-serif",fontSize:12,color:"rgba(255,255,255,.5)"}}>{ico} {l}</span>
                  <span style={{fontFamily:"JetBrains Mono,monospace",fontSize:11,color:c}}>{Math.round(v)}%</span>
                </div>
                <Bar value={v} max={m} color={c}/>
              </div>
            ))}
          </div>
        </motion.div>
      </>)}

      {/* HISTORY TAB */}
      {tab==="history"&&(
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {displayHistory.map((match,i)=>{
            const pos=match.position||"-";
            const isWin=pos===1;
            const isTop3=pos<=3;
            const posColor=pos===1?AMBER:pos===2?GREEN:pos===3?CYAN:INDIGO;
            const tn=match.tournament||{};
            return(
              <motion.div key={match.id} initial={{opacity:0,x:-14}} animate={{opacity:1,x:0}} transition={{delay:i*.05}}
                style={{position:"relative",overflow:"hidden",background:CARD,border:`1px solid ${isWin?ax(.2):cx(.08)}`,borderRadius:14,padding:"18px 22px",
                  boxShadow:isWin?`0 0 20px ${ax(.1)}`:"0 4px 16px rgba(0,0,0,.4)"}}>
                {isWin&&<div style={{position:"absolute",top:0,left:0,right:0,height:2,background:`linear-gradient(90deg,transparent,${AMBER},transparent)`}}/>}
                <div style={{display:"flex",alignItems:"center",gap:16,flexWrap:"wrap"}}>
                  <div style={{width:52,height:52,borderRadius:12,background:`${posColor}15`,border:`2px solid ${posColor}30`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                    <span style={{fontFamily:"Bebas Neue,cursive",fontSize:22,color:posColor,lineHeight:1}}>#{pos}</span>
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <p style={{fontSize:14,fontWeight:600,color:"#fff",marginBottom:4}}>{tn.name||"Tournoi"}</p>
                    <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
                      <span style={{fontFamily:"JetBrains Mono,monospace",fontSize:9,color:"rgba(255,255,255,.25)"}}>­ƒòÉ {tn.created_at?new Date(tn.created_at).toLocaleDateString("fr-FR"):"-"}</span>
                      {tn.game_type&&<span style={{fontFamily:"JetBrains Mono,monospace",fontSize:9,color:cx(.5)}}>{tn.game_type}</span>}
                    </div>
                  </div>
                  <div style={{display:"flex",gap:16,flexShrink:0}}>
                    <div style={{textAlign:"center"}}>
                      <p style={{fontFamily:"Bebas Neue,cursive",fontSize:20,color:RED,lineHeight:1}}>{match.kills||0}</p>
                      <p style={{fontFamily:"JetBrains Mono,monospace",fontSize:8,color:"rgba(255,255,255,.2)"}}>KILLS</p>
                    </div>
