import { useState, useEffect, useRef } from "react";
import { useOutletContext, Link, useSearchParams } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { useProfileData } from "../hooks/useProfileData";
import { usePermissions } from "../utils/permissions";
import { supabase } from "../lib/supabase";

/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
   CIPHERPOOL ÔÇö PROFILE PAGE
   Design System: orange #FF4F00, dark bg, Barlow Condensed + Inter
   ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */

// ÔöÇÔöÇ Design tokens ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const ACCENT = "#FF4F00";
const GREEN  = "#10b981";
const AMBER  = "#fbbf24";
const RED    = "#ef4444";

const ax = a => `rgba(255,79,0,${a})`;
const gx = a => `rgba(16,185,129,${a})`;
const rx = a => `rgba(239,68,68,${a})`;

const CARD = "rgba(16,16,26,0.90)";
const BG   = "var(--bg)";

// Sanitize user input
const sanitize = (str, maxLen = 500) => {
  if (!str) return "";
  return str
    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;").replace(/'/g, "&#x27;")
    .trim().slice(0, maxLen);
};

// ÔöÇÔöÇ Rarity system for store items (keep distinct colors) ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const RARITY = {
  legendary:{ color:"#FF4F00", glow:ax(.55), bg:ax(.08),  border:ax(.25),  label:"L├ëGENDAIRE" },
  epic:     { color:"#a78bfa", glow:"rgba(167,139,250,.55)", bg:"rgba(167,139,250,.1)",  border:"rgba(167,139,250,.3)",  label:"├ëPIQUE"     },
  rare:     { color:"#818cf8", glow:"rgba(129,140,248,.55)", bg:"rgba(129,140,248,.1)",  border:"rgba(129,140,248,.25)", label:"RARE"       },
  common:   { color:"#94a3b8", glow:"rgba(148,163,184,.3)", bg:"rgba(148,163,184,.07)", border:"rgba(148,163,184,.2)",  label:"COMMUN"     },
};

// ÔöÇÔöÇ Role metadata ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const ROLE_META = {
  super_admin:{ label:"SUPER ADMIN", color:ACCENT,   glow:ax(.35) },
  admin:      { label:"ADMIN",       color:"#FF7A33", glow:"rgba(255,122,51,.35)" },
  founder:    { label:"FONDATEUR",   color:AMBER,     glow:"rgba(251,191,36,.35)" },
  designer:   { label:"DESIGNER",    color:GREEN,     glow:gx(.35) },
  user:       { label:"MEMBRE",      color:"#94a3b8", glow:"transparent" },
};

// ÔöÇÔöÇ Tab definitions ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const TABS = [
  { key:"stats",        label:"Statistiques", icon:"­ƒôè", color:ACCENT },
  { key:"history",      label:"Historique",   icon:"­ƒÅå", color:"#a78bfa" },
  { key:"achievements", label:"Succ├¿s",       icon:"­ƒÄû´©Å", color:"#818cf8" },
  { key:"wallet",       label:"Finances",     icon:"­ƒÆÄ", color:GREEN  },
  { key:"edit",         label:"Mon profil",   icon:"Ô£Å´©Å", color:AMBER  },
];

/* ÔöÇÔöÇ Animated canvas background ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function HeroBg() {
  const ref = useRef(null);
  useEffect(() => {
    const c = ref.current; if (!c) return;
    const ctx = c.getContext("2d");
    let raf, t = 0;
    const resize = () => { c.width = c.offsetWidth; c.height = c.offsetHeight; };
    resize();
    const ro = new ResizeObserver(resize); ro.observe(c);
    const orbs = [
      { cx:.12, cy:.6,  r:.55, vx:.0009,  vy:.0006,  color:[255,79,0],   a:.09 },
      { cx:.82, cy:.3,  r:.42, vx:-.0007, vy:.0007,  color:[255,120,40], a:.07 },
      { cx:.5,  cy:.85, r:.38, vx:.0006,  vy:-.0008, color:[232,50,0],   a:.06 },
      { cx:.92, cy:.82, r:.28, vx:-.0007, vy:-.0005, color:[255,160,80], a:.04 },
    ];
    const draw = () => {
      t++;
      ctx.clearRect(0,0,c.width,c.height);
      orbs.forEach(o => {
        o.cx += o.vx * Math.sin(t*.008); o.cy += o.vy * Math.cos(t*.006);
        if (o.cx<-.1||o.cx>1.1) o.vx*=-1;
        if (o.cy<-.1||o.cy>1.1) o.vy*=-1;
        const x=o.cx*c.width, y=o.cy*c.height;
        const r=o.r*Math.max(c.width,c.height)*(1+.07*Math.sin(t*.014));
        const a=o.a*(1+.15*Math.sin(t*.02));
        const [R,G,B]=o.color;
        const g=ctx.createRadialGradient(x,y,0,x,y,r);
        g.addColorStop(0,  `rgba(${R},${G},${B},${a})`);
        g.addColorStop(.45,`rgba(${R},${G},${B},${a*.4})`);
        g.addColorStop(1,  `rgba(${R},${G},${B},0)`);
        ctx.fillStyle=g; ctx.fillRect(0,0,c.width,c.height);
      });
      raf=requestAnimationFrame(draw);
    };
    draw();
    return ()=>{ cancelAnimationFrame(raf); ro.disconnect(); };
  },[]);
  return <canvas ref={ref} style={{ position:"absolute",inset:0,width:"100%",height:"100%",pointerEvents:"none" }} />;
}

/* ÔöÇÔöÇ Animated counter ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function N({ v, sfx="" }) {
  const [d, setD] = useState(0);
  const r = useRef(null);
  useEffect(()=>{
    const end=parseFloat(String(v).replace(/[^\d.]/g,""))||0;
    if(!end){setD(0);return;}
    const s=performance.now(),dur=1150;
    const step=ts=>{
      const p=Math.min((ts-s)/dur,1);
      setD(Math.floor((1-Math.pow(1-p,3))*end));
      if(p<1) r.current=requestAnimationFrame(step); else setD(end);
    };
    r.current=requestAnimationFrame(step);
    return()=>cancelAnimationFrame(r.current);
  },[v]);
  const sv=String(v);
  return <>{sv.includes(".")?parseFloat(v).toFixed(2):d.toLocaleString("fr-FR")}{sv.includes("%")?"%":sfx}</>;
}

/* ÔöÇÔöÇ Glass card ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function G({ children, style, ac }) {
  const [h,setH]=useState(false);
  return (
    <div onMouseEnter={()=>setH(true)} onMouseLeave={()=>setH(false)}
      style={{ position:"relative", overflow:"hidden",
        background: h&&ac ? `linear-gradient(135deg,${ac}09,${CARD})` : CARD,
        backdropFilter:"blur(16px)",
        border:`1px solid ${h&&ac?ac+"35":"rgba(255,255,255,0.08)"}`,
        borderRadius:14,
        boxShadow: h&&ac
          ? `0 0 0 1px ${ac}12,0 8px 32px rgba(0,0,0,.5),inset 0 1px 0 rgba(255,255,255,.05)`
          : `0 4px 20px rgba(0,0,0,.4),inset 0 1px 0 rgba(255,255,255,.03)`,
        transition:"all .22s", ...style }}>
      <div style={{ position:"absolute",top:0,left:0,right:0,height:2,background:`linear-gradient(90deg,transparent,${ac||ax(.4)},transparent)`,opacity:h?1:.3,transition:"opacity .22s",pointerEvents:"none" }} />
      {children}
    </div>
  );
}

/* ÔöÇÔöÇ KPI stat card ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function Kpi({ label, value, ac, icon, delay=0 }) {
  return (
    <motion.div initial={{opacity:0,y:18,scale:.94}} animate={{opacity:1,y:0,scale:1}} transition={{delay,duration:.44,ease:[.22,1,.36,1]}} whileHover={{y:-4,transition:{duration:.18}}}>
      <G ac={ac} style={{ padding:"20px 18px" }}>
        <div style={{ position:"absolute",top:-18,right:-18,width:75,height:75,borderRadius:"50%",background:`radial-gradient(circle,${ac}16,transparent 70%)`,pointerEvents:"none" }} />
        <p style={{ fontFamily:"var(--f-ui)",fontSize:10,color:"rgba(255,255,255,.3)",marginBottom:8,position:"relative" }}>
          <span style={{marginRight:5}}>{icon}</span>{label}
        </p>
        <p style={{ fontFamily:"var(--f-dis)",fontSize:38,letterSpacing:1,lineHeight:1,color:"#fff",textShadow:`0 0 30px ${ac}40`,position:"relative" }}>
          <N v={String(value)} />
        </p>
      </G>
    </motion.div>
  );
}

/* ÔöÇÔöÇ Edit Profile Form ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function EditProfileForm({ profile, onSaved }) {
  const [ffid, setFfid]       = useState(profile?.free_fire_id || "");
  const [bio,  setBio]        = useState(profile?.bio          || "");
  const [saving, setSaving]   = useState(false);
  const [success, setSuccess] = useState(false);
  const [error,  setError]    = useState("");

  const handleSaveDirect = async () => {
    setSaving(true); setError(""); setSuccess(false);
    try {
      const { error: e } = await supabase
        .from("profiles")
        .update({ free_fire_id: sanitize(ffid,20)||null, bio: sanitize(bio,250)||null })
        .eq("id", profile?.id);
      if (e) throw e;
      setSuccess(true); onSaved?.();
      setTimeout(()=>setSuccess(false), 3000);
    } catch(e) { setError(e.message||"Erreur"); }
    finally { setSaving(false); }
  };

  const sendSupportRequest = (field, currentVal) => {
    const fieldNames = { full_name:"Nom complet", age:"Age", city:"Ville", country:"Pays" };
    const params = new URLSearchParams({
      type:"profile_edit", userId:profile?.id||"", name:profile?.full_name||"",
      email:profile?.email||"", ffid:profile?.free_fire_id||"",
      role:profile?.role||"user", level:String(profile?.level||1),
      joinDate:profile?.created_at?new Date(profile.created_at).toLocaleDateString("fr-FR"):"",
      field:fieldNames[field]||field, currentVal:currentVal||"",
    });
    window.location.href = "/support?"+params.toString();
  };

  const ReadonlyField = ({ label, icon, field, value }) => (
    <div style={{marginBottom:14}}>
      <label style={{display:"block",fontFamily:"var(--f-ui)",fontSize:11,color:"rgba(255,255,255,.3)",marginBottom:7}}>{icon} {label}</label>
      <div style={{display:"flex",gap:10,alignItems:"center"}}>
        <div style={{flex:1,padding:"12px 16px",borderRadius:10,background:"rgba(255,255,255,.03)",border:"1px solid rgba(255,255,255,.07)",color:"rgba(255,255,255,.4)",fontFamily:"var(--f-ui)",fontSize:13}}>
          {value||<span style={{color:"rgba(255,255,255,.15)"}}>ÔÇö</span>}
        </div>
        <motion.button whileHover={{scale:1.04}} whileTap={{scale:.96}} onClick={()=>sendSupportRequest(field,value)}
          style={{padding:"11px 16px",borderRadius:10,background:"rgba(251,191,36,.08)",border:"1px solid rgba(251,191,36,.2)",color:AMBER,fontFamily:"var(--f-ui)",fontSize:11,cursor:"pointer",whiteSpace:"nowrap",flexShrink:0,fontWeight:600}}>
          Modifier
        </motion.button>
      </div>
      <p style={{fontFamily:"var(--f-ui)",fontSize:11,color:"rgba(255,255,255,.18)",marginTop:5}}>Trait├® par le support sous 24h</p>
    </div>
  );

  return (
    <div style={{maxWidth:660}}>
      <p style={{fontFamily:"var(--f-ui)",fontSize:11,letterSpacing:1,color:"rgba(255,255,255,.2)",marginBottom:24,textTransform:"uppercase"}}>
        ├ëdition du profil
      </p>

      {/* Direct edit: FF ID + Bio */}
      <G ac={ACCENT} style={{padding:"24px 28px",marginBottom:14}}>
        <p style={{fontFamily:"var(--f-dis)",fontSize:14,letterSpacing:2,color:ACCENT,marginBottom:18,textTransform:"uppercase"}}>
          Modification directe
        </p>
        <div style={{marginBottom:16}}>
          <label style={{display:"block",fontFamily:"var(--f-ui)",fontSize:11,color:"rgba(255,255,255,.35)",marginBottom:8}}>
            Free Fire ID
          </label>
          <input value={ffid} onChange={e=>setFfid(e.target.value)} placeholder="ex: 1234567890" maxLength={20}
            style={{width:"100%",padding:"12px 16px",borderRadius:10,background:ax(.05),border:`1px solid ${ax(.2)}`,color:"#fff",fontFamily:"var(--f-ui)",fontSize:14,outline:"none",boxSizing:"border-box",letterSpacing:2}}/>
        </div>
        <div style={{marginBottom:20}}>
          <label style={{display:"block",fontFamily:"var(--f-ui)",fontSize:11,color:"rgba(255,255,255,.35)",marginBottom:8}}>
            Bio
          </label>
          <textarea value={bio} onChange={e=>setBio(e.target.value)} placeholder="Parle de toi, ton style de jeu..." maxLength={250} rows={3}
            style={{width:"100%",padding:"12px 16px",borderRadius:10,background:ax(.05),border:`1px solid ${ax(.2)}`,color:"rgba(255,255,255,.85)",fontFamily:"var(--f-ui)",fontSize:13,outline:"none",resize:"vertical",boxSizing:"border-box"}}/>
          <p style={{fontFamily:"var(--f-ui)",fontSize:11,color:"rgba(255,255,255,.2)",textAlign:"right",marginTop:4}}>{bio.length}/250</p>
        </div>
        {error && (
          <div style={{padding:"10px 14px",borderRadius:9,background:rx(.1),border:`1px solid ${rx(.2)}`,color:RED,fontSize:12,marginBottom:12}}>
            {error}
          </div>
        )}
        {success && (
          <motion.div initial={{opacity:0,scale:.95}} animate={{opacity:1,scale:1}}
            style={{padding:"10px 14px",borderRadius:9,background:gx(.1),border:`1px solid ${gx(.2)}`,color:GREEN,fontSize:12,marginBottom:12}}>
            Sauvegard├® avec succ├¿s
          </motion.div>
        )}
        <motion.button whileHover={{scale:1.02}} whileTap={{scale:.97}} onClick={handleSaveDirect} disabled={saving}
          style={{width:"100%",padding:"13px 0",borderRadius:11,background:saving?"rgba(255,255,255,.06)":ACCENT,border:"none",color:"#fff",fontFamily:"var(--f-dis)",fontSize:16,letterSpacing:2,fontWeight:700,cursor:saving?"wait":"pointer",textTransform:"uppercase"}}>
          {saving ? "Sauvegarde en cours..." : "Enregistrer les modifications"}
        </motion.button>
      </G>

      {/* Via support */}
