ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */
export default function Profile() {
  const { profile:ap, balance:cb, equippedItems:ce, refreshProfile } = useOutletContext();
  const [searchParams] = useSearchParams();
  const viewingId = searchParams.get("id");
  const isViewingOther = !!(viewingId && viewingId !== ap?.id);

  const [uploading,   setUploading]   = useState(false);
  const [deleting,    setDeleting]    = useState(false);
  const [avatarMenu,  setAvatarMenu]  = useState(false);
  const [tab,         setTab]         = useState("stats");
  const [imgErr,      setImgErr]      = useState(false);
  const [avatarMode,  setAvatarModeState] = useState(null);
  const menuRef = useRef(null);
  const { isAdmin } = usePermissions(ap);

  const { profile:dp, stats, achievements, recentMatches, transactions, loading, uploadAvatar, equippedItems: fetchedEquippedItems } = useProfileData(viewingId || ap?.id);

  const profile  = dp || ap;
  const balance  = cb ?? 0;
  const eq = fetchedEquippedItems && Object.keys(fetchedEquippedItems).length > 0 ? fetchedEquippedItems : (ce || {});

  const isVerified = profile?.verification_status === "approved";
  const role       = ROLE_META[profile?.role] || ROLE_META.user;
  const initials   = profile?.full_name?.split(" ").map(w=>w[0]).join("").slice(0,2).toUpperCase() || "?";
  const xpPct      = (profile?.xp % 100) || 0;
  const wr         = stats?.total_matches > 0 ? Math.round((stats.wins / stats.total_matches) * 100) : 0;
  const kd         = stats?.deaths > 0 ? (stats.kills / stats.deaths).toFixed(2) : (stats?.kills || 0);

  const effectiveAvatarMode = avatarMode ?? profile?.avatar_mode ?? "auto";
  const storeAvatarUrl = eq?.avatar?.image_url;
  const photoAvatarUrl = (profile?.avatar_url && !imgErr) ? profile.avatar_url : null;
  const avatarSrc = effectiveAvatarMode === "photo"
    ? photoAvatarUrl
    : effectiveAvatarMode === "store"
    ? (storeAvatarUrl || photoAvatarUrl)
    : (storeAvatarUrl || photoAvatarUrl);
  const hasImg = !!(avatarSrc);

  useEffect(() => { setImgErr(false); }, [profile?.avatar_url, eq?.avatar?.image_url]);

  const setAvatarMode = async (mode) => {
    setAvatarModeState(mode);
    if (!ap?.id) return;
    await supabase.from("profiles").update({ avatar_mode: mode }).eq("id", ap.id);
    if (refreshProfile) refreshProfile();
  };

  useEffect(() => {
    if (!avatarMenu) return;
    const close = e => { if (menuRef.current && !menuRef.current.contains(e.target)) setAvatarMenu(false); };
    document.addEventListener("mousedown", close);
    return () => document.removeEventListener("mousedown", close);
  }, [avatarMenu]);

  const handleUpload = async e => {
    const f = e.target.files?.[0]; if (!f) return;
    setAvatarMenu(false); setUploading(true); setImgErr(false);
    try {
      const userId = ap?.id;
      if (!userId) throw new Error("No user");
      const exts = ["jpg","jpeg","png","webp","gif","JPG","PNG","WEBP"];
      await supabase.storage.from("avatars").remove(exts.map(x => `${userId}/avatar.${x}`));
      const { data: listed } = await supabase.storage.from("avatars").list(userId);
      if (listed?.length) await supabase.storage.from("avatars").remove(listed.map(f => `${userId}/${f.name}`));
      const ext = f.name.split(".").pop().toLowerCase() || "jpg";
      const ts  = Date.now();
      const fileName = `${userId}/avatar_${ts}.${ext}`;
      const { error: upErr } = await supabase.storage.from("avatars").upload(fileName, f, { upsert: true, cacheControl: "0" });
      if (upErr) throw upErr;
      const { data } = supabase.storage.from("avatars").getPublicUrl(fileName);
      const publicUrl = data.publicUrl + "?t=" + ts;
      const { error: updErr } = await supabase.from("profiles").update({ avatar_url: publicUrl }).eq("id", userId);
      if (updErr) throw updErr;
      refreshProfile?.();
    } catch (err) { console.error("Avatar upload error:", err); }
    finally { setUploading(false); }
  };

  const handleDeleteAvatar = async () => {
    setAvatarMenu(false); setDeleting(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        for (const ext of ["jpg","jpeg","png","webp","gif"]) {
          await supabase.storage.from("avatars").remove([`${user.id}/avatar.${ext}`]);
        }
      }
      await supabase.from("profiles").update({ avatar_url: null }).eq("id", ap?.id);
      refreshProfile?.(); setImgErr(false);
