                          <span style={{fontSize:16,opacity:.7}}>{c.icon}</span>
                        </div>
                        <p style={{ fontFamily:"var(--f-dis)",fontSize:32,letterSpacing:1,color:c.ac,lineHeight:1,textShadow:`0 0 22px ${c.ac}45`,position:"relative" }}><N v={c.val} /></p>
                        <p style={{ fontFamily:"var(--f-ui)",fontSize:10,color:"rgba(255,255,255,.2)",marginTop:3,position:"relative" }}>CP Coins</p>
                      </G>
                    </motion.div>
                  ))}
                </div>

                <G style={{ overflow:"hidden" }}>
                  <div style={{ padding:"18px 24px 13px",borderBottom:"1px solid rgba(255,255,255,0.07)" }}>
                    <p style={{ fontFamily:"var(--f-ui)",fontSize:11,color:"rgba(255,255,255,.25)",textTransform:"uppercase",letterSpacing:1 }}>Historique des transactions</p>
                  </div>
                  {transactions.length === 0
                    ? <p style={{ color:"rgba(255,255,255,.15)",fontSize:12,textAlign:"center",padding:"40px 0",fontFamily:"var(--f-ui)",letterSpacing:2,textTransform:"uppercase" }}>
                        Aucune transaction
                      </p>
                    : transactions.map((tx,i)=>{
                        const deb=["purchase","debit","penalty"].includes(tx.type?.toLowerCase());
                        return (
                          <motion.div key={tx.id||i} initial={{opacity:0,x:-10}} animate={{opacity:1,x:0}} transition={{delay:i*.04+.15}} className="rowh"
                            style={{ display:"flex",alignItems:"center",padding:"13px 24px",borderBottom:i<transactions.length-1?"1px solid rgba(255,255,255,0.05)":"none",gap:13 }}>
                            <div style={{ width:32,height:32,borderRadius:10,flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,background:deb?rx(.1):gx(.1),border:`1px solid ${deb?rx(.22):gx(.25)}` }}>
                              {deb?"Ôåæ":"Ôåô"}
                            </div>
                            <p style={{ flex:1,fontSize:13,fontWeight:500,color:"rgba(255,255,255,.55)" }}>{tx.description||tx.type||"ÔÇö"}</p>
                            <p style={{ fontFamily:"var(--f-ui)",fontSize:11,color:"rgba(255,255,255,.2)" }}>
                              {tx.created_at?new Date(tx.created_at).toLocaleDateString("fr-FR"):""}
                            </p>
                            <p style={{ fontFamily:"var(--f-dis)",fontSize:20,letterSpacing:1,minWidth:80,textAlign:"right",color:deb?RED:GREEN,textShadow:`0 0 12px ${deb?rx(.4):gx(.4)}` }}>
                              {deb?"ÔêÆ":"+"}{(tx.amount||0).toLocaleString("fr-FR")}
                            </p>
                          </motion.div>
                        );
                      })
                  }
                </G>
              </motion.div>
            )}

            {/* ÔöÇÔöÇ EDIT PROFILE ÔöÇÔöÇ */}
            {tab==="edit" && !isViewingOther && (
              <motion.div key="edit" initial={{opacity:0,y:12}} animate={{opacity:1,y:0}} exit={{opacity:0,y:-12}} transition={{duration:.28}}>
                <EditProfileForm profile={profile} onSaved={refreshProfile} />
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </>
  );
}

