import { motion, AnimatePresence } from "framer-motion";
import {
  User, MapPin, Mail, Lock, Eye, EyeOff, Gamepad2,
  Upload, Camera, AlertTriangle, CheckCircle,
  AlertCircle, Check,
} from "lucide-react";
import Button from "../components/ui/Button";
import Input  from "../components/ui/Input";
import "./auth/auth.css";

const ease = { duration: 0.4, ease: [0.32, 0, 0.15, 1] };

/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
   STEP INDICATOR
ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */
function StepBar({ step }) {
  return (
    <div className="auth-steps">
      <div className="auth-step">
        <div className={`auth-step-circle ${step >= 1 ? "auth-step-circle--active" : ""} ${step > 1 ? "auth-step-circle--done" : ""}`}>
          {step > 1 ? <Check size={13} /> : 1}
        </div>
        <span className={`auth-step-label ${step === 1 ? "auth-step-label--active" : ""}`}>
          Your Info
        </span>
      </div>

      <div className={`auth-step-connector ${step > 1 ? "auth-step-connector--done" : ""}`} />

      <div className="auth-step">
        <div className={`auth-step-circle ${step === 2 ? "auth-step-circle--active" : ""}`}>
          2
        </div>
        <span className={`auth-step-label ${step === 2 ? "auth-step-label--active" : ""}`}>
          Verification
        </span>
      </div>
    </div>
  );
}

/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
   KYC WARNING MODAL
ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */
function KYCModal({ onConfirm, onBack }) {
  const ITEMS = [
    { ok: true,  text: "Nom complet identique ├á la CIN" },
    { ok: true,  text: "Date de naissance correcte" },
    { ok: true,  text: "Ville de r├®sidence r├®elle" },
    { ok: true,  text: "Photo de votre CIN requise ├á l'├®tape suivante" },
    { ok: true,  text: "Selfie avec votre CIN requis" },
    { ok: false, text: "Toute information fausse = compte refus├®" },
  ];

  return (
    <div className="auth-kyc-overlay">
      <motion.div
        className="auth-kyc-box"
        initial={{ opacity: 0, scale: 0.96, y: 12 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.96 }}
        transition={ease}
      >
        <div className="auth-kyc-header">
          <div className="auth-kyc-icon">
            <AlertTriangle size={22} />
          </div>
          <h2 className="auth-kyc-title">V├ëRIFICATION D'IDENTIT├ë</h2>
        </div>

        <div className="auth-kyc-body">
          <p className="auth-kyc-text">
            Les informations saisies <strong style={{ color: "var(--t1)" }}>doivent correspondre exactement</strong> ├á celles de votre Carte Nationale d'Identit├®.
          </p>

          <ul className="auth-kyc-list">
            {ITEMS.map((item, i) => (
              <li key={i} className={item.ok ? "" : "warn"}>
                {item.ok ? "Ô£ô " : "Ô£ù "}{item.text}
              </li>
            ))}
          </ul>

          <p style={{ fontFamily: "var(--f-ui)", fontSize: 12, color: "var(--t4)", textAlign: "center", marginBottom: 20 }}>
            L'administrateur v├®rifiera manuellement vos documents.
          </p>

          <div className="auth-kyc-actions">
            <Button variant="ghost" onClick={onBack} style={{ flex: 1 }}>
              ÔåÉ Modifier
            </Button>
            <Button variant="primary" onClick={onConfirm} style={{ flex: 2 }}>
              Compris ÔÇö Continuer
            </Button>
          </div>
        </div>
      </motion.div>
    </div>
  );
}

/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
   FILE UPLOAD ZONE
ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */
function UploadZone({ label, preview, onFileSelect, onCamera, hint }) {
  const pickFile = () => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = "image/*";
    input.onchange = onFileSelect;
    input.click();
  };

  return (
    <div>
      {label && <label className="ui-field-label">{label}</label>}

      {preview ? (
        <div className="auth-upload-zone auth-upload-zone--filled">
          <img src={preview} alt="preview" className="auth-upload-preview" />
          <p className="auth-upload-title" style={{ color: "var(--s-green)" }}>Document ajout├®</p>
          <div className="auth-upload-actions">
            <Button variant="ghost" size="sm" onClick={pickFile} icon={<Upload size={13} />}>Changer</Button>
            <Button variant="ghost" size="sm" onClick={onCamera} icon={<Camera size={13} />}>Reprendre</Button>
          </div>
        </div>
      ) : (
        <div className="auth-upload-zone" onClick={pickFile} role="button" tabIndex={0}
          onKeyDown={e => e.key === "Enter" && pickFile()}>
          <div className="auth-upload-icon"><Upload size={22} /></div>
          <p className="auth-upload-title">Cliquez pour s├®lectionner</p>
          <p className="auth-upload-hint">{hint || "JPG, PNG ÔÇö max 5 MB"}</p>
          <div className="auth-upload-actions" onClick={e => e.stopPropagation()}>
            <Button variant="ghost" size="sm" icon={<Upload size={13} />} onClick={pickFile}>Galerie</Button>
            <Button variant="ghost" size="sm" icon={<Camera size={13} />} onClick={onCamera}>Cam├®ra</Button>
          </div>
        </div>
      )}
    </div>
  );
}

/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
   MAIN COMPONENT
ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */
export default function Register() {
  const navigate = useNavigate();
  const [step,           setStep]           = useState(1);
  const [loading,        setLoading]        = useState(false);
  const [error,          setError]          = useState("");
  const [success,        setSuccess]        = useState("");
  const [showKYCWarning, setShowKYCWarning] = useState(false);
  const [showPass,       setShowPass]       = useState(false);
  const [showConfirm,    setShowConfirm]    = useState(false);

  const [formData, setFormData] = useState({
    fullName: "", age: "", city: "", country: "",
    email: "", password: "", confirmPassword: "",
    freeFireId: "", idCard: null, selfie: null,
  });

  const [previews, setPreviews] = useState({ idCard: null, selfie: null });

  /* ÔöÇÔöÇ Helpers ÔöÇÔöÇ */
  const handleChange = e => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleFileChange = (e, type) => {
    const file = e.target?.files?.[0] || e;
    if (!file) return;
    if (!file.type?.startsWith("image/")) { setError("Veuillez choisir une image"); setTimeout(() => setError(""), 3000); return; }
    if (file.size > 5 * 1024 * 1024)      { setError("Taille max : 5 MB");          setTimeout(() => setError(""), 3000); return; }
    setFormData(d => ({ ...d, [type]: file }));
    const reader = new FileReader();
    reader.onloadend = () => setPreviews(p => ({ ...p, [type]: reader.result }));
    reader.readAsDataURL(file);
  };

  const openCamera    = (type, facingMode) => {
    const input = document.createElement("input");
    input.type = "file"; input.accept = "image/*"; input.capture = facingMode;
    input.onchange = e => handleFileChange(e.target.files[0], type);
    input.click();
  };

  const makeFileHandler = type => e => handleFileChange(e.target.files[0], type);

  /* ÔöÇÔöÇ Validation ÔöÇÔöÇ */
  const validateStep1 = () => {
    if (!formData.fullName)                                    { setError("Nom complet requis"); return false; }
    if (!formData.age || formData.age < 13)                    { setError("├ége minimum : 13 ans"); return false; }
    if (!formData.city)                                        { setError("Ville requise"); return false; }
    if (!formData.country)                                     { setError("Pays requis"); return false; }
    if (!formData.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/))  { setError("Email invalide"); return false; }
    if (!formData.freeFireId)                                  { setError("Free Fire ID requis"); return false; }
    if (formData.password.length < 6)                          { setError("Mot de passe : 6 caract├¿res minimum"); return false; }
    if (formData.password !== formData.confirmPassword)        { setError("Les mots de passe ne correspondent pas"); return false; }
    return true;
  };

  const validateStep2 = () => {
    if (!formData.idCard) { setError("CIN requise"); return false; }
    if (!formData.selfie) { setError("Selfie avec CIN requis"); return false; }
    return true;
  };

  const handleNextStep = () => { setError(""); if (validateStep1()) setShowKYCWarning(true); };
  const confirmKYC     = () => { setShowKYCWarning(false); setStep(2); };

  /* ÔöÇÔöÇ Upload helper ÔöÇÔöÇ */
  const uploadFile = async (file, userId, folder) => {
    const ext      = file.name.split(".").pop();
    const fileName = `${userId}-${folder}-${Date.now()}.${ext}`;
    const filePath = `${folder}/${fileName}`;
    const { error: upErr } = await supabase.storage.from("verification-docs").upload(filePath, file);
    if (upErr) throw upErr;
    const { data } = supabase.storage.from("verification-docs").getPublicUrl(filePath);
    return data.publicUrl;
  };

  /* ÔöÇÔöÇ Submit ÔöÇÔöÇ */
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(""); setSuccess("");
    if (!validateStep2()) return;
    setLoading(true);
    setSuccess("Cr├®ation de votre compteÔÇª");

    try {
      const { data, error: authErr } = await supabase.auth.signUp({
        email: formData.email, password: formData.password,
      });
      if (authErr) throw authErr;
      const user = data.user;
      if (!user) throw new Error("├ëchec de la cr├®ation du compte");

      setSuccess("Enregistrement du profilÔÇª");
      const { error: profileErr } = await supabase.rpc("create_profile_on_signup", {
        user_id:      user.id,
        user_email:   formData.email,
        full_name:    formData.fullName,
        age:          parseInt(formData.age),
        city:         formData.city,
        country:      formData.country,
        free_fire_id: formData.freeFireId,
      });
      if (profileErr) throw profileErr;

      setSuccess("Envoi des documentsÔÇª");
      try {
        const idCardUrl = await uploadFile(formData.idCard, user.id, "id-cards");
        const selfieUrl = await uploadFile(formData.selfie, user.id, "selfies");
        await supabase.from("profiles").update({ id_card_url: idCardUrl, selfie_url: selfieUrl }).eq("id", user.id);
      } catch (uploadErr) {
        console.warn("Upload docs ├®chou├® (non critique):", uploadErr.message);
      }

      setSuccess("Compte cr├®├® ! RedirectionÔÇª");
      setTimeout(() => navigate("/login"), 2000);
    } catch (err) {
      if (err.message?.includes("already registered") || err.message?.includes("already been registered")) {
        setError("Cet email est d├®j├á utilis├®.");
      } else if (err.message?.includes("row-level security") || err.message?.includes("RLS")) {
        setError("Erreur serveur. Contactez l'administrateur.");
      } else {
        setError(err.message || "Une erreur est survenue");
      }
    } finally {
      setLoading(false);
    }
  };

  /* ÔöÇÔöÇ Render ÔöÇÔöÇ */
  return (
    <div className="auth-video-root" style={{ alignItems: "flex-start", paddingTop: 40 }}>
      {/* ÔöÇÔöÇ Video background ÔöÇÔöÇ */}
      <div className="auth-video-bg" aria-hidden="true">
        <div className="auth-video-overlay" />
        <video autoPlay loop muted playsInline>
          <source
            src="https://videos.pexels.com/video-files/8128311/8128311-uhd_2560_1440_25fps.mp4"
            type="video/mp4"
          />
        </video>
      </div>

      {/* KYC modal */}
      <AnimatePresence>
        {showKYCWarning && (
          <KYCModal onConfirm={confirmKYC} onBack={() => setShowKYCWarning(false)} />
        )}
      </AnimatePresence>

      {/* ÔöÇÔöÇ Register card ÔöÇÔöÇ */}
      <motion.div
        className="auth-form-box"
        initial={{ opacity: 0, y: 24 }}
        animate={{ opacity: 1, y: 0 }}
        transition={ease}
      >
        {/* Logo */}
        <Link to="/" className="auth-mobile-logo" style={{ display: "flex" }}>
          <div className="auth-form-logo-mark">CP</div>
          <span className="auth-form-logo-text">
            CIPHER<span style={{ color: "var(--accent)" }}>POOL</span>
          </span>
        </Link>

        {/* Game badge */}
        <div className="auth-game-badge" style={{ marginTop: 8 }}>
          <span className="auth-game-badge-dot" />
          Free Fire &amp; Blood Strike ┬À Maroc
        </div>

        <h1 className="auth-form-heading" style={{ marginTop: 16 }}>
          Join the <span>Arena</span>
        </h1>
        <p className="auth-form-sub">
          Create your account and compete in Free Fire &amp; Blood Strike tournaments.
        </p>

        <StepBar step={step} />

        {/* Feedback */}
        {error && (
          <div className="auth-alert auth-alert--error" style={{ marginBottom: 16 }}>
            <AlertCircle size={15} style={{ flexShrink: 0, marginTop: 1 }} />
            {error}
          </div>
        )}
        {success && (
          <div className="auth-alert auth-alert--success" style={{ marginBottom: 16 }}>
            <CheckCircle size={15} style={{ flexShrink: 0, marginTop: 1 }} />
            {success}
          </div>
        )}

        <AnimatePresence mode="wait">
          {step === 1 ? (
            /* ÔöÇÔöÇ STEP 1 ÔöÇÔöÇ */
            <motion.div
              key="step1"
              initial={{ opacity: 0, x: 12 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -12 }}
              transition={ease}
            >
              <div className="ui-field-group">
                <Input
                  label="Full name"
                  name="fullName"
                  icon={<User size={15} />}
                  placeholder="First Last"
                  onChange={handleChange}
                  autoComplete="name"
                />

                <div className="ui-field-row">
                  <Input
                    label="Age"
                    name="age"
                    type="number"
                    placeholder="Your age"
                    onChange={handleChange}
                    min={13} max={99}
                  />
                  <Input
                    label="City"
                    name="city"
                    icon={<MapPin size={15} />}
                    placeholder="CasablancaÔÇª"
                    onChange={handleChange}
                  />
                </div>

                <Input
                  label="Country"
                  name="country"
                  icon={<MapPin size={15} />}
                  placeholder="Morocco"
                  onChange={handleChange}
                />

                <Input
                  label="Free Fire ID"
                  name="freeFireId"
                  icon={<Gamepad2 size={15} />}
                  placeholder="Your in-game ID"
                  onChange={handleChange}
                  autoCapitalize="none"
                />

                <Input
                  label="Email address"
                  name="email"
                  type="email"
                  icon={<Mail size={15} />}
                  placeholder="you@email.com"
                  onChange={handleChange}
                  autoComplete="email"
                  autoCapitalize="none"
                />

                {/* Password with show/hide */}
                <div className="ui-field">
                  <label className="ui-field-label">Password</label>
                  <div className="ui-input-wrap">
                    <span className="ui-input-icon"><Lock size={15} /></span>
                    <input
                      className="ui-input ui-input--has-icon ui-input--has-action"
                      type={showPass ? "text" : "password"}
                      name="password"
                      placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                      onChange={handleChange}
                      autoComplete="new-password"
                    />
                    <button type="button" className="ui-input-action"
                      onClick={() => setShowPass(v => !v)}>
                      {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>

                {/* Confirm password with show/hide */}
                <div className="ui-field">
                  <label className="ui-field-label">Confirm password</label>
                  <div className="ui-input-wrap">
                    <span className="ui-input-icon"><Lock size={15} /></span>
                    <input
                      className="ui-input ui-input--has-icon ui-input--has-action"
                      type={showConfirm ? "text" : "password"}
                      name="confirmPassword"
                      placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó"
                      onChange={handleChange}
                      autoComplete="new-password"
                    />
                    <button type="button" className="ui-input-action"
                      onClick={() => setShowConfirm(v => !v)}>
                      {showConfirm ? <EyeOff size={16} /> : <Eye size={16} />}
                    </button>
                  </div>
                </div>
              </div>

              <Button
                variant="primary"
                size="lg"
                className="ui-btn-full"
                style={{ marginTop: 24 }}
                onClick={handleNextStep}
              >
                Next Step ÔåÆ
              </Button>
            </motion.div>
          ) : (
            /* ÔöÇÔöÇ STEP 2 ÔöÇÔöÇ */
            <motion.form
              key="step2"
              initial={{ opacity: 0, x: 12 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -12 }}
              transition={ease}
              onSubmit={handleSubmit}
            >
              <div className="ui-field-group">
                <UploadZone
                  label="National ID Card (CIN) *"
                  preview={previews.idCard}
                  onFileSelect={makeFileHandler("idCard")}
                  onCamera={() => openCamera("idCard", "environment")}
                  hint="Place the ID on a flat surface ÔÇö all 4 corners visible, good lighting"
                />

                <UploadZone
                  label="Selfie holding your CIN *"
                  preview={previews.selfie}
                  onFileSelect={makeFileHandler("selfie")}
                  onCamera={() => openCamera("selfie", "user")}
                  hint="Hold the ID next to your face ÔÇö both face and ID text must be readable"
                />

                <div style={{
                  padding: "12px 16px",
                  background: "rgba(124,58,237,0.05)",
                  border: "1px solid rgba(124,58,237,0.15)",
                  borderRadius: "var(--r2)",
                }}>
                  <p style={{ fontFamily: "var(--f-ui)", fontSize: 12, color: "var(--t3)", margin: 0, lineHeight: 1.6 }}>
                    Documents are encrypted and visible only to admins for identity verification.
                  </p>
                </div>
              </div>

              <div style={{ display: "flex", gap: 10, marginTop: 24 }}>
                <Button type="button" variant="ghost" size="lg" onClick={() => setStep(1)} style={{ flex: 1 }}>
                  ÔåÉ Back
                </Button>
                <Button type="submit" variant="primary" size="lg" loading={loading} style={{ flex: 2 }}>
                  {loading ? "CreatingÔÇª" : "Create My Account ÔåÆ"}
                </Button>
              </div>
            </motion.form>
          )}
        </AnimatePresence>

        <p className="auth-form-footer" style={{ marginTop: 20 }}>
          Already have an account?{" "}
          <Link to="/login">Sign in ÔåÆ</Link>
        </p>
      </motion.div>

      {/* Footer */}
      <p className="auth-video-footer">┬® 2026 CipherPool ÔÇö All rights reserved</p>
    </div>
  );
}

