import { useState, useEffect, useCallback } from "react";
import { useOutletContext } from "react-router-dom";
import { supabase } from "../lib/supabase";
import { motion, AnimatePresence } from "framer-motion";

// ÔöÇÔöÇÔöÇ CONSTANTS ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const TABS = [
  { key: "all",        label: "Tout",      icon: "­ƒÅ¬" },
  { key: "avatar",     label: "Avatar",    icon: "­ƒÄ¡" },
  { key: "banner",     label: "Banner",    icon: "­ƒû╝´©Å" },
  { key: "frame",      label: "Cadre",     icon: "­ƒÆá" },
  { key: "badge",      label: "Badge",     icon: "­ƒÅà" },
  { key: "name_color", label: "Nom",       icon: "Ô£¿" },
  { key: "emote",      label: "Emote",     icon: "­ƒÿÄ" },
  { key: "inventory",  label: "Inventaire",icon: "­ƒÄÆ" },
];

const RARITY = {
  common:    { label: "COMMUN",    color: "#9ca3af", glow: "#9ca3af30", bg: "#9ca3af15" },
  rare:      { label: "RARE",      color: "#3b82f6", glow: "#3b82f630", bg: "#3b82f615" },
  epic:      { label: "├ëPIQUE",    color: "#a855f7", glow: "#a855f730", bg: "#a855f715" },
  legendary: { label: "L├ëGEND.",   color: "#f59e0b", glow: "#f59e0b40", bg: "#f59e0b15" },
};

const RARITY_ORDER = { common: 0, rare: 1, epic: 2, legendary: 3 };

// ÔöÇÔöÇÔöÇ ITEM CARD ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function ItemCard({ item, owned, equipped, onBuy, onEquip, coins }) {
  const [hovered, setHovered]   = useState(false);
  const [buying, setBuying]     = useState(false);
  const [equipping, setEquipping] = useState(false);
  const rarity = RARITY[item.rarity] || RARITY.common;
  const canAfford = coins >= item.price;

  const handleBuy = async () => {
    if (buying || owned) return;
    setBuying(true);
    await onBuy(item);
    setBuying(false);
  };

  const handleEquip = async () => {
    if (equipping) return;
    setEquipping(true);
    await onEquip(item);
    setEquipping(false);
  };

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.9 }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        position: "relative",
        borderRadius: 14,
        border: `1px solid ${equipped ? rarity.color : hovered ? rarity.color + "60" : "rgba(255,255,255,0.07)"}`,
        background: equipped
          ? `linear-gradient(145deg, ${rarity.bg}, rgba(14,14,22,0.97))`
          : hovered
            ? `rgba(18,18,28,0.96)`
            : `rgba(14,14,22,0.90)`,
        transition: "all 0.25s",
        overflow: "hidden",
        boxShadow: equipped ? `0 0 25px ${rarity.glow}` : hovered ? `0 4px 25px rgba(0,0,0,0.4)` : "none",
        cursor: "pointer",
      }}
    >
      {/* Rarity stripe top */}
      <div style={{ height: 3, background: `linear-gradient(90deg, ${rarity.color}, transparent)` }} />

      {/* Equipped badge */}
      {equipped && (
        <div style={{
          position: "absolute", top: 10, right: 10, zIndex: 2,
          padding: "3px 8px", borderRadius: 99,
          background: rarity.color, color: "#000",
          fontSize: 9, fontWeight: 700, letterSpacing: 1,
        }}>
          ├ëQUIP├ë
        </div>
      )}

      {/* Limited badge */}
      {item.limited && (
        <div style={{
          position: "absolute", top: equipped ? 32 : 10, right: 10, zIndex: 2,
          padding: "3px 8px", borderRadius: 99,
          background: "#ef4444", color: "#fff",
          fontSize: 9, fontWeight: 700, letterSpacing: 1,
        }}>
          LIMIT├ë
        </div>
      )}

      {/* Image area */}
      <div style={{
        height: 110, display: "flex", alignItems: "center", justifyContent: "center",
        position: "relative", overflow: "hidden",
        background: `radial-gradient(circle at center, ${rarity.glow}, transparent 70%)`,
      }}>
        {item.image_url ? (
          <img
            src={item.image_url}
            alt={item.name}
            style={{ width: "100%", height: "100%", objectFit: "cover", opacity: 0.9 }}
          />
        ) : (
          <div style={{ fontSize: 64, filter: `drop-shadow(0 0 15px ${rarity.color})` }}>
            {item.type === "avatar"     ? "­ƒÄ¡" :
             item.type === "banner"     ? "­ƒû╝´©Å" :
             item.type === "badge"      ? "­ƒÅà" :
             item.type === "name_color" ? "Ô£¿" :
             item.type === "frame"      ? "­ƒÆá" : "­ƒÿÄ"}
          </div>
        )}

        {/* Name color preview */}
        {item.type === "name_color" && item.color_value && (
          <div style={{
            position: "absolute", bottom: 8,
            fontSize: 14, fontWeight: 800,
            color: item.color_value,
            textShadow: `0 0 15px ${item.color_value}`,
            fontFamily: "var(--f-dis)",
            letterSpacing: 2,
          }}>
            VOTRE NOM
          </div>
        )}
      </div>

      {/* Info */}
      <div style={{ padding: "10px 12px" }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 4 }}>
          <span style={{
            fontSize: 9, fontWeight: 700, letterSpacing: 1.5,
            color: rarity.color,
            padding: "2px 6px", borderRadius: 4,
            background: rarity.bg,
          }}>
            {rarity.label}
          </span>
          <span style={{ fontSize: 9, color: "rgba(255,255,255,0.3)", letterSpacing: 1 }}>
            {item.type?.toUpperCase()}
          </span>
        </div>

        <h3 style={{
          fontSize: 14, fontWeight: 700, color: "#fff",
          fontFamily: "var(--f-ui)", letterSpacing: .5,
          marginBottom: 4, marginTop: 6,
        }}>
          {item.name}
        </h3>

        {item.description && (
          <p style={{ fontSize: 11, color: "rgba(255,255,255,0.4)", lineHeight: 1.4, marginBottom: 12 }}>
            {item.description}
          </p>
        )}

        {/* Price + Actions */}
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginTop: 8 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 5 }}>
            <span style={{ fontSize: 16 }}>­ƒÆ░</span>
            <span style={{
              fontSize: 16, fontWeight: 800,
              color: item.source !== "store" ? "#10b981" : canAfford || owned ? "#f59e0b" : "#ef4444",
              fontFamily: "var(--f-dis)",
            }}>
              {item.source !== "store" ? "GRATUIT" : item.price.toLocaleString()}
            </span>
          </div>

          <div style={{ display: "flex", gap: 6 }}>
            {owned ? (
              <button
                onClick={handleEquip}
                disabled={equipping || equipped}
                style={{
                  padding: "6px 10px", borderRadius: 7,
                  background: equipped
                    ? "rgba(255,255,255,0.05)"
                    : `linear-gradient(135deg, ${rarity.color}, ${rarity.color}cc)`,
                  border: "none", color: equipped ? "rgba(255,255,255,0.3)" : "#000",
                  fontSize: 11, fontWeight: 700, letterSpacing: 1,
                  cursor: equipped ? "default" : "pointer",
                  transition: "all 0.2s",
                  opacity: equipping ? 0.7 : 1,
                }}
              >
                {equipping ? "..." : equipped ? "Ô£ô ├ëQUIP├ë" : "├ëQUIPER"}
              </button>
            ) : (
              <button
                onClick={handleBuy}
                disabled={buying || !canAfford}
                style={{
                  padding: "6px 12px", borderRadius: 7,
                  background: !canAfford
                    ? "rgba(229,64,64,0.10)"
                    : "var(--accent)",
                  border: `1px solid ${!canAfford ? "rgba(229,64,64,0.28)" : "transparent"}`,
                  color: !canAfford ? "var(--s-red)" : "#fff",
                  fontSize: 11, fontWeight: 700, letterSpacing: "0.04em",
                  cursor: !canAfford ? "not-allowed" : "pointer",
                  transition: "all 0.2s",
                  opacity: buying ? 0.7 : 1,
                  boxShadow: !canAfford ? "none" : "0 3px 12px rgba(255,79,0,0.25)",
                }}
              >
                {buying ? "..." : !canAfford ? "Solde insuffisant" : "Acheter"}
              </button>
            )}
          </div>
        </div>
      </div>
    </motion.div>
  );
}

// ÔöÇÔöÇÔöÇ MAIN STORE ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
// ÔöÇÔöÇÔöÇ INVENTORY VIEW ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function InventoryView({ userItems, items, onEquip, onUnequip }) {
  const [activeType, setActiveType] = useState("all");

  const itemTypes = [
    { key: "all",        label: "TOUT",   icon: "­ƒÄÆ" },
    { key: "avatar",     label: "AVATAR", icon: "­ƒÄ¡" },
    { key: "banner",     label: "BANN.",  icon: "­ƒû╝´©Å" },
    { key: "frame",      label: "CADRE",  icon: "­ƒÆá" },
    { key: "badge",      label: "BADGE",  icon: "­ƒÅà" },
    { key: "name_color", label: "NOM",    icon: "Ô£¿" },
    { key: "emote",      label: "EMOTE",  icon: "­ƒÿÄ" },
  ];

  const ownedFull = userItems
    .map(ui => ({ ...ui, item: items.find(it => it.id === ui.item_id) }))
    .filter(ui => ui.item);

  const filtered = activeType === "all"
    ? ownedFull
    : ownedFull.filter(ui => ui.item.type === activeType);

  const equippedByType = {};
  ownedFull.filter(ui => ui.equipped).forEach(ui => {
    equippedByType[ui.item.type] = ui.item;
  });

  if (ownedFull.length === 0) {
    return (
      <div style={{ textAlign: "center", padding: "80px 0" }}>
        <div style={{ fontSize: 64, marginBottom: 16 }}>­ƒÄÆ</div>
        <p style={{ color: "rgba(255,255,255,0.3)", fontSize: 16, letterSpacing: 2, fontFamily: "var(--f-dis)" }}>
          INVENTAIRE VIDE
        </p>
        <p style={{ color: "rgba(255,255,255,0.15)", fontSize: 13, marginTop: 8 }}>
          Ach├¿te des items dans la boutique !
        </p>
      </div>
    );
  }

  return (
    <div>
      {/* Equipped summary */}
      {Object.keys(equippedByType).length > 0 && (
        <div style={{
          background: "rgba(255,79,0,0.05)", border: "1px solid rgba(255,79,0,0.18)",
          borderRadius: 12, padding: "12px 16px", marginBottom: 16,
        }}>
          <p style={{ fontFamily: "var(--f-dis)", fontSize: 11, letterSpacing: 2, color: "var(--accent)", marginBottom: 14 }}>
            ÔÜí ACTUELLEMENT ├ëQUIP├ë
          </p>
          <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
            {Object.entries(equippedByType).map(([type, item]) => {
              const rc = RARITY[item.rarity] || RARITY.common;
              return (
                <div key={type} style={{
                  display: "flex", alignItems: "center", gap: 10,
                  background: `${rc.color}10`, border: `1px solid ${rc.color}30`,
                  borderRadius: 8, padding: "6px 10px",
                }}>
                  {item.image_url
                    ? <img src={item.image_url} style={{ width: 28, height: 28, borderRadius: 6, objectFit: "cover" }} />
                    : <span style={{ fontSize: 22 }}>
                        {type === "avatar" ? "­ƒÄ¡" : type === "banner" ? "­ƒû╝´©Å" : type === "frame" ? "­ƒÆá" :
                         type === "badge" ? "­ƒÅà" : type === "name_color" ? "Ô£¿" : "­ƒÿÄ"}
                      </span>
                  }
                  <div>
                    <p style={{ fontSize: 12, fontWeight: 700, color: "#fff" }}>{item.name}</p>
                    <p style={{ fontSize: 10, color: rc.color, letterSpacing: 1 }}>{rc.label}</p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Type filter */}
      <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
        {itemTypes.map(t => (
          <button key={t.key} onClick={() => setActiveType(t.key)}
            style={{
              padding: "5px 10px", borderRadius: 7, cursor: "pointer",
              background: activeType === t.key ? "rgba(255,79,0,0.15)" : "transparent",
              border: `1px solid ${activeType === t.key ? "rgba(255,79,0,0.45)" : "rgba(255,255,255,0.08)"}`,
              color: activeType === t.key ? "var(--accent)" : "rgba(255,255,255,0.35)",
              fontSize: 11, fontWeight: 700, letterSpacing: .5,
              fontFamily: "var(--f-ui)",
            }}
          >
            {t.icon} {t.label} {activeType === t.key || t.key === "all" ? `(${t.key === "all" ? ownedFull.length : ownedFull.filter(u => u.item.type === t.key).length})` : ""}
          </button>
        ))}
      </div>

      {/* Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(200px, 1fr))", gap: 14 }}>
        {filtered.map(({ item, equipped, id }) => {
          const rc = RARITY[item.rarity] || RARITY.common;
          return (
            <motion.div
              key={id}
              layout
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              style={{
                borderRadius: 14,
                background: equipped ? `${rc.color}08` : "rgba(255,255,255,0.02)",
                border: `1px solid ${equipped ? rc.color + "50" : "rgba(255,255,255,0.07)"}`,
                padding: 11, position: "relative", overflow: "hidden",
                boxShadow: equipped ? `0 0 20px ${rc.color}20` : "none",
              }}
            >
              {/* Equipped badge */}
              {equipped && (
                <div style={{
                  position: "absolute", top: 10, right: 10,
                  background: rc.color, color: "#000",
                  fontSize: 9, fontWeight: 800, letterSpacing: 1.5,
                  padding: "3px 8px", borderRadius: 99,
                  fontFamily: "var(--f-dis)",
                }}>
                  ├ëQUIP├ë
                </div>
              )}

              {/* Image */}
              <div style={{
                width: "100%", aspectRatio: "1", borderRadius: 10, marginBottom: 12,
                background: `${rc.color}10`,
                display: "flex", alignItems: "center", justifyContent: "center",
                overflow: "hidden",
              }}>
                {item.image_url
                  ? <img src={item.image_url} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                  : <span style={{ fontSize: 48 }}>
                      {item.type === "avatar" ? "­ƒÄ¡" : item.type === "banner" ? "­ƒû╝´©Å" : item.type === "frame" ? "­ƒÆá" :
                       item.type === "badge" ? "­ƒÅà" : item.type === "name_color" ? "Ô£¿" : "­ƒÿÄ"}
                    </span>
                }
              </div>

              <p style={{ fontWeight: 700, color: "#fff", fontSize: 13, marginBottom: 4 }}>{item.name}</p>
              <p style={{ fontSize: 10, color: rc.color, letterSpacing: 1.5, marginBottom: 12 }}>{rc.label}</p>

              {/* Action button */}
              <button
                onClick={() => equipped ? onUnequip(item) : onEquip(item)}
                style={{
                  width: "100%", padding: "9px", borderRadius: 8, cursor: "pointer", border: "none",
                  background: equipped
                    ? "rgba(255,255,255,0.05)"
                    : `linear-gradient(135deg, ${rc.color}, ${rc.color}cc)`,
                  color: equipped ? "rgba(255,255,255,0.4)" : "#000",
                  fontSize: 11, fontWeight: 700, letterSpacing: 1,
                  fontFamily: "var(--f-dis)",
                  transition: "all 0.2s",
                }}
              >
                {equipped ? "Ô£ô D├ëS├ëQUIPER" : "ÔÜí ├ëQUIPER"}
              </button>
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}

// ÔöÇÔöÇÔöÇ MAIN STORE ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export default function Store() {
  const { profile, setProfile, refreshProfile }   = useOutletContext();
  const [tab, setTab]             = useState("all");
  const [items, setItems]         = useState([]);
  const [userItems, setUserItems] = useState([]);
  const [dailyItems, setDailyItems] = useState([]);
  const [coins, setCoins]         = useState(0);
  const [loading, setLoading]     = useState(true);
  const [sort, setSort]           = useState("rarity");
  const [notification, setNotification] = useState(null);
  const [confirmItem, setConfirmItem]   = useState(null);

  useEffect(() => {
    fetchAll();
    fetchCoins();
  }, []);

  const fetchCoins = async () => {
    const { data } = await supabase.from("wallets")
      .select("balance").eq("user_id", profile.id).maybeSingle();
    setCoins(data?.balance || 0);
  };

  const fetchAll = async () => {
    setLoading(true);

    const { data: storeData } = await supabase
      .from("store_items")
      .select("*")
      .eq("active", true)
      .eq("approved", true)
      .order("sort_order", { ascending: true });

    const { data: owned } = await supabase
      .from("user_items")
      .select("*, item:store_items(*)")
      .eq("user_id", profile.id);

    const { data: daily } = await supabase
      .from("daily_store")
      .select("*, item:store_items(*)")
      .eq("date", new Date().toISOString().split("T")[0]);

    setItems(storeData || []);
    setUserItems(owned || []);
    setDailyItems(daily?.filter(d => d.item) || []);
    setLoading(false);
  };

  const notify = (msg, type = "success") => {
    setNotification({ msg, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const handleBuy = async (item) => {
    setConfirmItem(item);
  };

  const confirmBuy = async () => {
    if (!confirmItem) return;
    const { data, error } = await supabase.rpc("purchase_item", {
      p_item_id: confirmItem.id,
    });

    setConfirmItem(null);

    if (error || !data?.success) {
      notify(data?.error || error?.message || "Erreur", "error");
      return;
    }

    notify(`Ô£à ${confirmItem.name} achet├® !`);
    await fetchAll();
    await fetchCoins();
    if (refreshProfile) refreshProfile();
  };

  const handleEquip = async (item) => {
    const { data, error } = await supabase.rpc("equip_item", {
      p_item_id: item.id,
    });

    if (error || !data?.success) {
      notify(data?.error || "Erreur d'├®quipement", "error");
      return;
    }

    notify(`ÔÜí ${item.name} ├®quip├® !`);
    await fetchAll();
    if (refreshProfile) refreshProfile();
  };

  const isOwned   = (id) => userItems.some(u => u.item_id === id);
  const isEquipped = (id) => userItems.some(u => u.item_id === id && u.equipped);

  const filtered = items
    .filter(item => tab === "all" || item.type === tab)
    .sort((a, b) => {
      if (sort === "rarity")  return RARITY_ORDER[b.rarity] - RARITY_ORDER[a.rarity];
      if (sort === "price_asc") return a.price - b.price;
      if (sort === "price_desc") return b.price - a.price;
      return 0;
    });

  const ownedCount = userItems.length;
  const totalItems = items.length;

  return (
    <>
      <div style={{ minHeight: "100vh", background: "var(--bg)", color: "var(--t1)", fontFamily: "var(--f-ui)" }}>

        {/* ÔöÇÔöÇ Notification toast ÔöÇÔöÇ */}
        <AnimatePresence>
          {notification && (
            <motion.div
              initial={{ opacity: 0, y: -40, x: "-50%" }}
              animate={{ opacity: 1, y: 0, x: "-50%" }}
              exit={{ opacity: 0, y: -40, x: "-50%" }}
              style={{
                position: "fixed", top: 20, left: "50%", zIndex: 9999,
                padding: "12px 24px", borderRadius: 12,
                background: notification.type === "error" ? "rgba(229,64,64,0.08)" : "rgba(16,16,26,0.96)",
                border: `1px solid ${notification.type === "error" ? "rgba(229,64,64,0.40)" : "var(--accent-3)"}`,
                color: notification.type === "error" ? "var(--s-red)" : "var(--t1)",
                fontSize: 14, fontWeight: 600, fontFamily: "var(--f-ui)",
                backdropFilter: "blur(20px)",
                boxShadow: `0 8px 30px ${notification.type === "error" ? "rgba(229,64,64,0.20)" : "rgba(255,79,0,0.15)"}`,
              }}
            >
              {notification.msg}
            </motion.div>
          )}
        </AnimatePresence>

        {/* ÔöÇÔöÇ Confirm modal ÔöÇÔöÇ */}
        <AnimatePresence>
          {confirmItem && (
            <motion.div
              initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              style={{
                position: "fixed", inset: 0, background: "rgba(0,0,0,0.8)",
                backdropFilter: "blur(8px)", zIndex: 200,
                display: "flex", alignItems: "center", justifyContent: "center",
              }}
              onClick={() => setConfirmItem(null)}
            >
              <motion.div
                initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }} exit={{ scale: 0.9 }}
                onClick={e => e.stopPropagation()}
                style={{
                  width: "min(380px,90vw)", background: "rgba(16,16,26,0.97)",
                  border: `1px solid ${RARITY[confirmItem.rarity]?.color || "var(--accent)"}40`,
                  borderRadius: 20, padding: 32, backdropFilter: "blur(24px)",
                  boxShadow: `0 20px 60px rgba(0,0,0,0.60), 0 0 40px ${RARITY[confirmItem.rarity]?.glow || "rgba(255,79,0,0.15)"}`,
                }}
              >
                <div style={{ textAlign: "center", marginBottom: 24 }}>
                  <div style={{ fontSize: 52, marginBottom: 12 }}>­ƒøÆ</div>
                  <h3 style={{ fontFamily: "var(--f-dis)", fontSize: 20, fontWeight: 900, color: "var(--t1)", marginBottom: 8, letterSpacing: 1 }}>
                    CONFIRMER L'ACHAT
                  </h3>
                  <p style={{ color: "rgba(255,255,255,0.5)", fontSize: 13 }}>
                    Vous achetez <strong style={{ color: "#fff" }}>{confirmItem.name}</strong>
                  </p>
                </div>

                <div style={{
                  display: "flex", alignItems: "center", justifyContent: "space-between",
                  padding: "12px 16px", borderRadius: 10,
                  background: "rgba(245,158,11,0.08)", border: "1px solid rgba(245,158,11,0.2)",
                  marginBottom: 24,
                }}>
                  <span style={{ color: "rgba(255,255,255,0.5)", fontSize: 13 }}>Prix</span>
                  <span style={{ color: "var(--s-gold)", fontFamily: "var(--f-dis)", fontWeight: 800, fontSize: 20 }}>
                    ­ƒÆ░ {confirmItem.price.toLocaleString()}
                  </span>
                </div>

                <div style={{
                  display: "flex", alignItems: "center", justifyContent: "space-between",
                  padding: "10px 16px", borderRadius: 10,
                  background: "rgba(255,255,255,0.03)", marginBottom: 24,
                }}>
                  <span style={{ color: "rgba(255,255,255,0.4)", fontSize: 12 }}>Solde apr├¿s achat</span>
                  <span style={{
                    fontWeight: 700, fontSize: 14,
                    color: (coins - confirmItem.price) < 0 ? "#ef4444" : "#10b981",
                  }}>
                    ­ƒÆ░ {(coins - confirmItem.price).toLocaleString()}
                  </span>
                </div>

                <div style={{ display: "flex", gap: 12 }}>
                  <button
                    onClick={() => setConfirmItem(null)}
                    style={{
                      flex: 1, padding: "12px", borderRadius: 10,
                      background: "transparent", border: "1px solid rgba(255,255,255,0.1)",
                      color: "rgba(255,255,255,0.5)", fontSize: 13, fontWeight: 600,
                      cursor: "pointer", transition: "all 0.2s",
                    }}
                    onMouseEnter={e => e.target.style.borderColor = "rgba(255,255,255,0.3)"}
                    onMouseLeave={e => e.target.style.borderColor = "rgba(255,255,255,0.1)"}
                  >
                    ANNULER
                  </button>
                  <button
                    onClick={confirmBuy}
                    style={{
                      flex: 1, padding: "12px", borderRadius: 10,
                      background: "var(--accent)",
                      border: "none", color: "#fff", fontSize: 13, fontWeight: 700,
                      cursor: "pointer", letterSpacing: "0.05em",
                      boxShadow: "0 4px 16px rgba(255,79,0,0.30)",
                    }}
                  >
                    ACHETER
                  </button>
                </div>
              </motion.div>
            </motion.div>
          )}
        </AnimatePresence>

        {/* ÔöÇÔöÇ HERO HEADER ÔöÇÔöÇ */}
        <div style={{
          position: "relative", overflow: "hidden",
          padding: "36px 32px 28px",
          background: "linear-gradient(180deg, rgba(255,79,0,0.07) 0%, transparent 100%)",
          borderBottom: "1px solid rgba(255,255,255,0.07)",
        }}>
          <div style={{ position: "absolute", inset: 0, overflow: "hidden", pointerEvents: "none" }}>
            <div style={{ position: "absolute", top: -60, right: -60, width: 280, height: 280, borderRadius: "50%", background: "radial-gradient(circle, rgba(255,79,0,0.10), transparent 70%)" }} />
          </div>

          <div style={{ position: "relative", maxWidth: 1200, margin: "0 auto" }}>
            <div style={{ display: "flex", alignItems: "flex-end", justifyContent: "space-between", flexWrap: "wrap", gap: 16 }}>
              <div>
                <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 8 }}>
                  <div style={{
                    width: 44, height: 44, borderRadius: 12,
                    background: "var(--accent)",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontSize: 22, boxShadow: "0 8px 25px rgba(255,79,0,0.30)",
                  }}>
                    ­ƒÅ¬
                  </div>
                  <div>
                    <h1 style={{
                      fontFamily: "var(--f-dis)", fontSize: 26, fontWeight: 900,
                      color: "var(--t1)", letterSpacing: 3, margin: 0,
                    }}>
                      CIPHER<span style={{ color: "var(--accent)" }}>STORE</span>
                    </h1>
                    <p style={{ color: "var(--t4)", fontSize: 11, letterSpacing: "0.12em", margin: 0, fontWeight: 600, textTransform: "uppercase" }}>
                      Cosm├®tiques ┬À No Pay2Win
                    </p>
                  </div>
                </div>
              </div>

              {/* Wallet + stats */}
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <div style={{
                  padding: "10px 18px", borderRadius: 12,
                  background: "rgba(232,160,32,0.08)", border: "1px solid rgba(232,160,32,0.22)",
                }}>
                  <div style={{ fontSize: 9, color: "var(--t4)", letterSpacing: "0.09em", marginBottom: 2, fontWeight: 700, textTransform: "uppercase" }}>Mon solde</div>
                  <div style={{ fontFamily: "var(--f-dis)", fontWeight: 800, fontSize: 17, color: "var(--s-gold)" }}>
                    ­ƒÆ░ {coins.toLocaleString()}
                  </div>
                </div>

                <div style={{
                  padding: "10px 16px", borderRadius: 12,
                  background: "var(--accent-2)", border: "1px solid var(--accent-3)",
                }}>
                  <div style={{ fontSize: 9, color: "var(--t4)", letterSpacing: "0.09em", marginBottom: 2, fontWeight: 700, textTransform: "uppercase" }}>Collection</div>
                  <div style={{ fontFamily: "var(--f-dis)", fontWeight: 800, fontSize: 17, color: "var(--accent)" }}>
                    {ownedCount} / {totalItems}
                  </div>
                </div>
              </div>
            </div>

            {/* Daily items banner */}
            {dailyItems.length > 0 && (
              <div style={{
                marginTop: 12, padding: "10px 14px", borderRadius: 12,
                background: "linear-gradient(135deg, rgba(239,68,68,0.1), rgba(245,158,11,0.1))",
                border: "1px solid rgba(239,68,68,0.25)",
                display: "flex", alignItems: "center", gap: 12,
              }}>
                <span style={{ fontSize: 18 }}>ÔÜí</span>
                <div>
                  <span style={{ fontSize: 11, fontWeight: 700, color: "#ef4444", letterSpacing: 1.5 }}>
                    OFFRES DU JOUR
                  </span>
                  <span style={{ color: "rgba(255,255,255,0.5)", fontSize: 11, marginLeft: 8 }}>
                    {dailyItems.map(d => d.item?.name).join(" ÔÇó ")}
                  </span>
                </div>
                <span style={{
                  marginLeft: "auto", fontSize: 11, color: "#f59e0b", fontWeight: 700,
                  padding: "3px 8px", borderRadius: 6, background: "rgba(245,158,11,0.1)",
                }}>
                  SE RENOUVELLE DANS 24H
                </span>
              </div>
            )}
          </div>
        </div>

        {/* ÔöÇÔöÇ TABS + FILTERS ÔöÇÔöÇ */}
        <div style={{
          position: "sticky", top: 0, zIndex: 10,
          background: "rgba(8,8,14,0.97)", backdropFilter: "blur(20px) saturate(1.6)",
          borderBottom: "1px solid rgba(255,255,255,0.07)",
          padding: "0 32px",
        }}>
          <div style={{ maxWidth: 1200, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            {/* Tabs */}
            <div style={{ display: "flex", gap: 2, overflowX: "auto" }}>
              {TABS.map(t => (
                <button
                  key={t.key}
                  onClick={() => setTab(t.key)}
                  style={{
                    padding: "7px 14px",
                    background: tab === t.key ? "var(--accent)" : "transparent",
                    border: `1px solid ${tab === t.key ? "transparent" : "rgba(255,255,255,0.07)"}`,
                    borderRadius: 99, margin: "6px 0",
                    color: tab === t.key ? "#fff" : "var(--t3)",
                    fontSize: 11, fontWeight: 700, letterSpacing: "0.04em",
                    cursor: "pointer", transition: "all 0.18s", whiteSpace: "nowrap",
                    fontFamily: "var(--f-ui)",
                    display: "flex", alignItems: "center", gap: 6,
                    boxShadow: tab === t.key ? "0 3px 12px rgba(255,79,0,0.25)" : "none",
                  }}
                >
                  <span>{t.icon}</span>
                  <span>{t.label}</span>
                </button>
              ))}
            </div>

            {/* Sort */}
            <select
              value={sort}
              onChange={e => setSort(e.target.value)}
              style={{
                padding: "8px 12px", borderRadius: 8, fontSize: 11,
                background: "var(--sf-2)", border: "1px solid var(--ln-1)",
                color: "var(--t2)", cursor: "pointer", outline: "none",
                fontFamily: "var(--f-ui)", letterSpacing: "0.04em",
              }}
            >
              <option value="rarity">RARET├ë Ôåô</option>
              <option value="price_asc">PRIX Ôåæ</option>
              <option value="price_desc">PRIX Ôåô</option>
            </select>
          </div>
        </div>

        {/* ÔöÇÔöÇ FEATURED ITEM (all tab only) ÔöÇÔöÇ */}
        {tab === "all" && (() => {
          const RARITY_ORDER_L = { common:0, rare:1, epic:2, legendary:3 };
          const featured = [...items].filter(i => ["legendary","epic"].includes(i.rarity))
            .sort((a,b) => (RARITY_ORDER_L[b.rarity]||0) - (RARITY_ORDER_L[a.rarity]||0))[0];
          if (!featured) return null;
          const rc = RARITY[featured.rarity] || RARITY.common;
          const isOwned = userItems.some(u => u.item_id === featured.id);
          return (
            <div style={{ maxWidth:1200, margin:"0 auto", padding:"0 clamp(12px,3vw,28px) 10px" }}>
              <div style={{
                background:`linear-gradient(135deg,${rc.bg},rgba(255,255,255,0.02))`,
                border:`1px solid ${rc.color}35`, borderRadius:16,
                padding:"14px 18px", display:"flex", alignItems:"center", gap:14,
                flexWrap:"wrap", boxShadow:`0 6px 28px ${rc.glow}`,
                position:"relative", overflow:"hidden",
              }}>
                <span style={{ position:"absolute", top:8, left:14, fontSize:9,
                  fontWeight:800, letterSpacing:1.5, color:rc.color,
                  background:`${rc.color}15`, padding:"3px 8px", borderRadius:99 }}>
                  Ô¡É FEATURED
                </span>
                <div style={{ width:64, height:64, borderRadius:12, marginTop:10, flexShrink:0,
                  background:`${rc.color}12`, border:`1px solid ${rc.color}28`,
                  display:"flex", alignItems:"center", justifyContent:"center" }}>
                  {featured.image_url
                    ? <img src={featured.image_url} alt="" style={{ width:"100%", height:"100%", objectFit:"cover", borderRadius:10 }}/>
                    : <span style={{ fontSize:28 }}>
                        {featured.type==="avatar"?"­ƒÄ¡":featured.type==="banner"?"­ƒû╝´©Å":
                         featured.type==="frame"?"­ƒÆá":featured.type==="badge"?"­ƒÅà":"Ô£¿"}
                      </span>}
                </div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:9, fontWeight:800, color:rc.color, letterSpacing:1.5, marginBottom:3 }}>{rc.label}</div>
                  <div style={{ fontSize:15, fontWeight:800, color:"#fff", marginBottom:3,
                    overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                    {featured.name}
                  </div>
                  <div style={{ display:"flex", alignItems:"center", gap:10, flexWrap:"wrap" }}>
                    <span style={{ fontSize:14, fontWeight:800, color:"#f59e0b" }}>
                      ­ƒÆ░ {featured.source==="store" ? featured.price?.toLocaleString() : "GRATUIT"}
                    </span>
                    {!isOwned
                      ? <button onClick={() => setConfirmItem(featured)}
                          style={{ padding:"6px 16px", borderRadius:8, border:"none",
                            background:`linear-gradient(135deg,${rc.color},${rc.color}aa)`,
                            color:"#fff", fontSize:12, fontWeight:800, cursor:"pointer" }}>
                          Acheter ÔåÆ
                        </button>
                      : <span style={{ fontSize:11, color:rc.color, fontWeight:700 }}>Ô£ô Poss├®d├®</span>
                    }
                  </div>
                </div>
              </div>
            </div>
          );
        })()}

        {/* ÔöÇÔöÇ ITEMS GRID ÔöÇÔöÇ */}
        <div style={{ maxWidth: 1200, margin: "0 auto", padding:"clamp(10px,3vw,24px) clamp(12px,3vw,28px)" }}>

          {/* ÔöÇÔöÇ INVENTORY TAB ÔöÇÔöÇ */}
          {tab === "inventory" ? (
            <InventoryView
              userItems={userItems}
              items={items}
              onEquip={handleEquip}
              onUnequip={async (item) => {
                const { data, error } = await supabase
                  .from("user_items")
                  .update({ equipped: false })
                  .eq("user_id", (await supabase.auth.getUser()).data.user?.id)
                  .eq("item_id", item.id);
                if (!error) { notify(`${item.name} d├®s├®quip├®`); await fetchAll(); }
              }}
            />
          ) : loading ? (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", gap: 16 }}>
              {Array.from({ length: 8 }).map((_, i) => (
                <div key={i} style={{
                  height: 280, borderRadius: 14, background: "rgba(255,255,255,0.03)",
                  border: "1px solid rgba(255,255,255,0.05)",
                  animation: "pulse 1.5s ease infinite",
                }} />
              ))}
              <style>{`@keyframes pulse { 0%,100%{opacity:0.5} 50%{opacity:1} }`}</style>
            </div>
          ) : filtered.length === 0 ? (
            <div style={{ textAlign: "center", padding: "80px 0" }}>
              <div style={{ fontSize: 64, marginBottom: 16 }}>­ƒøÆ</div>
              <p style={{ color: "rgba(255,255,255,0.3)", fontSize: 16, letterSpacing: 2 }}>
                AUCUN ITEM DANS CETTE CAT├ëGORIE
              </p>
            </div>
          ) : (
            <>
              {/* Rarity sections */}
              {["legendary","epic","rare","common"].map(r => {
                const section = filtered.filter(i => i.rarity === r);
                if (section.length === 0) return null;
                const rc = RARITY[r];
                return (
                  <div key={r} style={{ marginBottom: 40 }}>
                    <div style={{
                      display: "flex", alignItems: "center", gap: 12, marginBottom: 16,
                    }}>
                      <div style={{ height: 1, flex: 1, background: `linear-gradient(90deg, ${rc.color}40, transparent)` }} />
                      <span style={{
                        fontSize: 11, fontWeight: 700, letterSpacing: 2.5,
                        color: rc.color, fontFamily: "var(--f-dis)",
                        padding: "4px 14px", borderRadius: 99,
                        background: rc.bg, border: `1px solid ${rc.color}30`,
                      }}>
                        Ôùå {rc.label}
                      </span>
                      <div style={{ height: 1, flex: 1, background: `linear-gradient(90deg, transparent, ${rc.color}40)` }} />
                    </div>

                    <motion.div
                      layout
                      style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(220px, 1fr))", gap: 16 }}
                    >
                      {section.map(item => (
                        <ItemCard
                          key={item.id}
                          item={item}
                          owned={isOwned(item.id)}
                          equipped={isEquipped(item.id)}
                          onBuy={handleBuy}
                          onEquip={handleEquip}
                          coins={coins}
                        />
                      ))}
                    </motion.div>
                  </div>
                );
              })}
            </>
          )}
        </div>
      </div>
    </>
  );
}

import { useState, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useOutletContext } from "react-router-dom";
import { supabase } from "../lib/supabase";

const BG    = "#020817"; const SURF  = "#060f23"; const CARD  = "#0a1628";
const CYAN  = "#00d4ff"; const INDIGO= "#818cf8"; const GREEN = "#10b981";
const RED   = "#f43f5e"; const AMBER = "#fbbf24"; const VIOLET= "#a78bfa";
const cx = a => `rgba(0,212,255,${a})`;
const gx = a => `rgba(16,185,129,${a})`;
const ax = a => `rgba(251,191,36,${a})`;

// Free Fire placement points
const PLACEMENT_PTS = [0,12,9,8,7,6,5,4,3,2,1,0,0];
const calcPoints = (placement, kills) => (PLACEMENT_PTS[placement]||0) + (kills||0);

const G = ({ children, ac=CYAN, style={}, ...p }) => (
  <div style={{
    background: CARD, borderRadius:16,
    border: `1px solid ${ac}22`,
    boxShadow: `0 0 30px ${ac}08`,
    ...style
  }} {...p}>{children}</div>
);

export default function SubmitResult() {
  const { profile } = useOutletContext();
  const [step, setStep]           = useState(1); // 1=form 2=preview 3=success
  const [tournamentId, setTournamentId] = useState("");
  const [matchNum, setMatchNum]   = useState(1);
  const [placement, setPlacement] = useState(1);
  const [kills, setKills]         = useState(0);
  const [screenshot, setScreenshot] = useState(null);
  const [screenshotUrl, setScreenshotUrl] = useState("");
  const [uploading, setUploading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError]         = useState("");
  const [result, setResult]       = useState(null);
  const fileRef = useRef();

  const points = calcPoints(placement, kills);

  const handleFile = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (!file.type.startsWith("image/")) { setError("Image uniquement"); return; }
    if (file.size > 5 * 1024 * 1024) { setError("Max 5MB"); return; }
    setScreenshot(file);
    // Preview
    const reader = new FileReader();
    reader.onload = ev => setScreenshotUrl(ev.target.result);
    reader.readAsDataURL(file);
  };

  const uploadScreenshot = async () => {
    if (!screenshot) return null;
    setUploading(true);
    const ext = screenshot.name.split(".").pop();
    const path = `match-results/${profile.id}/${Date.now()}.${ext}`;
    const { data, error: upErr } = await supabase.storage
      .from("screenshots")
      .upload(path, screenshot, { cacheControl: "3600", upsert: false });
    setUploading(false);
    if (upErr) { setError("Erreur upload: " + upErr.message); return null; }
    const { data: { publicUrl } } = supabase.storage.from("screenshots").getPublicUrl(path);
    return publicUrl;
  };

  const handleSubmit = async () => {
    if (!tournamentId.trim()) { setError("Tournament ID requis"); return; }
    setSubmitting(true); setError("");
    try {
      let imgUrl = screenshotUrl && screenshot ? await uploadScreenshot() : null;

      const { data, error: rpcErr } = await supabase.rpc("submit_match_result", {
        p_tournament_id:   tournamentId.trim(),
        p_match_number:    matchNum,
        p_team_id:         profile.team_id || null,
        p_placement:       placement,
        p_kills:           kills,
        p_screenshot_url:  imgUrl,
      });

      if (rpcErr) throw rpcErr;
      if (!data?.success) throw new Error(data?.error || "Erreur soumission");

      setResult(data);
      setStep(3);
    } catch(e) { setError(e.message); }
    finally { setSubmitting(false); }
  };

  const PlacementBadge = ({ pos }) => {
    const colors = { 1:AMBER, 2:"#c0c0c0", 3:"#cd7f32" };
    const color = colors[pos] || "rgba(255,255,255,.4)";
    return (
      <motion.button
        whileHover={{ scale: 1.08 }} whileTap={{ scale: .95 }}
        onClick={() => setPlacement(pos)}
        style={{
          width: 52, height: 52, borderRadius: 12,
          background: placement === pos ? `${color}22` : "rgba(255,255,255,.03)",
          border: `2px solid ${placement === pos ? color : "rgba(255,255,255,.08)"}`,
          color: placement === pos ? color : "rgba(255,255,255,.3)",
          fontFamily: "Bebas Neue,cursive", fontSize: 22,
          cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center",
          flexDirection: "column", gap: 0,
          boxShadow: placement === pos ? `0 0 16px ${color}44` : "none",
          transition: "all .15s"
        }}
      >
        <span>{pos}</span>
        {pos <= 3 && <span style={{ fontSize: 8, marginTop: -2 }}>
          {pos===1?"­ƒææ":pos===2?"­ƒÑê":"­ƒÑë"}
        </span>}
      </motion.button>
    );
  };

  return (
    <div style={{ minHeight:"100vh", background:BG, padding:"clamp(14px,4vw,32px) clamp(12px,3vw,24px)", fontFamily:"Space Grotesk,sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&family=Space+Grotesk:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap');
        input[type=number]::-webkit-inner-spin-button { -webkit-appearance:none; }
        input:focus, textarea:focus { outline:none; }
      `}</style>

      <div style={{ maxWidth: 680, margin: "0 auto" }}>

        {/* Header */}
        <motion.div initial={{ opacity:0, y:-16 }} animate={{ opacity:1, y:0 }} style={{ marginBottom: 32 }}>
          <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:3, color:cx(.4), marginBottom:8 }}>
            ­ƒÄ« R├ëSULTATS DE MATCH
          </p>
          <h1 style={{ fontFamily:"Bebas Neue,cursive", fontSize:42, letterSpacing:2, color:"#fff", margin:0, lineHeight:1 }}>
            SOUMETTRE <span style={{ color:CYAN }}>R├ëSULTAT</span>
          </h1>
          <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:10, color:"rgba(255,255,255,.25)", marginTop:8, letterSpacing:1 }}>
            Les r├®sultats seront v├®rifi├®s par un admin avant validation
          </p>
        </motion.div>

        {/* Steps */}
        <div style={{ display:"flex", gap:8, marginBottom:28 }}>
          {["INFOS","APER├çU","ENVOY├ë"].map((s,i) => (
            <div key={i} style={{ flex:1, padding:"10px 0", borderRadius:10, textAlign:"center",
              background: step > i ? cx(.12) : "rgba(255,255,255,.03)",
              border: `1px solid ${step > i ? cx(.3) : "rgba(255,255,255,.06)"}`,
              fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:2,
              color: step > i ? CYAN : "rgba(255,255,255,.2)" }}>
              {i+1}. {s}
            </div>
          ))}
        </div>

        <AnimatePresence mode="wait">

          {/* ÔöÇÔöÇ STEP 1: FORM ÔöÇÔöÇ */}
          {step === 1 && (
            <motion.div key="step1" initial={{ opacity:0,x:20 }} animate={{ opacity:1,x:0 }} exit={{ opacity:0,x:-20 }}>

              {/* Tournament ID */}
              <G style={{ padding:"22px 24px", marginBottom:14 }}>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:2, color:VIOLET, marginBottom:14 }}>
                  ­ƒôï TOURNOI
                </p>
                <div style={{ marginBottom:14 }}>
                  <label style={{ display:"block", fontFamily:"JetBrains Mono,monospace", fontSize:8, letterSpacing:2, color:"rgba(255,255,255,.25)", marginBottom:7 }}>
                    TOURNAMENT ID
                  </label>
                  <input value={tournamentId} onChange={e=>setTournamentId(e.target.value)}
                    placeholder="Coller l'ID du tournoi"
                    style={{ width:"100%", padding:"12px 16px", borderRadius:10, background:"rgba(129,140,248,.05)", border:`1px solid rgba(129,140,248,.2)`, color:"#fff", fontFamily:"JetBrains Mono,monospace", fontSize:12, boxSizing:"border-box", letterSpacing:1 }}
                  />
                </div>
                <div>
                  <label style={{ display:"block", fontFamily:"JetBrains Mono,monospace", fontSize:8, letterSpacing:2, color:"rgba(255,255,255,.25)", marginBottom:7 }}>
                    NUM├ëRO DE MATCH
                  </label>
                  <div style={{ display:"flex", gap:8 }}>
                    {[1,2,3,4,5,6].map(n => (
                      <motion.button key={n} whileHover={{scale:1.08}} whileTap={{scale:.95}}
                        onClick={() => setMatchNum(n)}
                        style={{ flex:1, padding:"10px 0", borderRadius:9, fontFamily:"Bebas Neue,cursive", fontSize:18,
                          background: matchNum===n ? "rgba(129,140,248,.15)" : "rgba(255,255,255,.03)",
                          border: `1px solid ${matchNum===n?"rgba(129,140,248,.4)":"rgba(255,255,255,.07)"}`,
                          color: matchNum===n ? INDIGO : "rgba(255,255,255,.3)", cursor:"pointer" }}>
                        {n}
                      </motion.button>
                    ))}
                  </div>
                </div>
              </G>

              {/* Placement */}
              <G style={{ padding:"22px 24px", marginBottom:14 }}>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:2, color:AMBER, marginBottom:14 }}>
                  ­ƒÅå CLASSEMENT FINAL
                </p>
                <div style={{ display:"flex", flexWrap:"wrap", gap:8 }}>
                  {Array.from({length:12},(_,i)=>i+1).map(pos => (
                    <PlacementBadge key={pos} pos={pos} />
                  ))}
                </div>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:ax(.6), marginTop:12, letterSpacing:1 }}>
                  {placement <= 3 ? `­ƒÅå TOP ${placement} ÔÇö +${PLACEMENT_PTS[placement]} pts placement` : `+${PLACEMENT_PTS[placement]||0} pts placement`}
                </p>
              </G>

              {/* Kills */}
              <G style={{ padding:"22px 24px", marginBottom:14 }}>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:2, color:RED, marginBottom:14 }}>
                  ­ƒÆÇ NOMBRE DE KILLS
                </p>
                <div style={{ display:"flex", alignItems:"center", gap:16 }}>
                  <motion.button whileHover={{scale:1.1}} whileTap={{scale:.9}}
                    onClick={() => setKills(k => Math.max(0, k-1))}
                    style={{ width:44, height:44, borderRadius:10, background:"rgba(244,63,94,.1)", border:"1px solid rgba(244,63,94,.25)", color:RED, fontSize:22, cursor:"pointer", fontFamily:"Bebas Neue,cursive" }}>
                    ÔêÆ
                  </motion.button>
                  <input type="number" value={kills} onChange={e=>setKills(Math.max(0,Math.min(99,+e.target.value||0)))}
                    style={{ flex:1, padding:"14px 0", textAlign:"center", borderRadius:12, background:"rgba(244,63,94,.05)", border:"1px solid rgba(244,63,94,.15)", color:"#fff", fontFamily:"Bebas Neue,cursive", fontSize:36, letterSpacing:2 }} />
                  <motion.button whileHover={{scale:1.1}} whileTap={{scale:.9}}
                    onClick={() => setKills(k => Math.min(99, k+1))}
                    style={{ width:44, height:44, borderRadius:10, background:gx(.1), border:`1px solid ${gx(.25)}`, color:GREEN, fontSize:22, cursor:"pointer", fontFamily:"Bebas Neue,cursive" }}>
                    +
                  </motion.button>
                </div>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:"rgba(244,63,94,.6)", marginTop:10, letterSpacing:1 }}>
                  +{kills} pts kills
                </p>
              </G>

              {/* Screenshot */}
              <G style={{ padding:"22px 24px", marginBottom:14 }}>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:2, color:cx(.7), marginBottom:14 }}>
                  ­ƒô© SCREENSHOT PREUVE
                </p>
                <input ref={fileRef} type="file" accept="image/*" onChange={handleFile} style={{ display:"none" }} />
                {screenshotUrl ? (
                  <div style={{ position:"relative" }}>
                    <img src={screenshotUrl} alt="screenshot"
                      style={{ width:"100%", borderRadius:12, objectFit:"cover", maxHeight:220, border:`1px solid ${cx(.2)}` }} />
                    <motion.button whileHover={{scale:1.05}} onClick={() => { setScreenshot(null); setScreenshotUrl(""); }}
                      style={{ position:"absolute", top:10, right:10, padding:"6px 12px", borderRadius:8, background:"rgba(244,63,94,.8)", border:"none", color:"#fff", fontSize:11, cursor:"pointer", fontFamily:"JetBrains Mono,monospace" }}>
                      Ô£ò CHANGER
                    </motion.button>
                  </div>
                ) : (
                  <motion.div whileHover={{ borderColor:CYAN, background:cx(.04) }}
                    onClick={() => fileRef.current?.click()}
                    style={{ border:`2px dashed ${cx(.15)}`, borderRadius:14, padding:"36px 24px", textAlign:"center", cursor:"pointer", transition:"all .2s" }}>
                    <p style={{ fontSize:32, marginBottom:8 }}>­ƒô©</p>
                    <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:10, color:"rgba(255,255,255,.3)", letterSpacing:1 }}>
                      CLIQUEZ POUR UPLOADER
                    </p>
                    <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:"rgba(255,255,255,.15)", marginTop:6, letterSpacing:1 }}>
                      Scoreboard ou Room Result ┬À Max 5MB
                    </p>
                  </motion.div>
                )}
              </G>

              {/* Points preview */}
              <G ac={points > 0 ? CYAN : "rgba(255,255,255,.1)"} style={{ padding:"18px 24px", marginBottom:20, display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                <div>
                  <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, letterSpacing:2, color:"rgba(255,255,255,.25)", marginBottom:4 }}>TOTAL ESTIM├ë</p>
                  <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:"rgba(255,255,255,.4)", letterSpacing:1 }}>
                    {PLACEMENT_PTS[placement]||0} placement + {kills} kills
                  </p>
                </div>
                <div style={{ textAlign:"right" }}>
                  <p style={{ fontFamily:"Bebas Neue,cursive", fontSize:48, color: points > 0 ? CYAN : "rgba(255,255,255,.15)", lineHeight:1, letterSpacing:2, textShadow: points > 0 ? `0 0 20px ${CYAN}66` : "none" }}>
                    {points}
                  </p>
                  <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:8, color:"rgba(255,255,255,.2)", letterSpacing:1 }}>POINTS</p>
                </div>
              </G>

              {error && (
                <div style={{ padding:"12px 16px", borderRadius:10, background:"rgba(244,63,94,.1)", border:"1px solid rgba(244,63,94,.2)", color:RED, fontFamily:"Space Grotesk,sans-serif", fontSize:13, marginBottom:16 }}>
                  ÔØî {error}
                </div>
              )}

              <motion.button whileHover={{scale:1.02}} whileTap={{scale:.97}}
                onClick={() => { if(!tournamentId.trim()){setError("Tournament ID requis");return;} setError(""); setStep(2); }}
                style={{ width:"100%", padding:"16px 0", borderRadius:13, background:`linear-gradient(135deg,${CYAN},${INDIGO})`, border:"none", color:"#000", fontFamily:"JetBrains Mono,monospace", fontSize:12, letterSpacing:2, fontWeight:700, cursor:"pointer", boxShadow:`0 8px 32px ${cx(.3)}` }}>
                APER├çU AVANT ENVOI ÔåÆ
              </motion.button>
            </motion.div>
          )}

          {/* ÔöÇÔöÇ STEP 2: PREVIEW ÔöÇÔöÇ */}
          {step === 2 && (
            <motion.div key="step2" initial={{ opacity:0,x:20 }} animate={{ opacity:1,x:0 }} exit={{ opacity:0,x:-20 }}>
              <G style={{ padding:"28px 28px", marginBottom:16 }}>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:2, color:AMBER, marginBottom:20 }}>
                  ­ƒæü´©Å V├ëRIFICATION AVANT SOUMISSION
                </p>

                {[
                  ["TOURNOI", tournamentId.slice(0,20)+"...", VIOLET],
                  ["MATCH", `Match #${matchNum}`, INDIGO],
                  ["CLASSEMENT", `${placement}├¿me place`, placement<=3?AMBER:cx(.7)],
                  ["KILLS", `${kills} kills`, RED],
                  ["POINTS CALCUL├ëS", `${points} pts`, CYAN],
                  ["SCREENSHOT", screenshot ? "Ô£à Fourni" : "ÔÜá´©Å Non fourni", screenshot?GREEN:AMBER],
                ].map(([lbl, val, col]) => (
                  <div key={lbl} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"12px 0", borderBottom:"1px solid rgba(255,255,255,.05)" }}>
                    <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, letterSpacing:1.5, color:"rgba(255,255,255,.3)" }}>{lbl}</span>
                    <span style={{ fontFamily:"JetBrains Mono,monospace", fontSize:11, color:col, letterSpacing:1 }}>{val}</span>
                  </div>
                ))}

                <div style={{ marginTop:20, padding:"14px 16px", borderRadius:10, background:"rgba(251,191,36,.06)", border:"1px solid rgba(251,191,36,.15)" }}>
                  <p style={{ fontFamily:"Space Grotesk,sans-serif", fontSize:12, color:"rgba(255,255,255,.5)", lineHeight:1.6, margin:0 }}>
                    ÔÜá´©Å Les r├®sultats soumis seront v├®rifi├®s par un admin. Toute soumission frauduleuse entra├«ne un ban d├®finitif.
                  </p>
                </div>
              </G>

              {screenshotUrl && (
                <G style={{ padding:"16px", marginBottom:16 }}>
                  <img src={screenshotUrl} alt="proof" style={{ width:"100%", borderRadius:10, objectFit:"cover", maxHeight:200 }} />
                </G>
              )}

              {error && (
                <div style={{ padding:"12px 16px", borderRadius:10, background:"rgba(244,63,94,.1)", border:"1px solid rgba(244,63,94,.2)", color:RED, fontFamily:"Space Grotesk,sans-serif", fontSize:13, marginBottom:16 }}>
                  ÔØî {error}
                </div>
              )}

              <div style={{ display:"flex", gap:12 }}>
                <motion.button whileHover={{scale:1.02}} whileTap={{scale:.97}}
                  onClick={() => setStep(1)}
                  style={{ flex:1, padding:"14px 0", borderRadius:12, background:"rgba(255,255,255,.05)", border:"1px solid rgba(255,255,255,.1)", color:"rgba(255,255,255,.6)", fontFamily:"JetBrains Mono,monospace", fontSize:11, letterSpacing:2, cursor:"pointer" }}>
                  ÔåÉ MODIFIER
                </motion.button>
                <motion.button whileHover={{scale:1.02}} whileTap={{scale:.97}}
                  onClick={handleSubmit} disabled={submitting||uploading}
                  style={{ flex:2, padding:"14px 0", borderRadius:12, background:`linear-gradient(135deg,${GREEN},${CYAN})`, border:"none", color:"#000", fontFamily:"JetBrains Mono,monospace", fontSize:11, letterSpacing:2, fontWeight:700, cursor:submitting?"wait":"pointer" }}>
                  {submitting||uploading ? "ENVOI EN COURS..." : "Ô£à CONFIRMER ET ENVOYER"}
                </motion.button>
              </div>
            </motion.div>
          )}

          {/* ÔöÇÔöÇ STEP 3: SUCCESS ÔöÇÔöÇ */}
          {step === 3 && (
            <motion.div key="step3" initial={{ opacity:0, scale:.95 }} animate={{ opacity:1, scale:1 }} style={{ textAlign:"center", padding:"48px 24px" }}>
              <motion.div initial={{ scale:0 }} animate={{ scale:1 }} transition={{ delay:.2, type:"spring" }}
                style={{ fontSize:72, marginBottom:24 }}>
                Ô£à
              </motion.div>
              <h2 style={{ fontFamily:"Bebas Neue,cursive", fontSize:36, color:GREEN, letterSpacing:2, marginBottom:8 }}>
                R├ëSULTAT SOUMIS
              </h2>
              <p style={{ fontFamily:"Space Grotesk,sans-serif", fontSize:14, color:"rgba(255,255,255,.4)", marginBottom:32, lineHeight:1.6 }}>
                Votre r├®sultat est en attente de v├®rification.<br/>
                Un admin va v├®rifier et valider sous 24h.
              </p>
              <G style={{ padding:"24px 28px", marginBottom:28, display:"inline-block", minWidth:280 }}>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:"rgba(255,255,255,.25)", letterSpacing:2, marginBottom:12 }}>POINTS EN ATTENTE</p>
                <p style={{ fontFamily:"Bebas Neue,cursive", fontSize:56, color:CYAN, letterSpacing:2, lineHeight:1, textShadow:`0 0 30px ${CYAN}66` }}>
                  +{result?.points || points}
                </p>
                <p style={{ fontFamily:"JetBrains Mono,monospace", fontSize:9, color:ax(.7), letterSpacing:1, marginTop:4 }}>
                  Ôëê {(result?.points||points) * 10} COINS si valid├®
                </p>
              </G>
              <div style={{ display:"flex", gap:12, justifyContent:"center" }}>
                <motion.button whileHover={{scale:1.04}} onClick={() => { setStep(1); setTournamentId(""); setPlacement(1); setKills(0); setScreenshot(null); setScreenshotUrl(""); setResult(null); }}
                  style={{ padding:"12px 28px", borderRadius:11, background:"rgba(255,255,255,.05)", border:"1px solid rgba(255,255,255,.1)", color:"rgba(255,255,255,.6)", fontFamily:"JetBrains Mono,monospace", fontSize:10, letterSpacing:2, cursor:"pointer" }}>
                  NOUVEAU R├ëSULTAT
                </motion.button>
                <motion.button whileHover={{scale:1.04}} onClick={() => window.location.href="/dashboard"}
                  style={{ padding:"12px 28px", borderRadius:11, background:`linear-gradient(135deg,${CYAN},${INDIGO})`, border:"none", color:"#000", fontFamily:"JetBrains Mono,monospace", fontSize:10, letterSpacing:2, fontWeight:700, cursor:"pointer" }}>
                  TABLEAU DE BORD
                </motion.button>
              </div>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
}

// src/pages/SuperAdmin.jsx ÔÇö Command Center ┬À admin.css design system
import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate, Link } from "react-router-dom";
import { supabase } from "../lib/supabase";
import { motion, AnimatePresence } from "framer-motion";
import {
  Users, UserCheck, UserX, Shield, Crown, Trophy, Swords,
  TicketCheck, AlertTriangle, Coins, Wallet, Settings,
  BarChart2, ClipboardList, Bell, RefreshCw, Eye,
  CheckCircle, XCircle, Ban, Trash2, ChevronRight,
  TrendingUp, Activity, Zap, Star, Plus, Search,
} from "lucide-react";
import "../components/admin/admin.css";

const safeCount = async (query) => {
  try { const r = await query; if (r.error) return 0; return r.count ?? 0; } catch { return 0; }
};

/* ÔöÇÔöÇ Role chip meta ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
const ROLE_BADGE = {
  super_admin: "adm-badge--gold",
  admin:       "adm-badge--cyan",
  founder:     "adm-badge--orange",
  fondateur:   "adm-badge--orange",
  designer:    "adm-badge--violet",
  banned:      "adm-badge--red",
