  { value: "founder",     icon: Zap,     label: "Founder",    desc: "Creates tournaments", cls: "adm-badge--orange" },
  { value: "designer",    icon: Star,    label: "Designer",   desc: "Manages store",     cls: "adm-badge--violet" },
  { value: "admin",       icon: Shield,  label: "Admin",      desc: "Moderation",        cls: "adm-badge--cyan"   },
  { value: "super_admin", icon: Crown,   label: "Super Admin",desc: "Full access",       cls: "adm-badge--gold"   },
  { value: "banned",      icon: Ban,     label: "Banned",     desc: "Access blocked",    cls: "adm-badge--red"    },
];

const STATUS_BADGE = {
  pending:  "adm-badge--orange",
  approved: "adm-badge--green",
  rejected: "adm-badge--red",
  banned:   "adm-badge--red",
};

/* ÔöÇÔöÇ Stat card ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
function StatCard({ icon: Icon, iconCls, cardCls, label, value, onClick, delay = 0 }) {
  return (
    <motion.div
      className={`adm-stat-card ${cardCls || ""} ${onClick ? "adm-stat-card--clickable" : ""}`}
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay }}
      onClick={onClick}
      style={onClick ? { cursor: "pointer" } : {}}
    >
      <div className={`adm-stat-icon ${iconCls || ""}`}>
        <Icon size={16} />
      </div>
      <div className="adm-stat-value">{typeof value === "number" ? value.toLocaleString() : value}</div>
      <div className="adm-stat-label">{label}</div>
    </motion.div>
  );
}

export default function SuperAdmin() {
  const navigate     = useNavigate();
  const intervalRef  = useRef(null);

  const [profile,    setProfile]    = useState(null);
  const [loading,    setLoading]    = useState(true);
  const [activeTab,  setActiveTab]  = useState("dashboard");

  const [users,       setUsers]       = useState([]);
  const [tournaments, setTournaments] = useState([]);
  const [reports,     setReports]     = useState([]);
  const [logs,        setLogs]        = useState([]);
  const [admins,      setAdmins]      = useState([]);

  const [stats, setStats] = useState({
    totalUsers: 0, onlineUsers: 0, bannedUsers: 0,
    pendingVerifications: 0, totalTournaments: 0, activeTournaments: 0,
    totalMatches: 0, totalCoins: 0, totalReports: 0, openTickets: 0,
    newToday: 0, liveMatches: 0, todayRevenue: 0, monthlyRevenue: 0, conversionRate: 0,
  });

  const [lastRefresh, setLastRefresh] = useState(null);

  // Modals
  const [selectedUser,        setSelectedUser]        = useState(null);
  const [selectedTournament,  setSelectedTournament]  = useState(null);
  const [showRoleModal,       setShowRoleModal]       = useState(false);
  const [showBanModal,        setShowBanModal]        = useState(false);
  const [showTournamentModal, setShowTournamentModal] = useState(false);
  const [showWalletModal,     setShowWalletModal]     = useState(false);
  const [showDeleteConfirm,   setShowDeleteConfirm]   = useState(false);
  const [tournamentToDelete,  setTournamentToDelete]  = useState(null);
  const [deleteLoading,       setDeleteLoading]       = useState(false);
  const [showReviewModal,     setShowReviewModal]     = useState(false);
  const [reviewUser,          setReviewUser]          = useState(null);

  const [walletSearch,        setWalletSearch]        = useState("");
  const [banDuration,         setBanDuration]         = useState("24h");
  const [newRole,             setNewRole]             = useState("user");
  const [tournamentStatus,    setTournamentStatus]    = useState("open");
  const [search,              setSearch]              = useState("");
  const [filter,              setFilter]              = useState("all");
  const [msg,                 setMsg]                 = useState({ type: "", text: "" });
  const [grantAmount,         setGrantAmount]         = useState("");
  const [grantReason,         setGrantReason]         = useState("");
  const [maintenanceMode,     setMaintenanceMode]     = useState(false);
  const [registrationEnabled, setRegistrationEnabled] = useState(true);
  const [tournamentsEnabled,  setTournamentsEnabled]  = useState(true);

  /* ÔöÇÔöÇ Data fetchers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
  const fetchStats = useCallback(async () => {
    try {
      const today    = new Date(); today.setHours(0, 0, 0, 0);
      const month    = new Date(); month.setDate(1); month.setHours(0, 0, 0, 0);
      const online15 = new Date(Date.now() - 15 * 60 * 1000);

      const [
        totalUsers, bannedUsers, pendingVerif,
        totalTournaments, activeTournaments,
        totalMatches, liveMatches,
        totalReports, openTickets, newToday, onlineUsers,
      ] = await Promise.all([
        safeCount(supabase.from("profiles").select("*", { count: "exact", head: true })),
        safeCount(supabase.from("profiles").select("*", { count: "exact", head: true }).eq("role", "banned")),
        safeCount(supabase.from("profiles").select("*", { count: "exact", head: true }).eq("verification_status", "pending")),
        safeCount(supabase.from("tournaments").select("*", { count: "exact", head: true })),
        safeCount(supabase.from("tournaments").select("*", { count: "exact", head: true }).eq("status", "open")),
        safeCount(supabase.from("match_results").select("*", { count: "exact", head: true })),
        safeCount(supabase.from("match_results").select("*", { count: "exact", head: true }).eq("status", "pending")),
        safeCount(supabase.from("reports").select("*", { count: "exact", head: true }).eq("status", "pending")),
        safeCount(supabase.from("support_tickets").select("*", { count: "exact", head: true }).in("status", ["open", "pending"])),
        safeCount(supabase.from("profiles").select("*", { count: "exact", head: true }).gte("created_at", today.toISOString())),
        safeCount(supabase.from("profiles").select("*", { count: "exact", head: true }).gte("last_seen", online15.toISOString())),
      ]);

      let totalCoins = 0;
      try { const { data: w } = await supabase.from("wallets").select("balance"); totalCoins = (w || []).reduce((s, x) => s + (x.balance || 0), 0); } catch {}

      let todayCoins = 0;
      try { const { data: t } = await supabase.from("wallet_transactions").select("amount").gte("created_at", today.toISOString()).gt("amount", 0); todayCoins = (t || []).reduce((s, x) => s + (x.amount || 0), 0); } catch {}

      let monthCoins = 0;
      try { const { data: t } = await supabase.from("wallet_transactions").select("amount").gte("created_at", month.toISOString()).gt("amount", 0); monthCoins = (t || []).reduce((s, x) => s + (x.amount || 0), 0); } catch {}

      let conversionRate = 0;
      try { const p = await safeCount(supabase.from("tournament_participants").select("user_id", { count: "exact", head: true })); conversionRate = totalUsers > 0 ? Math.round((p / totalUsers) * 100) : 0; } catch {}

      setStats({ totalUsers, onlineUsers, bannedUsers, pendingVerifications: pendingVerif, totalTournaments, activeTournaments, totalMatches, liveMatches, totalCoins, totalReports, openTickets, newToday, todayRevenue: todayCoins, monthlyRevenue: monthCoins, conversionRate });
      setLastRefresh(new Date());
    } catch (err) { console.error("fetchStats:", err); }
  }, []);

  const fetchUsers = useCallback(async () => {
    try {
      const { data: p, error: pErr } = await supabase.from("profiles").select("*").order("created_at", { ascending: false });
      if (pErr) throw pErr;
      const { data: w } = await supabase.from("wallets").select("user_id,balance");
      const wMap = {}; (w || []).forEach(x => { wMap[x.user_id] = x.balance; });
      setUsers((p || []).map(u => ({ ...u, coins: wMap[u.id] || 0, display_name: u.username || u.full_name || u.name || u.email?.split("@")[0] || "Unknown" })));
    } catch (err) { console.error("fetchUsers:", err); }
  }, []);

  const fetchAdmins = useCallback(async () => {
    try {
      const { data, error } = await supabase.from("profiles").select("*").in("role", ["admin", "super_admin", "founder", "fondateur"]).order("created_at", { ascending: false });
      if (error) throw error;
      setAdmins(data || []);
    } catch (err) { console.error(err); }
  }, []);

  const fetchTournaments = useCallback(async () => {
    try {
      const { data, error } = await supabase.from("tournaments").select("*").order("created_at", { ascending: false }).limit(50);
      if (error) throw error;
      setTournaments(data || []);
    } catch { setTournaments([]); }
  }, []);

  const fetchReports = useCallback(async () => {
    try {
      const { data, error } = await supabase.from("reports").select("*").order("created_at", { ascending: false });
      if (error) throw error;
      setReports(data || []);
    } catch { setReports([]); }
  }, []);

  const fetchLogs = useCallback(async () => {
    try {
      const { data, error } = await supabase.from("admin_logs").select("*").order("created_at", { ascending: false }).limit(100);
      if (error) throw error;
      setLogs(data || []);
    } catch { setLogs([]); }
  }, []);

  const fetchSystemConfig = useCallback(async () => {
    try {
      const { data } = await supabase.from("system_config").select("*").single();
      if (data) {
        setMaintenanceMode(data.maintenance_mode || false);
        setRegistrationEnabled(data.registration_enabled !== false);
        setTournamentsEnabled(data.tournaments_enabled !== false);
      }
    } catch {}
  }, []);

  /* ÔöÇÔöÇ Init ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
  useEffect(() => {
    const init = async () => {
      try {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) { navigate("/login"); return; }
        const { data, error } = await supabase.from("profiles").select("*").eq("id", user.id).maybeSingle();
        if (error || !data || data.role?.toLowerCase() !== "super_admin") { navigate("/dashboard"); return; }
        // Normalize role in-place so all downstream comparisons work
        if (data.role) data.role = data.role.toLowerCase();
        setProfile(data);
        await Promise.all([fetchStats(), fetchUsers(), fetchTournaments(), fetchReports(), fetchLogs(), fetchAdmins(), fetchSystemConfig()]);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    init();
  }, []);

  useEffect(() => {
    if (!profile) return;
    intervalRef.current = setInterval(() => { fetchStats(); fetchUsers(); fetchTournaments(); fetchReports(); fetchLogs(); }, 30000);
    return () => clearInterval(intervalRef.current);
  }, [profile]);

  useEffect(() => {
    if (!profile) return;
    const ch = supabase.channel("superadmin-pending-users")
      .on("postgres_changes", { event: "INSERT", schema: "public", table: "profiles" }, (payload) => {
        if (payload.new?.verification_status === "pending") {
          showMsg("success", `New user pending verification: ${payload.new.full_name || payload.new.email || "Unknown"}`);
          fetchUsers(); fetchStats();
        }
      }).subscribe();
    return () => supabase.removeChannel(ch);
  }, [profile]);

  useEffect(() => {
    if (!profile) return;
    const upd = () => supabase.from("profiles").update({ last_seen: new Date().toISOString() }).eq("id", profile.id).then(() => {});
    upd(); const t = setInterval(upd, 60000); return () => clearInterval(t);
  }, [profile]);

  /* ÔöÇÔöÇ Actions ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */
  const showMsg = (type, text) => { setMsg({ type, text }); setTimeout(() => setMsg({ type: "", text: "" }), 5000); };

  const approveUser = async (userId) => {
    try {
      const { error } = await supabase.rpc("admin_verify_user", { target_user_id: userId, new_status: "approved" });
      if (error) throw error;
      showMsg("success", "User approved.");
      fetchUsers(); fetchStats();
      setShowReviewModal(false); setReviewUser(null);
    } catch (err) { showMsg("error", err.message); }
  };

  const rejectUser = async (userId) => {
    try {
      const { error } = await supabase.rpc("admin_verify_user", { target_user_id: userId, new_status: "rejected" });
      if (error) throw error;
      showMsg("success", "User rejected.");
      fetchUsers(); fetchStats();
      setShowReviewModal(false); setReviewUser(null);
    } catch (err) { showMsg("error", err.message); }
  };

  const updateUserRole = async (userId, role) => {
    try {
      const { error: rpcErr } = await supabase.rpc("set_user_role", { target_user: userId, new_role: role });
      if (rpcErr) { const { error: dErr } = await supabase.from("profiles").update({ role }).eq("id", userId); if (dErr) throw dErr; }
      await supabase.from("admin_logs").insert([{ user_id: profile.id, action: "change_role", details: { target_user: userId, new_role: role } }]);
      if (userId === profile.id) { await supabase.auth.refreshSession(); }
      showMsg("success", "Role updated. User must re-login to see changes.");
      fetchUsers(); fetchAdmins(); setShowRoleModal(false);
    } catch (err) { showMsg("error", err.message); }
  };

  const banUser = async (userId, duration) => {
    const b = new Date();
    if (duration === "24h") b.setHours(b.getHours() + 24);
    else if (duration === "7d") b.setDate(b.getDate() + 7);
    else if (duration === "30d") b.setDate(b.getDate() + 30);
    else b.setFullYear(b.getFullYear() + 10);
    try {
      const { error } = await supabase.rpc("ban_user", { target_user: userId, banned_until: b.toISOString(), banned_by: profile.id });
      if (error) throw error;
      showMsg("success", "User banned.");
      fetchUsers(); fetchStats(); setShowBanModal(false);
    } catch (err) { showMsg("error", err.message); }
  };

  const unbanUser = async (userId) => {
    try {
      const { error } = await supabase.rpc("unban_user", { target_user: userId });
      if (error) throw error;
      showMsg("success", "User unbanned.");
      fetchUsers(); fetchStats();
    } catch (err) { showMsg("error", err.message); }
  };

  const deleteUser = async (userId) => {
    if (!window.confirm("Permanently delete this user?")) return;
    try {
      const { error } = await supabase.rpc("delete_user_complete", { target_user: userId });
      if (error) throw error;
      showMsg("success", "User deleted.");
      fetchUsers(); fetchStats();
    } catch (err) { showMsg("error", err.message); }
  };

  const grantCoins = async () => {
    if (!selectedUser) return;
    const amount = parseInt(grantAmount);
    if (isNaN(amount) || amount === 0) { showMsg("error", "Invalid amount"); return; }
    if (!grantReason.trim()) { showMsg("error", "Reason is required"); return; }
    try {
      const { data, error } = await supabase.rpc("admin_adjust_coins", { p_target_user_id: selectedUser.id, p_amount: amount, p_reason: grantReason });
      if (error) throw error;
      if (!data?.success) throw new Error(data?.error || "Error");
      showMsg("success", `${amount > 0 ? "+" : ""}${amount} coins ÔåÆ ${selectedUser.display_name} (balance: ${data.new_balance})`);
      setGrantAmount(""); setGrantReason(""); setShowWalletModal(false);
      fetchUsers(); fetchStats();
    } catch (err) { showMsg("error", err.message); }
  };

  const updateTournamentStatus = async (tId, status) => {
    try {
      const { error } = await supabase.from("tournaments").update({ status }).eq("id", tId);
      if (error) throw error;
      showMsg("success", "Status updated.");
      setShowTournamentModal(false); fetchTournaments(); fetchStats();
    } catch (err) { showMsg("error", err.message); }
  };

  const deleteTournament = async (tId) => {
    try {
      const { error } = await supabase.rpc("delete_tournament_complete", { tournament_id: tId });
      if (error) throw error;
      showMsg("success", "Tournament deleted.");
      fetchTournaments(); fetchStats();
    } catch (err) { showMsg("error", err.message); }
  };

  const resolveReport = async (reportId, action) => {
    try {
      const { error } = await supabase.from("reports").update({ status: "resolved", resolved_by: profile.id, resolved_action: action, resolved_at: new Date().toISOString() }).eq("id", reportId);
      if (error) throw error;
      showMsg("success", "Report resolved.");
      fetchReports(); fetchStats();
    } catch (err) { showMsg("error", err.message); }
  };

  const updateSystemConfig = async () => {
    try {
      const { error } = await supabase.from("system_config").upsert({ maintenance_mode: maintenanceMode, registration_enabled: registrationEnabled, tournaments_enabled: tournamentsEnabled, updated_by: profile.id, updated_at: new Date().toISOString() });
      if (error) throw error;
      showMsg("success", "Configuration saved.");
    } catch (err) { showMsg("error", err.message); }
  };

  const manualRefresh = async () => {
    await Promise.all([fetchStats(), fetchUsers(), fetchTournaments(), fetchReports(), fetchLogs(), fetchAdmins()]);
    showMsg("success", "Data refreshed.");
  };

  const filteredUsers = users.filter(u => {
    const s = search.toLowerCase();
    const m = u.display_name?.toLowerCase().includes(s) || u.email?.toLowerCase().includes(s) || u.free_fire_id?.includes(s);
    if (filter === "all")      return m;
    if (filter === "admins")   return m && u.role === "admin";
    if (filter === "founders") return m && ["founder", "fondateur"].includes(u.role);
    if (filter === "banned")   return m && u.role === "banned";
    if (filter === "pending")  return m && u.verification_status === "pending";
    return m;
  });

  const TABS = [
    { id: "dashboard",   icon: BarChart2,     label: "Dashboard"                     },
    { id: "users",       icon: Users,         label: `Users (${users.length})`       },
    { id: "admins",      icon: Shield,        label: `Staff (${admins.length})`      },
    { id: "tournaments", icon: Trophy,        label: `Tournaments (${tournaments.length})` },
    { id: "reports",     icon: AlertTriangle, label: `Reports (${reports.length})`   },
    { id: "economy",     icon: Coins,         label: "Economy"                       },
    { id: "security",    icon: Shield,        label: "Security"                      },
    { id: "logs",        icon: ClipboardList, label: "Logs"                          },
    { id: "system",      icon: Settings,      label: "System"                        },
  ];

  if (loading) return (
    <div className="adm-loading-screen">
      <div className="adm-spinner" />
      <p className="adm-loading-text">Loading Command CenterÔÇª</p>
    </div>
  );

  return (
    <div className="adm-page">
      <div className="adm-content">

        {/* ÔöÇÔöÇ Header ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
        <motion.div className="adm-page-head" initial={{ opacity: 0, y: -16 }} animate={{ opacity: 1, y: 0 }}>
          <div>
            <h1 className="adm-page-title">Command Center</h1>
            <p className="adm-page-sub">
              <span className="adm-online-dot" />
              {profile?.username || profile?.email?.split("@")[0]} ÔÇö Full control
              {lastRefresh && <span style={{ marginLeft: 8, opacity: 0.4, fontSize: 11 }}>
                ┬À refreshed {lastRefresh.toLocaleTimeString()}
              </span>}
            </p>
          </div>
          <div className="adm-page-actions">
            <button
              className="adm-btn adm-btn--ghost"
              style={{ position: "relative" }}
              onClick={() => { setActiveTab("users"); setFilter("pending"); }}
              title="Pending verifications"
            >
              <Bell size={15} />
              {stats.pendingVerifications > 0 && (
                <span className="adm-nav-badge adm-nav-badge--danger" style={{ position: "absolute", top: -4, right: -4 }}>
                  {stats.pendingVerifications}
                </span>
              )}
            </button>
            <button className="adm-btn adm-btn--ghost" onClick={manualRefresh}>
              <RefreshCw size={14} />
              Refresh
            </button>
            <Link to="/admin" className="adm-btn adm-btn--orange">
              <Shield size={14} />
              Admin Panel
            </Link>
          </div>
        </motion.div>

        {/* ÔöÇÔöÇ Alert ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ */}
        <AnimatePresence>
          {msg.text && (
            <motion.div
              className={`adm-alert adm-alert--${msg.type}`}
              initial={{ opacity: 0, y: -8 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
            >
              {msg.text}
            </motion.div>
          )}
        </AnimatePresence>

