            </motion.div>
          )}

          {/* LOGS */}
          {activeTab === "logs" && (
            <motion.div key="logs" initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0 }}>
              <div className="adm-card">
                <div className="adm-card-head">
                  <span className="adm-card-accent" />
                  <h2 className="adm-card-title">Admin Logs</h2>
                </div>
                <div style={{ maxHeight: 520, overflowY: "auto", display: "flex", flexDirection: "column", gap: 6 }}>
