                </div>
                <button className="adm-btn adm-btn--primary adm-btn--lg" style={{ width: "100%" }} onClick={updateSystemConfig}>
                  <Settings size={15} />
                  Save Configuration
                </button>
              </div>
            </motion.div>
          )}

        </AnimatePresence>

        {/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ MODALS ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */}
        <AnimatePresence>

          {/* Review / User Profile Modal */}
          {showReviewModal && reviewUser && (
            <motion.div className="adm-modal-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => { setShowReviewModal(false); setReviewUser(null); }}>
              <motion.div className="adm-modal" style={{ maxWidth: 860 }} initial={{ scale: 0.95, y: 12, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
                onClick={e => e.stopPropagation()}>
                <div className="adm-modal-head">
                  <div>
                    <h2 className="adm-modal-title">User Profile Review</h2>
                    <p className="adm-modal-sub">Identity verification ÔÇö {reviewUser.full_name || reviewUser.email}</p>
                  </div>
                  <button className="adm-btn adm-btn--ghost" onClick={() => { setShowReviewModal(false); setReviewUser(null); }}>
                    <XCircle size={16} /> Close
                  </button>
                </div>
                <div className="adm-modal-body" style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
                  <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                    <div className="adm-info-block">
                      <p className="adm-info-block-title">Account Information</p>
                      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                        {[
                          { l: "Full Name",  v: reviewUser.full_name },
                          { l: "Email",      v: reviewUser.email },
                          { l: "Age",        v: reviewUser.age },
                          { l: "City",       v: reviewUser.city },
                          { l: "Country",    v: reviewUser.country },
                          { l: "FF ID",      v: reviewUser.free_fire_id },
                          { l: "Joined",     v: reviewUser.created_at ? new Date(reviewUser.created_at).toLocaleString() : null },
                          { l: "Status",     v: reviewUser.verification_status, highlight: true },
                        ].map((f, i) => (
                          <div key={i}>
                            <p style={{ fontSize: 10, color: "var(--t4)", marginBottom: 2 }}>{f.l}</p>
                            <p style={{ fontSize: 13, fontWeight: 600, color: f.highlight ? "var(--s-gold)" : "var(--t1)", textTransform: f.highlight ? "uppercase" : "none" }}>
                              {f.v || "ÔÇö"}
                            </p>
                          </div>
                        ))}
                      </div>
                    </div>
                    <div className="adm-info-block">
                      <p className="adm-info-block-title">Admin Actions</p>
                      <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                        <button className="adm-btn adm-btn--success" style={{ flex: 1 }} onClick={() => approveUser(reviewUser.id)}>
                          <CheckCircle size={14} /> Approve
                        </button>
                        <button className="adm-btn adm-btn--danger" style={{ flex: 1 }} onClick={() => rejectUser(reviewUser.id)}>
                          <XCircle size={14} /> Reject
                        </button>
                        <button className="adm-btn adm-btn--ghost" style={{ flex: 1 }} onClick={() => { setSelectedUser(reviewUser); setShowBanModal(true); setShowReviewModal(false); }}>
                          <Ban size={14} /> Ban
                        </button>
                      </div>
                    </div>
                  </div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
                    <div className="adm-info-block">
                      <p className="adm-info-block-title">ID Card (CIN)</p>
                      {reviewUser.id_card_url
                        ? <img src={reviewUser.id_card_url} alt="ID Card" style={{ width: "100%", maxHeight: 220, objectFit: "contain", borderRadius: 8, border: "1px solid var(--border)", background: "var(--bg-2)" }} />
                        : <div className="adm-doc-placeholder"><p>No image provided</p></div>
                      }
                    </div>
                    <div className="adm-info-block">
                      <p className="adm-info-block-title">Selfie with ID</p>
                      {reviewUser.selfie_url
                        ? <img src={reviewUser.selfie_url} alt="Selfie" style={{ width: "100%", maxHeight: 220, objectFit: "contain", borderRadius: 8, border: "1px solid var(--border)", background: "var(--bg-2)" }} />
                        : <div className="adm-doc-placeholder"><p>No image provided</p></div>
                      }
                    </div>
                  </div>
                </div>
              </motion.div>
            </motion.div>
          )}

          {/* Role Modal */}
          {showRoleModal && selectedUser && (
            <motion.div className="adm-modal-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setShowRoleModal(false)}>
              <motion.div className="adm-modal" style={{ maxWidth: 500 }} initial={{ scale: 0.95, y: 12, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
                onClick={e => e.stopPropagation()}>
                <div className="adm-modal-head">
                  <div>
                    <h2 className="adm-modal-title">Change Role</h2>
                    <p className="adm-modal-sub">{selectedUser.display_name || selectedUser.email}</p>
                  </div>
                </div>
                <div className="adm-modal-body">
                  <div style={{ display: "flex", justifyContent: "space-between", padding: "8px 12px", borderRadius: 8, background: "var(--bg-2)", border: "1px solid var(--border)", marginBottom: 16 }}>
                    <span style={{ fontSize: 11, color: "var(--t4)" }}>Current Role</span>
                    <span className={`adm-badge ${ROLE_BADGE[selectedUser.role] || "adm-badge--subtle"}`}>{selectedUser.role?.toUpperCase()}</span>
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 16 }}>
                    {ROLE_OPTIONS.map(r => (
                      <div
                        key={r.value}
                        onClick={() => setNewRole(r.value)}
                        className={`adm-role-option${newRole === r.value ? " adm-role-option--active" : ""}`}
                      >
                        <r.icon size={18} style={{ flexShrink: 0 }} />
                        <div>
                          <p style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.05em" }}>{r.label}</p>
                          <p style={{ fontSize: 10, color: "var(--t4)" }}>{r.desc}</p>
                        </div>
                        {newRole === r.value && <CheckCircle size={14} style={{ marginLeft: "auto", flexShrink: 0, color: "var(--accent)" }} />}
                      </div>
                    ))}
                  </div>
                  {newRole === "super_admin" && (
                    <div className="adm-alert adm-alert--warning" style={{ marginBottom: 12 }}>
                      This role grants access to ALL platform features.
                    </div>
                  )}
                  {newRole === "banned" && (
                    <div className="adm-alert adm-alert--error" style={{ marginBottom: 12 }}>
                      This player will be immediately disconnected.
                    </div>
                  )}
                </div>
                <div className="adm-modal-footer">
                  <button className="adm-btn adm-btn--ghost" onClick={() => setShowRoleModal(false)}>Cancel</button>
                  <button className={`adm-btn ${newRole === "banned" ? "adm-btn--danger" : "adm-btn--primary"}`} onClick={() => updateUserRole(selectedUser.id, newRole)}>
                    <CheckCircle size={14} />
                    Confirm ÔÇö {newRole.replace("_", " ").toUpperCase()}
                  </button>
                </div>
              </motion.div>
            </motion.div>
          )}

          {/* Ban Modal */}
          {showBanModal && selectedUser && (
            <motion.div className="adm-modal-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setShowBanModal(false)}>
              <motion.div className="adm-modal" style={{ maxWidth: 420 }} initial={{ scale: 0.95, y: 12, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
                onClick={e => e.stopPropagation()}>
                <div className="adm-modal-head">
                  <h2 className="adm-modal-title">Ban User</h2>
                </div>
                <div className="adm-modal-body">
                  <p style={{ fontSize: 13, color: "var(--t2)", marginBottom: 14 }}>
                    User: <strong style={{ color: "var(--t1)" }}>{selectedUser.display_name}</strong>
                  </p>
                  <select value={banDuration} onChange={e => setBanDuration(e.target.value)} className="adm-input" style={{ marginBottom: 8 }}>
                    <option value="24h">24 hours</option>
                    <option value="7d">7 days</option>
                    <option value="30d">30 days</option>
                    <option value="permanent">Permanent</option>
                  </select>
                </div>
                <div className="adm-modal-footer">
                  <button className="adm-btn adm-btn--ghost" onClick={() => setShowBanModal(false)}>Cancel</button>
                  <button className="adm-btn adm-btn--danger" onClick={() => banUser(selectedUser.id, banDuration)}>
                    <Ban size={14} /> Ban User
                  </button>
                </div>
              </motion.div>
            </motion.div>
          )}

          {/* Wallet / Coins Modal */}
          {showWalletModal && (
            <motion.div className="adm-modal-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => { setShowWalletModal(false); setGrantAmount(""); setGrantReason(""); setWalletSearch(""); setSelectedUser(null); }}>
              <motion.div className="adm-modal" style={{ maxWidth: 500 }} initial={{ scale: 0.95, y: 12, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
                onClick={e => e.stopPropagation()}>
                <div className="adm-modal-head">
                  <div>
                    <h2 className="adm-modal-title">Coin Management</h2>
                    <p className="adm-modal-sub">
                      {selectedUser ? (selectedUser.display_name || selectedUser.email) : "Select a player"}
                    </p>
                  </div>
                </div>
                <div className="adm-modal-body" style={{ display: "flex", flexDirection: "column", gap: 14 }}>
                  {/* Player search */}
                  <div>
                    <label className="adm-label">Search Player</label>
                    <div style={{ position: "relative" }}>
                      <Search size={13} style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "var(--t4)" }} />
                      <input
                        placeholder="Name, username or emailÔÇª"
                        value={walletSearch}
                        onChange={e => setWalletSearch(e.target.value)}
                        className="adm-input"
                        style={{ paddingLeft: 32 }}
                      />
                    </div>
                    {walletSearch.length > 0 && (
                      <div className="adm-search-dropdown">
                        {users.filter(u =>
                          u.display_name?.toLowerCase().includes(walletSearch.toLowerCase()) ||
                          u.email?.toLowerCase().includes(walletSearch.toLowerCase())
                        ).slice(0, 8).map(u => (
                          <div key={u.id} className="adm-search-option" onClick={() => { setSelectedUser(u); setWalletSearch(""); }}>
                            <div className="adm-table-avatar" style={{ width: 28, height: 28, fontSize: 11 }}>
                              {(u.display_name || u.email || "?").charAt(0).toUpperCase()}
                            </div>
                            <div>
                              <p style={{ fontSize: 13, fontWeight: 600, color: "var(--t1)" }}>{u.display_name || u.username || "Unknown"}</p>
                              <p style={{ fontSize: 11, color: "var(--t4)" }}>{u.email} ┬À {(u.coins || 0).toLocaleString()} coins</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>

                  {selectedUser && (
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 14px", borderRadius: 8, background: "var(--bg-2)", border: "1px solid var(--border)" }}>
                      <span style={{ fontSize: 13, fontWeight: 600, color: "var(--t1)" }}>{selectedUser.display_name}</span>
                      <span style={{ fontSize: 15, fontWeight: 800, color: "var(--s-gold)" }}>
                        {(selectedUser.coins || 0).toLocaleString()} coins
                      </span>
                    </div>
                  )}

                  <div>
                    <label className="adm-label">Amount (negative to deduct)</label>
                    <input
                      type="number"
                      placeholder="e.g. 500 or -200"
                      value={grantAmount}
                      onChange={e => setGrantAmount(e.target.value)}
                      className="adm-input"
                    />
                    <div style={{ display: "flex", gap: 6, marginTop: 6, flexWrap: "wrap" }}>
                      {[100, 500, 1000, 2000, 5000].map(n => (
                        <button key={n} className="adm-btn adm-btn--sm adm-btn--ghost" onClick={() => setGrantAmount(String(n))}>+{n}</button>
                      ))}
                    </div>
                  </div>

                  <div>
                    <label className="adm-label">Reason *</label>
                    <input
                      type="text"
                      placeholder="e.g. Tournament reward, Bug fix compensationÔÇª"
                      value={grantReason}
                      onChange={e => setGrantReason(e.target.value)}
                      className="adm-input"
                    />
                  </div>

                  {selectedUser && grantAmount !== "" && parseInt(grantAmount) !== 0 && (
                    <div style={{ display: "flex", justifyContent: "space-between", padding: "8px 14px", borderRadius: 8, background: "var(--bg-2)", border: "1px solid var(--border)" }}>
                      <span style={{ fontSize: 12, color: "var(--t4)" }}>Balance after</span>
                      <span style={{ fontSize: 14, fontWeight: 800, color: ((selectedUser.coins || 0) + (parseInt(grantAmount) || 0)) < 0 ? "var(--c-red)" : "var(--c-green)" }}>
                        {Math.max(0, (selectedUser.coins || 0) + (parseInt(grantAmount) || 0)).toLocaleString()} coins
                      </span>
                    </div>
                  )}
                </div>
                <div className="adm-modal-footer">
                  <button className="adm-btn adm-btn--ghost" onClick={() => { setShowWalletModal(false); setGrantAmount(""); setGrantReason(""); setWalletSearch(""); setSelectedUser(null); }}>
                    Cancel
                  </button>
                  <button
                    className={`adm-btn ${(parseInt(grantAmount) || 0) < 0 ? "adm-btn--danger" : "adm-btn--success"}`}
                    onClick={grantCoins}
                    disabled={!selectedUser || !grantAmount || !grantReason.trim()}
                  >
                    <Coins size={14} />
                    {!selectedUser ? "Choose a player" : !grantAmount ? "Enter amount" : (parseInt(grantAmount) || 0) < 0 ? `Deduct ${Math.abs(parseInt(grantAmount))}` : `Add ${parseInt(grantAmount)}`}
                  </button>
                </div>
              </motion.div>
            </motion.div>
          )}

          {/* Tournament edit modal */}
          {showTournamentModal && selectedTournament && (
            <motion.div className="adm-modal-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setShowTournamentModal(false)}>
              <motion.div className="adm-modal" style={{ maxWidth: 420 }} initial={{ scale: 0.95, y: 12, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
                onClick={e => e.stopPropagation()}>
                <div className="adm-modal-head">
                  <h2 className="adm-modal-title">Edit Tournament</h2>
                  <p className="adm-modal-sub" style={{ marginLeft: 0 }}>{selectedTournament.name}</p>
                </div>
                <div className="adm-modal-body">
                  <label className="adm-label">Status</label>
                  <select value={tournamentStatus} onChange={e => setTournamentStatus(e.target.value)} className="adm-input">
                    <option value="open">Open</option>
                    <option value="ongoing">Ongoing</option>
                    <option value="completed">Completed</option>
                    <option value="cancelled">Cancelled</option>
                  </select>
                </div>
                <div className="adm-modal-footer">
                  <button className="adm-btn adm-btn--ghost" onClick={() => setShowTournamentModal(false)}>Cancel</button>
                  <button className="adm-btn adm-btn--primary" onClick={() => updateTournamentStatus(selectedTournament.id, tournamentStatus)}>
                    Update
                  </button>
                </div>
              </motion.div>
            </motion.div>
          )}

          {/* Delete confirm */}
          {showDeleteConfirm && tournamentToDelete && (
            <motion.div className="adm-modal-overlay" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              onClick={() => setShowDeleteConfirm(false)}>
              <motion.div className="adm-modal" style={{ maxWidth: 420 }} initial={{ scale: 0.95, y: 12, opacity: 0 }} animate={{ scale: 1, y: 0, opacity: 1 }} exit={{ scale: 0.95, opacity: 0 }}
                onClick={e => e.stopPropagation()}>
                <div className="adm-modal-head">
                  <h2 className="adm-modal-title">Delete Tournament</h2>
                </div>
                <div className="adm-modal-body">
                  <p style={{ fontSize: 13, color: "var(--t2)" }}>
                    Delete <strong style={{ color: "var(--t1)" }}>"{tournamentToDelete.name}"</strong>? This action is irreversible.
                  </p>
                </div>
                <div className="adm-modal-footer">
                  {deleteLoading ? (
                    <div style={{ display: "flex", justifyContent: "center", width: "100%", padding: "8px 0" }}>
                      <div className="adm-spinner" style={{ width: 24, height: 24 }} />
                    </div>
                  ) : (
                    <>
                      <button className="adm-btn adm-btn--ghost" onClick={() => { setShowDeleteConfirm(false); setTournamentToDelete(null); }}>Cancel</button>
                      <button className="adm-btn adm-btn--danger" onClick={async () => {
                        setDeleteLoading(true);
                        await deleteTournament(tournamentToDelete.id);
                        setDeleteLoading(false); setShowDeleteConfirm(false); setTournamentToDelete(null);
                      }}>
                        <Trash2 size={14} /> Delete
                      </button>
                    </>
                  )}
                </div>
              </motion.div>
            </motion.div>
          )}

        </AnimatePresence>
      </div>
    </div>
  );
}

