                      {[["normal","NORMAL","rgba(255,255,255,0.3)"],["urgent","URGENT","#fbbf24"],["critique","­ƒö┤ CRIT","#dc2626"]].map(([v,lb,c])=>(
                        <button key={v} onClick={()=>setForm({...form,priority:v})} style={{
