                <div>
                  <p style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,letterSpacing:2,color:"rgba(255,255,255,0.3)",marginBottom:7}}>MESSAGE / D├ëTAILS</p>
                  <textarea className="sp-input" value={form.body} onChange={e=>setForm({...form,body:e.target.value})} rows={6} placeholder="D├®crivez votre demande en d├®tailÔÇª" style={{resize:"vertical",minHeight:120}}/>
                </div>

                <div style={{display:"flex",gap:10,paddingTop:4}}>
