  );
}

import { useState, useEffect, useRef } from "react";
import { useParams, useNavigate, useOutletContext, Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "../lib/supabase";
import { useVerification } from "../hooks/useVerification";

// === CONSTANTS & THEME ===
const THEME = {
  cyan: "#00d4ff",
  indigo: "#6366f1",
  violet: "#8b5cf6",
  green: "#10b981",
  red: "#ef4444",
  amber: "#f59e0b",
  pink: "#ec4899",
  bg: "#0a0c10",
  card: "#111317",
  cardHover: "#1a1d24",
  border: "#1e2128",
  text: "#ffffff",
  textMuted: "#8f9bb3"
};

const COLORS = [THEME.cyan, THEME.indigo, THEME.violet, THEME.green, THEME.amber, THEME.pink];

const rgba = (color, alpha) => {
  const hex = color.replace('#', '');
  const r = parseInt(hex.substring(0, 2), 16);
  const g = parseInt(hex.substring(2, 4), 16);
  const b = parseInt(hex.substring(4, 6), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

// === COMPONENTS ===
function TeamAvatar({ team, size = 48 }) {
  const accent = team?.accent_color || THEME.cyan;
  const borderRadius = Math.round(size * 0.25);
  const fontSize = Math.round(size * 0.4);

  if (team?.logo_url) {
    return (
      <div style={{
        width: size,
        height: size,
        borderRadius,
        overflow: "hidden",
        border: `2px solid ${rgba(accent, 0.3)}`,
        boxShadow: `0 0 20px ${rgba(accent, 0.2)}`,
        flexShrink: 0
      }}>
        <img 
          src={team.logo_url} 
          alt={team?.name || "team"}
          style={{ width: "100%", height: "100%", objectFit: "cover" }}
          onError={e => { e.currentTarget.style.display = "none"; e.currentTarget.parentElement.style.background = `linear-gradient(135deg, ${rgba(accent, 0.2)}, ${THEME.card})`; }}
        />
      </div>
    );
  }

  return (
    <div style={{
      width: size,
      height: size,
      borderRadius,
      background: `linear-gradient(135deg, ${rgba(accent, 0.2)}, ${THEME.card})`,
      border: `2px solid ${rgba(accent, 0.3)}`,
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      fontFamily: "'Bebas Neue', cursive",
      fontSize,
      color: accent,
      flexShrink: 0,
      boxShadow: `0 0 20px ${rgba(accent, 0.1)}`
    }}>
      {team?.tag?.[0] || "?"}
    </div>
  );
}

function RoleBadge({ role }) {
  const config = {
    captain: { color: THEME.amber, icon: "­ƒææ", label: "CAPITAINE" },
    co_captain: { color: THEME.violet, icon: "ÔÜí", label: "CO-CAPITAINE" },
    member: { color: THEME.indigo, icon: "­ƒÄ«", label: "MEMBRE" }
  }[role] || { color: THEME.indigo, icon: "­ƒÄ«", label: role?.toUpperCase() };

  return (
    <span style={{
      display: "inline-flex",
      alignItems: "center",
      gap: 4,
      fontFamily: "'JetBrains Mono', monospace",
      fontSize: 10,
      fontWeight: 500,
      color: config.color,
      background: rgba(config.color, 0.1),
      border: `1px solid ${rgba(config.color, 0.2)}`,
      padding: "4px 8px",
      borderRadius: 6,
      letterSpacing: 0.5
    }}>
      <span>{config.icon}</span>
      {config.label}
    </span>
  );
}

function StatCard({ value, label, color, icon }) {
  return (
    <div style={{
      flex: 1,
      background: rgba(color, 0.05),
      border: `1px solid ${rgba(color, 0.1)}`,
      borderRadius: 12,
      padding: "12px 8px",
      textAlign: "center"
    }}>
      <div style={{ fontSize: 20, marginBottom: 4 }}>{icon}</div>
      <div style={{ fontFamily: "'Bebas Neue', cursive", fontSize: 28, color, lineHeight: 1 }}>{value}</div>
      <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 9, color: THEME.textMuted, letterSpacing: 1 }}>{label}</div>
    </div>
  );
}

// === MAIN COMPONENT ===
export default function TeamProfile() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { profile } = useOutletContext();
  const { requireVerified } = useVerification();

  const [team, setTeam] = useState(null);
  const [members, setMembers] = useState([]);
  const [myRole, setMyRole] = useState(null);
  const [joinRequests, setJoinRequests] = useState([]);
  const [tournaments, setTournaments] = useState([]);
  const [chatMessages, setChatMessages] = useState([]);
  const [senderEquipped, setSenderEquipped] = useState({}); // userId ÔåÆ equipped items
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [activeTab, setActiveTab] = useState("members");
  const [chatInput, setChatInput] = useState("");
  const [sending, setSending] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showAdminPanel, setShowAdminPanel] = useState(false);
  const [adminActionLoading, setAdminActionLoading] = useState(false);
  const [editForm, setEditForm] = useState({
    name: "", tag: "", description: "", accent_color: THEME.cyan, is_open: true
  });

  const chatEndRef = useRef(null);

  const isCaptain = myRole === "captain";
  const isCoCapt = myRole === "co_captain";
  const isMember = !!myRole;
  const isAdmin = ["admin", "super_admin"].includes(profile?.role);
  const isSuperAdmin = profile?.role === "super_admin";
  const canManage = isCaptain || isCoCapt || isAdmin;

  // === DATA FETCHING ===
  const fetchTeamData = async () => {
    setLoading(true);
    setError(null);
    
    try {
      // Fetch team details
      const { data: teamData, error: teamError } = await supabase
        .from("teams")
        .select(`
          *,
          captain:profiles!teams_captain_id_fkey(id, full_name, avatar_url, free_fire_id)
        `)
        .eq("id", id)
        .single();

      if (teamError) throw teamError;
      if (!teamData) {
        navigate("/teams");
        return;
      }

      setTeam(teamData);
      setEditForm({
        name: teamData.name,
        tag: teamData.tag,
        description: teamData.description || "",
        accent_color: teamData.accent_color || THEME.cyan,
        is_open: teamData.is_open
      });

      // Fetch members
      const { data: membersData, error: membersError } = await supabase
        .from("team_members")
        .select(`
          *,
          profile:profiles!team_members_user_id_fkey(id, full_name, avatar_url, free_fire_id, level)
        `)
        .eq("team_id", id)
        .order("role", { ascending: true });

      if (membersError) throw membersError;
      setMembers(membersData || []);

      // Set current user's role ÔÇö d├®fini EN DEHORS du if pour ├¬tre accessible plus bas
      const currentMember = profile?.id
        ? (membersData || []).find(m => m.user_id === profile.id)
        : null;
      setMyRole(currentMember?.role || null);

      // Fetch tournaments
      const { data: tournamentsData } = await supabase
        .from("team_tournaments")
        .select(`
          *,
          tournament:tournaments(name, background_color, mode, prize_coins, status, start_date)
        `)
        .eq("team_id", id)
        .order("joined_at", { ascending: false })
        .limit(10);

      setTournaments(tournamentsData || []);

      // Ô£à FIX: utilise currentMember (local) ÔÇö myRole (state) pas encore mis ├á jour ici
      const isMemberLocal = !!currentMember;
      const canManageLocal = currentMember?.role === "captain" || currentMember?.role === "co_captain" || isAdmin;

      // Fetch chat if member or admin
      if (isMemberLocal || isAdmin) {
        await fetchChatMessages();
      }

      // Fetch join requests if manager
      if (canManageLocal || isAdmin) {
        await fetchJoinRequests();
      }

    } catch (err) {
      console.error("Error fetching team data:", err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchChatMessages = async () => {
    try {
      const { data, error } = await supabase
        .from("team_messages")
        .select(`
          *,
          sender:profiles!team_messages_sender_id_fkey(
            id, full_name, avatar_url, avatar_mode
          )
        `)
        .eq("team_id", id)
        .order("created_at", { ascending: true })
        .limit(50);

      if (error) throw error;
      setChatMessages(data || []);

      // Fetch equipped items for each unique sender
      const senderIds = [...new Set((data||[]).map(m => m.sender_id).filter(Boolean))];
      if (senderIds.length > 0) {
        const { data: equips } = await supabase
          .from("user_items")
          .select("user_id, equipped, item:store_items(id, type, name, image_url, color_value, rarity)")
          .in("user_id", senderIds)
          .eq("equipped", true);

        if (equips) {
          const map = {};
          equips.forEach(e => {
            if (!map[e.user_id]) map[e.user_id] = {};
            if (e.item?.type) map[e.user_id][e.item.type] = e.item;
          });
          setSenderEquipped(map);
        }
      }
    } catch (err) {
      console.error("Error fetching chat:", err);
    }
  };

  const fetchJoinRequests = async () => {
    if (!id) return;
    
    try {
      // Utiliser une fonction RPC pour ├®viter les probl├¿mes de permission
      const { data, error } = await supabase
        .rpc("get_team_join_requests", { p_team_id: id });

      if (error) throw error;
      setJoinRequests(data || []);
    } catch (err) {
      console.error("Error fetching join requests:", err);
      // Fallback: essayer avec la table directement si RPC ├®choue
      try {
        const { data, error } = await supabase
          .from("team_join_requests")
          .select(`
            *,
            user:profiles!team_join_requests_user_id_fkey(id, full_name, avatar_url, free_fire_id, level)
          `)
          .eq("team_id", id)
          .eq("status", "pending")
          .order("created_at", { ascending: false });

        if (!error) setJoinRequests(data || []);
      } catch (fallbackErr) {
        console.error("Fallback also failed:", fallbackErr);
      }
    }
  };

  useEffect(() => {
    fetchTeamData();
  }, [id, profile?.id]);

  // Real-time chat subscription
  // FIX: utilise id + profile?.id ÔÇö pas isMember (calcul├® apr├¿s mount)
  useEffect(() => {
    if (!id || !profile?.id) return;

    const channel = supabase
      .channel(`team-chat-${id}`)
      .on(
        "postgres_changes",
        {
          event: "INSERT",
          schema: "public",
          table: "team_messages",
          filter: `team_id=eq.${id}`
        },
        async (payload) => {
          const newMsg = payload.new;

          setChatMessages(prev => {
            // Si message d├®j├á pr├®sent (vrai ID) ÔåÆ ignorer
            if (prev.some(m => m.id === newMsg.id)) return prev;

            // Si c'est MON message optimiste (sender_id correspond + contenu identique)
            // ÔåÆ remplacer le temp par le vrai ID
            const tempIdx = prev.findIndex(
              m => typeof m.id === "string" && m.id.startsWith("temp-") &&
                   m.sender_id === newMsg.sender_id &&
                   m.content === newMsg.content
            );
            if (tempIdx !== -1) {
              const updated = [...prev];
              updated[tempIdx] = { ...newMsg, sender: prev[tempIdx].sender };
              return updated;
            }

            // Message d'un autre utilisateur ÔåÆ ajouter
            return [...prev, { ...newMsg, sender: { full_name: "...", avatar_url: null } }];
          });

          // Enrichir avec profil exp├®diteur (pour messages d'autres)
          const { data: sender } = await supabase
            .from("profiles")
            .select("full_name, avatar_url")
            .eq("id", newMsg.sender_id)
            .single();
          if (sender) {
            setChatMessages(prev =>
              prev.map(m => m.id === newMsg.id ? { ...m, sender } : m)
            );
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [id, profile?.id]);

  // Auto-scroll chat
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chatMessages]);

  // === ACTIONS ===
  const sendMessage = () => {
    if (!chatInput.trim() || sending || !profile?.id) return;
    requireVerified(() => _doSendMessage());
  };

  const _doSendMessage = async () => {
    const text = chatInput.trim();
    const tempId = `temp-${Date.now()}`;

    // Ô£à Optimistic update ÔÇö message visible imm├®diatement
    const optimisticMsg = {
      id: tempId,
      team_id: id,
      sender_id: profile.id,
      content: text,
      created_at: new Date().toISOString(),
      sender: {
        full_name: profile.full_name || "Vous",
        avatar_url: profile.avatar_url || null
      }
    };
    setChatMessages(prev => [...prev, optimisticMsg]);
    setChatInput("");
    setSending(true);

    try {
      const { data, error } = await supabase
        .from("team_messages")
        .insert([{
          team_id: id,
          sender_id: profile.id,
          content: text
        }])
        .select()
        .single();

      if (error) throw error;

      // Remplacer le message temporaire par le vrai
      if (data) {
        setChatMessages(prev =>
          prev.map(m => m.id === tempId
            ? { ...data, sender: optimisticMsg.sender }
            : m
          )
        );
      }
    } catch (err) {
      console.error("Error sending message:", err);
      // Rollback ÔÇö supprimer le message temporaire
      setChatMessages(prev => prev.filter(m => m.id !== tempId));
      setChatInput(text);
      alert("ÔØî Erreur lors de l'envoi du message");
    } finally {
      setSending(false);
    }
  };

  const handleAcceptRequest = async (requestId, userId) => {
    try {
      const { data, error } = await supabase
        .rpc("approve_team_join_request", {
          p_request_id: requestId,
          p_team_id: id,
          p_user_id: userId
        });

      if (error) throw error;
      if (!data?.success) throw new Error(data?.error || "Erreur lors de l'acceptation");
      
      await fetchTeamData();
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  const handleRejectRequest = async (requestId) => {
    try {
      const { error } = await supabase
        .from("team_join_requests")
        .update({
          status: "rejected",
          reviewed_at: new Date().toISOString(),
          reviewed_by: profile.id
        })
        .eq("id", requestId);

      if (error) throw error;
      await fetchJoinRequests();
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  const handleKickMember = async (userId) => {
    if (!confirm("ÔÜá´©Å ├ètes-vous s├╗r de vouloir expulser ce membre ?")) return;

    try {
      const { data, error } = await supabase
        .rpc("team_kick_member", {
          p_team_id: id,
          p_user_id: userId
        });

      if (error) throw error;
      if (!data?.success) throw new Error(data?.error || "Erreur lors de l'expulsion");
      
      await fetchTeamData();
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  const handlePromoteToCoCapt = async (userId) => {
    if (!isCaptain) return;

    try {
      const { data, error } = await supabase
        .rpc("team_promote_member", {
          p_team_id: id,
          p_user_id: userId,
          p_role: "co_captain"
        });

      if (error) throw error;
      if (!data?.success) throw new Error(data?.error || "Erreur lors de la promotion");
      
      await fetchTeamData();
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  const handleLeaveTeam = async () => {
    if (!confirm("Quitter cette ├®quipe ?")) return;

    try {
      const { data, error } = await supabase
        .rpc("leave_team", {
          p_team_id: id,
          p_user_id: profile.id
        });

      if (error) throw error;
      if (!data?.success) throw new Error(data?.error || "Erreur lors du d├®part");
      
      navigate("/teams");
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  const handleDisbandTeam = async () => {
    if (!isCaptain) return;
    if (!confirm("ÔÜá´©Å DISSOUDRE L'├ëQUIPE ?\nCette action est irr├®versible !")) return;

    try {
      const { data, error } = await supabase
        .rpc("team_disband", { p_team_id: id });

      if (error) throw error;
      if (!data?.success) throw new Error(data?.error || "Erreur lors de la dissolution");
      
      navigate("/teams");
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  const handleSaveEdit = async () => {
    try {
      const { error } = await supabase
        .from("teams")
        .update({
          name: editForm.name,
          tag: editForm.tag.toUpperCase(),
          description: editForm.description,
          accent_color: editForm.accent_color,
          is_open: editForm.is_open
        })
        .eq("id", id);

      if (error) throw error;
      
      setShowEditModal(false);
      await fetchTeamData();
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  const handleAdminDeleteTeam = async () => {
    if (!isSuperAdmin) return;
    if (!confirm("ÔÜá´©Å SUPPRIMER D├ëFINITIVEMENT CETTE ├ëQUIPE ?\nCette action est irr├®versible !")) return;

    setAdminActionLoading(true);
    try {
      const { error } = await supabase
        .from("teams")
        .delete()
        .eq("id", id);

      if (error) throw error;
      navigate("/teams");
    } catch (err) {
      alert("ÔØî " + err.message);
    } finally {
      setAdminActionLoading(false);
    }
  };

  const handleRequestJoin = () => {
    requireVerified(() => _doRequestJoin());
  };

  const _doRequestJoin = async () => {
    try {
      const { data, error } = await supabase
        .rpc("team_request_join", { p_team_id: id });

      if (error) throw error;
      if (!data?.success) throw new Error(data?.error || "Erreur lors de la demande");
      
      alert("Ô£à Demande envoy├®e avec succ├¿s !");
    } catch (err) {
      alert("ÔØî " + err.message);
    }
  };

  // === RENDER STATES ===
  if (loading) {
    return (
      <div style={{
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: THEME.bg
      }}>
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
          style={{
            width: 48,
            height: 48,
            border: `3px solid ${rgba(THEME.cyan, 0.1)}`,
            borderTopColor: THEME.cyan,
            borderRadius: "50%"
          }}
        />
      </div>
    );
  }

  if (error || !team) {
    return (
      <div style={{
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        flexDirection: "column",
        gap: 16,
        background: THEME.bg
      }}>
        <div style={{
          padding: 32,
