import { useState, useEffect, useRef, useCallback } from "react";
import { useOutletContext, useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "../lib/supabase";
import { useVerification } from "../hooks/useVerification";

// ÔöÇÔöÇ CipherPool design tokens ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
const ACCENT = "#FF4F00";
const GREEN  = "#10b981";
const RED    = "#ef4444";
const AMBER  = "#fbbf24";
const CARD   = "rgba(16,16,26,0.90)";

const ax = a => `rgba(255,79,0,${a})`;
const gx = a => `rgba(16,185,129,${a})`;
const rx = a => `rgba(239,68,68,${a})`;

// Team accent color palette (user-selectable)
const COLORS = ["#FF4F00","#FF7A33","#fbbf24","#10b981","#3b82f6","#8b5cf6","#ec4899","#ef4444"];

// ÔöÇÔöÇ Error helper ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function getErrorMessage(err) {
  if (!err) return "Erreur inconnue";
  if (typeof err === "string") return err;
  if (err.message && typeof err.message === "string") return err.message;
  if (err.error && typeof err.error === "string") return err.error;
  try { return JSON.stringify(err); } catch { return "Erreur de format inconnu"; }
}

async function getTeamMembersCount(teamId) {
  try {
    const { count, error } = await supabase
      .from("team_members")
      .select("*", { count: "exact", head: true })
      .eq("team_id", teamId);
    if (error) throw error;
    return count || 0;
  } catch { return 0; }
}

async function enrichTeamsWithMemberCount(teams) {
  if (!teams?.length) return teams;
  return Promise.all(teams.map(async t => ({ ...t, member_count: await getTeamMembersCount(t.id) })));
}

// ÔöÇÔöÇ Glass card component ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function G({ children, style, ac, onClick }) {
  const [h, setH] = useState(false);
  return (
    <div
      onClick={onClick}
      onMouseEnter={() => setH(true)}
      onMouseLeave={() => setH(false)}
      style={{
        position: "relative",
        overflow: "hidden",
        background: CARD,
        border: `1px solid ${h && ac ? ac + "40" : "rgba(255,255,255,0.08)"}`,
        borderRadius: 14,
        boxShadow: h && ac
          ? `0 0 0 1px ${ac}15, 0 8px 32px rgba(0,0,0,.5)`
          : "0 4px 20px rgba(0,0,0,.4)",
        transition: "all .22s",
        cursor: onClick ? "pointer" : "default",
        ...style
      }}
    >
      <div style={{
        position: "absolute", top: 0, left: 0, right: 0, height: 2,
        background: `linear-gradient(90deg,transparent,${ac || ax(.5)},transparent)`,
        opacity: h ? 1 : .3, transition: "opacity .22s", pointerEvents: "none"
      }} />
      {children}
    </div>
  );
}

// ÔöÇÔöÇ Animated background orbs ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function HeroBg() {
  const ref = useRef(null);
  useEffect(() => {
    const c = ref.current;
    if (!c) return;
    const ctx = c.getContext("2d");
    let raf, t = 0;
    const resize = () => { c.width = c.offsetWidth; c.height = c.offsetHeight; };
    resize();
    const ro = new ResizeObserver(resize);
    ro.observe(c);
    const orbs = [
      { cx: .1,  cy: .5, r: .5,  vx: .0008,  vy: .0005,  color: [255, 79, 0],   a: .09 },
      { cx: .85, cy: .3, r: .4,  vx: -.0006, vy: .0007,  color: [255, 120, 40], a: .06 },
      { cx: .5,  cy: .9, r: .35, vx: .0005,  vy: -.0007, color: [232, 50, 0],   a: .05 }
    ];
    const draw = () => {
      t++;
      ctx.clearRect(0, 0, c.width, c.height);
      orbs.forEach(o => {
        o.cx += o.vx * Math.sin(t * .008);
        o.cy += o.vy * Math.cos(t * .006);
        if (o.cx < -.1 || o.cx > 1.1) o.vx *= -1;
        if (o.cy < -.1 || o.cy > 1.1) o.vy *= -1;
        const x = o.cx * c.width, y = o.cy * c.height;
        const r = o.r * Math.max(c.width, c.height) * (1 + .06 * Math.sin(t * .012));
        const a = o.a * (1 + .12 * Math.sin(t * .018));
        const [R, Gr, B] = o.color;
        const g = ctx.createRadialGradient(x, y, 0, x, y, r);
        g.addColorStop(0,  `rgba(${R},${Gr},${B},${a})`);
        g.addColorStop(.5, `rgba(${R},${Gr},${B},${a * .3})`);
        g.addColorStop(1,  `rgba(${R},${Gr},${B},0)`);
        ctx.fillStyle = g;
        ctx.fillRect(0, 0, c.width, c.height);
      });
      raf = requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(raf); ro.disconnect(); };
  }, []);
  return <canvas ref={ref} style={{ position: "absolute", inset: 0, width: "100%", height: "100%", pointerEvents: "none" }} />;
}

