                    fontFamily: "var(--f-dis)", fontSize: 18, letterSpacing: 2,
                    cursor: creating || tagCheck === "taken" ? "not-allowed" : "pointer",
                    opacity: creating || tagCheck === "taken" ? 0.5 : 1,
                    textTransform: "uppercase"
                  }}
                >
                  {creating ? "Cr├®ation en cours..." : "Lancer l'├®quipe"}
                </motion.button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
          MODAL ÔÇö JOIN TEAM
      ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */}
      <AnimatePresence>
        {showJoin && (
          <motion.div
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            style={{
              position: "fixed", inset: 0, background: "rgba(7,7,9,.88)",
              backdropFilter: "blur(14px)", display: "flex", alignItems: "center",
              justifyContent: "center", zIndex: 50, padding: 20
            }}
            onClick={e => { if (e.target === e.currentTarget) setShowJoin(false); }}
          >
            <motion.div
              initial={{ scale: .88, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: .88, opacity: 0 }}
              style={{
                width: "100%", maxWidth: 420,
                background: CARD,
                border: "1px solid rgba(255,79,0,0.18)",
                borderRadius: 18, padding: "28px",
                boxShadow: "0 24px 80px rgba(0,0,0,.8)"
              }}
            >
              <p style={{ fontSize: 10, letterSpacing: 2, color: ax(.5), marginBottom: 4, textTransform: "uppercase" }}>Rejoindre</p>
              <h2 style={{ fontFamily: "var(--f-dis)", fontSize: 26, letterSpacing: 2, color: "#fff", margin: "0 0 16px", textTransform: "uppercase" }}>
                Trouver une ├®quipe
              </h2>

              {err && (
                <div style={{ padding: "10px 14px", borderRadius: 9, background: rx(.1), border: `1px solid ${rx(.25)}`, color: RED, fontSize: 12, marginBottom: 12 }}>
                  {err}
                </div>
              )}

              <input
                className="tm-in"
                value={joinTag}
                onChange={e => handleJoinTagChange(e.target.value)}
                placeholder="CPL"
                style={{ textAlign: "center", letterSpacing: 4, fontFamily: "var(--f-dis)", fontSize: 24, marginBottom: 8 }}
              />
              <p style={{ fontSize: 11, color: "rgba(255,255,255,.25)", textAlign: "center", marginBottom: 14 }}>
                Entrez le TAG de l'├®quipe
              </p>

              {/* Team preview */}
              {joinPreview && (
                <div style={{
                  padding: "14px 16px", borderRadius: 12, marginBottom: 14,
                  background: `${joinPreview.accent_color || ACCENT}10`,
                  border: `1px solid ${joinPreview.accent_color || ACCENT}30`
                }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 8 }}>
                    <div style={{
                      width: 40, height: 40, borderRadius: 10, flexShrink: 0, overflow: "hidden",
                      background: `linear-gradient(135deg,${joinPreview.accent_color || ACCENT}25,rgba(16,16,26,1))`,
                      border: `1px solid ${joinPreview.accent_color || ACCENT}40`,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      fontFamily: "var(--f-dis)", fontSize: 15, color: joinPreview.accent_color || ACCENT
                    }}>
                      {joinPreview.logo_url
                        ? <img src={joinPreview.logo_url} style={{ width: "100%", height: "100%", objectFit: "cover" }} onError={e => e.target.style.display="none"} />
                        : joinPreview.tag
                      }
                    </div>
                    <div style={{ flex: 1 }}>
                      <p style={{ fontFamily: "var(--f-dis)", fontSize: 17, color: "#fff", textTransform: "uppercase" }}>{joinPreview.name}</p>
                      <p style={{ fontSize: 11, color: "rgba(255,255,255,.3)" }}>
                        {joinPreview.member_count || 0}/{joinPreview.max_members || 6} membres ┬À{" "}
                        <span style={{ color: joinPreview.is_open ? GREEN : RED }}>
                          {joinPreview.is_open ? "Ouvert" : "Ferm├®"}
                        </span>
                      </p>
                    </div>
                  </div>
                  {joinPreview.description && (
                    <p style={{ fontSize: 12, color: "rgba(255,255,255,.4)", fontStyle: "italic" }}>{joinPreview.description}</p>
                  )}
                </div>
              )}
              {joinTag.length >= 2 && !joinPreview && (
                <p style={{ textAlign: "center", fontSize: 12, color: RED, marginBottom: 14 }}>
                  Aucune ├®quipe avec ce TAG
                </p>
              )}

              <div style={{ display: "flex", gap: 10 }}>
                <motion.button whileHover={{ scale: 1.03 }}
                  onClick={() => { setShowJoin(false); setJoinTag(""); setJoinPreview(null); setErr(""); }}
                  style={{
                    flex: 1, padding: "11px", borderRadius: 10,
                    background: ax(.06), border: `1px solid ${ax(.18)}`,
                    color: "rgba(255,255,255,.6)", fontFamily: "var(--f-ui)", fontSize: 12, cursor: "pointer"
                  }}>
                  Annuler
                </motion.button>
                <motion.button whileHover={{ scale: 1.03 }}
                  onClick={joinByTag}
                  disabled={joining || !joinPreview || !joinPreview.is_open}
                  style={{
                    flex: 1, padding: "11px", borderRadius: 10,
                    background: joinPreview && joinPreview.is_open ? ACCENT : "rgba(255,255,255,.06)",
                    border: "none",
                    color: joinPreview && joinPreview.is_open ? "#fff" : "rgba(255,255,255,.3)",
                    fontFamily: "var(--f-ui)", fontSize: 12, fontWeight: 700,
                    cursor: joining || !joinPreview || !joinPreview.is_open ? "not-allowed" : "pointer"
                  }}>
                  {joining ? "..." : "Envoyer la demande"}
                </motion.button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

