};

function getTxConfig(type, desc) {
  if (!type) return { icon: "­ƒÆ▒", color: "#6b7280", label: "Transaction" };
  const key = Object.keys(TX_CONFIG).find(k => type.toLowerCase().includes(k));
  return key ? TX_CONFIG[key] : { icon: "­ƒÆ▒", color: "#6b7280", label: type };
}

function timeAgo(date) {
  const d = new Date(date);
  const now = new Date();
  const diff = Math.floor((now - d) / 1000);
  if (diff < 60) return "├Ç l'instant";
  if (diff < 3600) return `Il y a ${Math.floor(diff / 60)}min`;
  if (diff < 86400) return `Il y a ${Math.floor(diff / 3600)}h`;
  if (diff < 604800) return `Il y a ${Math.floor(diff / 86400)}j`;
  return d.toLocaleDateString("fr-FR");
}

