// TournamentsSection ÔÇö active tournament cards, no emoji
import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { Trophy, Users, Clock, Gamepad2, Zap } from "lucide-react";
import Button from "../../components/ui/Button";

const fmt = n => n >= 1000 ? (n / 1000).toFixed(1) + "K" : String(n ?? 0);

function useCountdown(target) {
  const [s, setS] = useState(null);
  useEffect(() => {
    if (!target) return;
    const tick = () => setS(Math.max(0, Math.floor((new Date(target) - Date.now()) / 1000)));
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [target]);
  if (!s || s <= 0) return null;
  const h = Math.floor(s / 3600).toString().padStart(2, "0");
  const m = Math.floor((s % 3600) / 60).toString().padStart(2, "0");
  const sec = (s % 60).toString().padStart(2, "0");
  return s < 3600 ? `${m}:${sec}` : `${h}:${m}:${sec}`;
}

function TournamentCard({ t, idx }) {
  const nav = useNavigate();
  const pct = t.max_players > 0 ? Math.round((t.current_players / t.max_players) * 100) : 0;
  const remaining = t.max_players - (t.current_players ?? 0);
  const isLive  = t.status === "in_progress";
  const isFull  = pct >= 100;
  const isHot   = pct >= 75 && !isFull;
  const isFree  = !t.entry_fee || t.entry_fee === 0;
  const countdown = useCountdown(t.start_date);

  return (
    <motion.div
      className={`db-tourn-card${isLive ? " db-tourn-card--live" : ""}`}
      initial={{ opacity: 0, y: 18 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: idx * 0.05, duration: 0.3 }}
      onClick={() => nav(`/tournaments/${t.id}`)}
    >
      {/* Top accent line */}
      <div
        className="db-tourn-accent-line"
        style={{ background: isLive ? "var(--s-red, #e54040)" : "var(--accent)", opacity: 0.7 }}
      />

      <div className="db-tourn-body">
        {/* Status badges row */}
        <div className="db-tourn-top-row">
          <div style={{ flex: 1, minWidth: 0 }}>
            {/* invisible placeholder to push badges right */}
          </div>
          <div className="db-tourn-badges">
            {isLive && <span className="cp-badge cp-badge-live">Live</span>}
            {isFull && <span className="cp-badge cp-badge-subtle">Complet</span>}
            {!isFull && !isLive && isHot && (
              <span className="cp-badge cp-badge-orange">{remaining} place{remaining > 1 ? "s" : ""}</span>
            )}
            {isFree && !isFull && (
              <span className="cp-badge cp-badge-green">Gratuit</span>
            )}
          </div>
        </div>

        {/* Title */}
        <h3 className="db-tourn-title">{t.name}</h3>

        {/* Meta */}
        <div className="db-tourn-meta-row">
          {t.prize_coins > 0 && (
            <span className="db-tourn-meta-item db-tourn-meta-item--gold">
              <Trophy size={12} />
              {fmt(t.prize_coins)} CP
            </span>
          )}
          <span className="db-tourn-meta-item">
            <Users size={12} />
            {t.current_players}/{t.max_players}
          </span>
          {t.mode && (
            <span className="db-tourn-meta-item">
              <Gamepad2 size={12} />
              {t.mode}
            </span>
          )}
        </div>

        {/* Countdown */}
        {countdown && !isLive && (
          <div className="db-tourn-countdown">
            <Clock size={11} />
            <span>D├®part dans</span>
            <span className="db-tourn-countdown-time">{countdown}</span>
          </div>
        )}

        {/* Fill label + bar */}
        <div className="db-tourn-fill-row">
          <span className="db-tourn-fill-label">Remplissage</span>
          <span className="db-tourn-fill-pct">{t.current_players}/{t.max_players}</span>
        </div>
        <div className="db-tourn-bar-track">
          <motion.div
            className="db-tourn-bar-fill"
            initial={{ width: 0 }}
            animate={{ width: `${pct}%` }}
            transition={{ duration: 0.8, delay: idx * 0.05, ease: [0.32, 0, 0.15, 1] }}
            style={{ background: pct >= 90 ? "var(--s-red,#e54040)" : pct >= 60 ? "var(--s-gold)" : "var(--accent)" }}
          />
        </div>

        {/* CTA */}
        <button
          className={`db-tourn-cta${isFull ? " db-tourn-cta--full" : " db-tourn-cta--primary"}`}
          onClick={e => { e.stopPropagation(); nav(`/tournaments/${t.id}`); }}
          disabled={isFull}
        >
          {isFull   ? "Tournoi complet"
          : isLive  ? "Rejoindre le match en cours"
          :           "S'inscrire au tournoi ÔåÆ"}
        </button>
      </div>
    </motion.div>
  );
}

