        <div className="hs-bento-media-bottom">
          <span className={`hs-bento-status${isLive ? " hs-bento-status--live" : isFull ? " hs-bento-status--full" : ""}`}>
            {isLive && <span className="hs-bento-status-dot" />}
            {isFull ? "Complet" : isLive ? "Live" : "Ouvert"}
          </span>
        </div>

        {/* Prize ÔÇö top-right on image */}
        {t.prize_coins > 0 && (
          <div className="hs-bento-prize-chip">
