class TeamService {
  // Ï¬┘åÏ©┘è┘à Ïº┘ä┘üÏ▒┘é Ï¡Ï│Ï¿ mode
  organizeTeams(players, mode) {
    const teamSize = this.getTeamSize(mode);
    const teamMap = {};

    players.forEach(player => {
      const teamNum = player.team_number || 1;
      if (!teamMap[teamNum]) {
        teamMap[teamNum] = {
          number: teamNum,
          captain: teamNum === 1 ? players[0]?.user_id : null,
          players: []
        };
      }
      teamMap[teamNum].players.push(player);
    });

    return Object.values(teamMap).sort((a, b) => a.number - b.number);
  }

  // Ï¬Ï¡Ï»┘èÏ» Ï¡Ï¼┘à Ïº┘ä┘üÏ▒┘è┘é Ï¡Ï│Ï¿ mode
  getTeamSize(mode) {
    switch(mode) {
      case "squad": return 4;
      case "duo": return 2;
      default: return 1;
    }
  }

  // ÏÑ┘åÏ┤ÏºÏí ┘àÏÁ┘ü┘ê┘üÏ® Ïº┘ä┘à┘éÏºÏ╣Ï»
  createSeats(players, maxPlayers, mode) {
    const teamSize = this.getTeamSize(mode);
    const seats = [];

    for (let i = 0; i < maxPlayers; i++) {
      const seatNumber = i + 1;
      const player = players.find(p => p.seat_number === seatNumber);
      seats.push({
        number: seatNumber,
        player: player || null,
        teamNumber: player?.team_number || Math.ceil(seatNumber / teamSize)
      });
    }

    return seats;
  }

  // Ï¡Ï│ÏºÏ¿ Ï╣Ï»Ï» Ïº┘äÏ¼Ïº┘çÏ▓┘è┘å
  countReady(players) {
    return players.filter(p => p.is_ready).length;
  }
}

export const teamService = new TeamService();

import { supabase } from '../lib/supabase';
import { useState, useEffect } from 'react';

// Ï¼┘à┘èÏ╣ Ïº┘äÏÁ┘äÏºÏ¡┘èÏºÏ¬ Ïº┘ä┘à┘à┘â┘åÏ® ┘ü┘è Ïº┘ä┘åÏ©Ïº┘à
export const PERMISSIONS = {
  // Ïº┘ä┘àÏ│Ï¬Ï«Ï»┘à┘ê┘å
  VIEW_USERS: 'view_users',
  EDIT_USER_ROLE: 'edit_user_role',
  BAN_USER: 'ban_user',
  DELETE_USER: 'delete_user',
  GRANT_COINS: 'grant_coins',
  VIEW_USER_DETAILS: 'view_user_details',
  
  // Ïº┘äÏ¿ÏÀ┘ê┘äÏºÏ¬
  CREATE_TOURNAMENT: 'create_tournament',
  EDIT_ANY_TOURNAMENT: 'edit_any_tournament',
  DELETE_ANY_TOURNAMENT: 'delete_any_tournament',
  MANAGE_OWN_TOURNAMENT: 'manage_own_tournament',
  START_MATCH: 'start_match',
  CONFIRM_MATCH_RESULT: 'confirm_match_result',
  
  // Ïº┘äÏÑÏ»ÏºÏ▒Ï®
  MANAGE_ADMINS: 'manage_admins',
  VIEW_LOGS: 'view_logs',
  MANAGE_REPORTS: 'manage_reports',
  VIEW_ANALYTICS: 'view_analytics',
  
  // Ïº┘äÏ»Ï╣┘à
  VIEW_ALL_TICKETS: 'view_all_tickets',
  REPLY_TO_TICKETS: 'reply_to_tickets',
  CLOSE_TICKETS: 'close_tickets',
  
  // Ïº┘äÏ¬Ï¡┘é┘é
  VERIFY_USERS: 'verify_users',
  
  // Ïº┘ä┘åÏ©Ïº┘à
  MAINTENANCE_MODE: 'maintenance_mode',
  VIEW_SYSTEM_CONFIG: 'view_system_config',
};

/**
 * Ïº┘äÏ¬Ï¡┘é┘é ┘à┘å ÏÁ┘äÏºÏ¡┘èÏ® Ïº┘ä┘àÏ│Ï¬Ï«Ï»┘à (Ï»Ïº┘äÏ® Ï╣ÏºÏ»┘èÏ®)
 */
export const can = (user, permission) => {
  if (!user || !user.role) return false;
  const role = user.role.toLowerCase();

  // super_admin Ï╣┘åÏ»┘ç ┘â┘ä Ïº┘äÏÁ┘äÏºÏ¡┘èÏºÏ¬
  if (role === 'super_admin') return true;

  // ÏÁ┘äÏºÏ¡┘èÏºÏ¬ admin
  if (role === 'admin') {
    const adminPermissions = [
      PERMISSIONS.VIEW_USERS,
      PERMISSIONS.BAN_USER,
      PERMISSIONS.GRANT_COINS,
      PERMISSIONS.VIEW_USER_DETAILS,
      PERMISSIONS.MANAGE_REPORTS,
      PERMISSIONS.VIEW_ANALYTICS,
      PERMISSIONS.VIEW_LOGS,
      PERMISSIONS.VIEW_ALL_TICKETS,
      PERMISSIONS.REPLY_TO_TICKETS,
      PERMISSIONS.CLOSE_TICKETS,
      PERMISSIONS.VERIFY_USERS,
      PERMISSIONS.CONFIRM_MATCH_RESULT,
    ];
    return adminPermissions.includes(permission);
  }
  
  // ÏÁ┘äÏºÏ¡┘èÏºÏ¬ founder / fondateur
  if (role === 'founder' || role === 'fondateur') {
    const founderPermissions = [
      PERMISSIONS.CREATE_TOURNAMENT,
      PERMISSIONS.MANAGE_OWN_TOURNAMENT,
      PERMISSIONS.START_MATCH,
      PERMISSIONS.VIEW_USERS,
    ];
    return founderPermissions.includes(permission);
  }

  // user Ï╣┘åÏ»┘ç ÏÁ┘äÏºÏ¡┘èÏºÏ¬ ÏúÏ│ÏºÏ│┘èÏ® (┘àÏ½┘äÏº┘ï ┘àÏº Ï╣┘åÏ»┘ê ┘êÏº┘ä┘ê)
  if (role === 'user') {
    return false;
  }
  
  return false;
};

/**
 * ┘ç┘ê┘â usePermissions - ┘èÏ│Ï¬Ï«Ï»┘à ┘ü┘è Ïº┘ä┘à┘â┘ê┘åÏºÏ¬
 */
export const usePermissions = (user) => {
  const [permissions, setPermissions] = useState({
    can: (permission) => false,
    isSuperAdmin: false,
    isAdmin: false,
    isFounder: false,
    isUser: false,
    isBanned: false,
  });

  useEffect(() => {
    if (!user) {
      setPermissions({
        can: () => false,
        isSuperAdmin: false,
        isAdmin: false,
        isFounder: false,
        isUser: false,
        isBanned: false,
      });
      return;
    }

    const r = user.role?.toLowerCase() ?? "";
    setPermissions({
      can: (permission) => can(user, permission),
      isSuperAdmin: r === 'super_admin',
      isAdmin:      r === 'admin' || r === 'super_admin',
      isFounder:    r === 'founder' || r === 'fondateur',
      isUser:       r === 'user',
      isBanned:     r === 'banned',
    });
  }, [user]);

  return permissions;
};

/**
 * Ï»Ïº┘äÏ® ┘ä┘äÏ¬Ï¡┘é┘é ┘à┘å Ïº┘äÏÁ┘äÏºÏ¡┘èÏ® Ï╣Ï¿Ï▒ RPC (┘ä┘äÏ╣┘à┘ä┘èÏºÏ¬ Ïº┘äÏ¡Ï│ÏºÏ│Ï®)
 */
export const checkPermission = async (userId, permissionName) => {
  try {
    const { data, error } = await supabase
      .rpc('check_user_permission', {
        user_id: userId,
        permission_name: permissionName
      });
    
    if (error) return false;
    return data || false;
  } catch (err) {
    console.error('Error checking permission:', err);
    return false;
  }
};

export default can;
